  getCollection(id: string): Promise<MediaCollection | null>;
  listCollections(): Promise<MediaCollection[]>;
  deleteCollection(id: string): Promise<boolean>;

  // Tag operations
  createTag(tag: Omit<MediaTag, 'id' | 'assetCount'>): Promise<MediaTag>;
  getTags(): Promise<MediaTag[]>;
  tagAsset(assetId: string, tagId: string): Promise<void>;
  untagAsset(assetId: string, tagId: string): Promise<void>;

  // Permission operations
  setPermission(permission: MediaPermission): Promise<void>;
  getPermissions(tenantId: string): Promise<MediaPermission[]>;

  // Document operations
  getDocument(tenantId: string): Promise<MediaDocument | null>;
}

export class MemoryMediaLibrary extends MemoryAssetLibrary implements MediaLibrary {
  private folders: Map<string, MediaFolder> = new Map();
  private collections: Map<string, MediaCollection> = new Map();
  private tags: Map<string, MediaTag> = new Map();
  private permissions: Map<string, MediaPermission> = new Map();
  private rootFolderId: string;

  constructor(storage: AssetStorage, rootFolderId: string = 'root') {
    super(storage);
    this.rootFolderId = rootFolderId;
  }

  // Folder operations
  async createFolder(folder: MediaFolder): Promise<MediaFolder> {
    this.folders.set(folder.id, folder);
    return folder;
  }

  async getFolder(id: string): Promise<MediaFolder | null> {
    return this.folders.get(id) || null;
  }

  async listFolders(parentId: string | null): Promise<MediaFolder[]> {
    return Array.from(this.folders.values()).filter(f => f.parentId === parentId);
  }

  async deleteFolder(id: string): Promise<boolean> {
    return this.folders.delete(id);
  }

  // Collection operations
  async createCollection(collection: Omit<MediaCollection, 'id' | 'createdAt'>): Promise<MediaCollection> {
    const id = crypto.randomUUID();
    const now = new Date().toISOString();
    const newCollection: MediaCollection = {
      ...collection,
      id,
      createdAt: now,
    };
    this.collections.set(id, newCollection);
    return newCollection;
  }

  async getCollection(id: string): Promise<MediaCollection | null> {
    return this.collections.get(id) || null;
  }

  async listCollections(): Promise<MediaCollection[]> {
    return Array.from(this.collections.values());
  }

  async deleteCollection(id: string): Promise<boolean> {
    return this.collections.delete(id);
  }

  // Tag operations
  async createTag(tag: Omit<MediaTag, 'id' | 'assetCount'>): Promise<MediaTag> {
    const id = crypto.randomUUID();
    const newTag: MediaTag = {
      ...tag,
      id,
      assetCount: 0,
    };
    this.tags.set(id, newTag);
    return newTag;
  }

  async getTags(): Promise<MediaTag[]> {
    return Array.from(this.tags.values());
  }

  async tagAsset(assetId: string, tagId: string): Promise<void> {
    const asset = await this.getById(assetId);
    if (asset) {
      asset.tags = [...(asset.tags || []), tagId];
    }
  }

  async untagAsset(assetId: string, tagId: string): Promise<void> {
    const asset = await this.getById(assetId);
    if (asset && asset.tags) {
      asset.tags = asset.tags.filter(t => t !== tagId);
    }
  }

  // Permission operations
  async setPermission(permission: MediaPermission): Promise<void> {
    const key = `${permission.tenantId}:${permission.userId}`;
    this.permissions.set(key, permission);
  }

  async getPermissions(tenantId: string): Promise<MediaPermission[]> {
    return Array.from(this.permissions.values()).filter(p => p.tenantId === tenantId);
  }

  // Document operations
  async getDocument(tenantId: string): Promise<MediaDocument | null> {
    const folders = Array.from(this.folders.values()).filter(f => f.tenantId === tenantId);
    const assets = Array.from(this.assets.values());
    const collections = Array.from(this.collections.values()).filter(c => c.tenantId === tenantId);
    const tags = Array.from(this.tags.values()).filter(t => t.tenantId === tenantId);
    const permissions = await this.getPermissions(tenantId);

    return {
      id: tenantId,
      tenantId,
      rootFolderId: this.rootFolderId,
      folders,
      assets,
      collections,
      tags,
      permissions,
    };
  }
}

// AssetResolver.ts
import { AssetType } from './AssetTypes';
import { AssetReference } from './AssetReference';
import { AssetStorage } from './AssetStorage';
import { AssetLibrary } from './AssetLibrary';

/**
 * AssetResolver is the critical component that turns AssetReferences
 * into actual usable URLs. This is where the indirection pays off:
 * 
 * Instead of storing "https://cdn.example.com/images/logo-v1.png" everywhere,
 * we store { id: "logo-123", type: "image" } and resolve it when needed.
 * 
 * This allows us to:
 * - Change CDN providers without updating content
 * - Implement versioning/cache-busting strategies
 * - Serve different images based on user agent (WebP vs JPEG)
 * - Resize/crop images on-the-fly
 * - Switch storage backends (local -> S3 -> etc)
 */
export interface AssetResolver {
  /**
   * Resolve an AssetReference to a public URL
   * @param reference What asset we want
   * @param options Transformation options (resize, format, etc.)
   * @returns Publicly accessible URL for the asset
   */
  resolve(reference: AssetReference, options?: {
    width?: number;
    height?: number;
    quality?: number; // 0-100 for images
    format?: string; // 'webp', 'jpg', 'png', etc.
    // Allow for future extensions
    [key: string]: any;
  }): Promise<string>;

  /**
   * Resolve multiple assets at once (for batch operations)
   */
  resolveAll(references: AssetReference[], options?: {
    width?: number;
    height?: number;
    quality?: number;
    format?: string;
  }): Promise<string[]>;

  /**
   * Get the underlying storage for direct operations
   * (useful for uploads, deletions, etc.)
   */
  getStorage(): AssetStorage;

  /**
   * Get the library for metadata/query operations
   */
  getLibrary(): AssetLibrary;
}

/**
 * Basic implementation of AssetResolver that combines
 * a storage backend and library
 */
export class SimpleAssetResolver implements AssetResolver {
  constructor(
    private storage: AssetStorage,
    private library: AssetLibrary
  ) {}

  async resolve(reference: AssetReference, options?: {
    width?: number;
    height?: number;
    quality?: number;
    format?: string;
  }): Promise<string> {
    // Get asset metadata to find storage key
    const asset = await this.library.getById(reference.id);
    if (!asset) {
      throw new Error(`Asset not found: ${reference.id}`);
    }

    // Verify type matches
    if (asset.type !== reference.type) {
      throw new Error(`Asset type mismatch: expected ${reference.type}, got ${asset.type}`);
    }

    // Delegate to storage for URL generation
    return this.storage.getUrl(asset.storageKey, options);
  }

  async resolveAll(references: AssetReference[], options?: {
    width?: number;
    height?: number;
    quality?: number;
    format?: string;
  }): Promise<string[]> {
    const promises = references.map(ref => this.resolve(ref, options));
    return Promise.all(promises);
  }

  getStorage(): AssetStorage {
    return this.storage;
  }

  getLibrary(): AssetLibrary {
    return this.library;
  }
}

// AssetStorage.ts
import { Asset } from './AssetTypes';

/**
 * AssetStorage abstracts the actual storage mechanism for asset binaries.
 * This allows us to switch between local storage, S3, Google Cloud Storage,
 * Azure Blob Storage, or custom CDNs without changing the asset management logic.
 */
export interface AssetStorage {
  /**
   * Upload asset binary data and return storage key/reference
   * @param file File data to upload
   * @param metadata Optional metadata (content type, etc.)
   * @returns Promise resolving to storage information
   */
  upload(
    file: File | Buffer | ReadableStream<Uint8Array>,
    metadata?: {
      contentType?: string;
      [key: string]: any;
    }
  ): Promise<{
    storageKey: string; // Key to use for storage/retrieval
    size: number; // File size in bytes
    checksum?: string; // Optional hash for integrity verification
  }>;

  /**
   * Download asset binary data by storage key
   * @param storageKey The key returned from upload()
   * @returns Promise resolving to the file data
   */
  download(storageKey: string): Promise<Uint8Array>;

  /**
   * Delete asset binary data
   * @param storageKey The key returned from upload()
   * @returns Promise resolving when deletion is complete
   */
  delete(storageKey: string): Promise<void>;

  /**
   * Get public URL for asset (may be signed URL or public CDN URL)
   * This is where CDN integration happens - the storage implementation
   * knows how to generate the correct URL for its backend
   * @param storageKey The key returned from upload()
   * @param options Transformation options (resize, format, etc.)
   * @returns Promise resolving to publicly accessible URL
   */
  getUrl(storageKey: string, options?: {
    width?: number;
    height?: number;
    quality?: number; // 0-100 for images
    format?: string; // 'webp', 'jpg', 'png', etc.
    // For images: resize, crop, format conversion
    // For video: timestamp, quality, format
  }): Promise<string>;

  /**
   * Check if asset exists in storage
   * @param storageKey The key to check
   * @returns Promise resolving to true if file exists
   */
  exists(storageKey: string): Promise<boolean>;

  /**
   * Get metadata about stored asset (size, etc.)
   * @param storageKey The key to query
   * @returns Promise resolving to file metadata
   */
  getMetadata(storageKey: string): Promise<{
    size: number;
    contentType?: string;
    lastModified?: string; // ISO timestamp
    // Storage-specific metadata
    [key: string]: any;
  }>;

  /**
   * Copy a file within the same storage bucket
   * @param sourceKey Source storage key
   * @param destinationKey Destination storage key
   * @returns Promise resolving when copy is complete
   */
  copy(sourceKey: string, destinationKey: string): Promise<void>;

  /**
   * Move/rename a file within the same storage bucket
   * @param sourceKey Source storage key
   * @param destinationKey Destination storage key
   * @returns Promise resolving when move is complete
   */
  move(sourceKey: string, destinationKey: string): Promise<void>;

  /**
   * Invalidate cache for a specific asset (CDN purge)
   * @param storageKey The key to invalidate
   * @returns Promise resolving when cache is invalidated
   */
  invalidateCache(storageKey: string): Promise<void>;

  /**
   * Create a versioned copy of an asset
   * @param storageKey The key to version
   * @param version Version identifier
   * @returns Promise resolving to new storage key
   */
  createVersion(storageKey: string, version: string): Promise<string>;
}

/**
 * Configuration for different storage implementations
 */
export interface StorageConfig {
  // Common options
  basePath?: string; // Prefix for all storage keys
  // Provider-specific options would go here in actual implementations
  // For example: region, bucketName, accessKey, etc. for S3
}

/**
 * Factory function for creating storage instances
 * In a real implementation, this would select the appropriate
 * storage driver based on configuration and environment variables
 */
export class StorageFactory {
  /**
   * Create a storage instance based on the provided type and config
   * @param type Storage type ('local', 's3', 'gcs', 'azure', 'r2', etc.)
   * @param config Configuration for the storage provider
   * @returns AssetStorage implementation
   */
  static async create(type: string, config: StorageConfig = {}): Promise<AssetStorage> {
    switch (type.toLowerCase()) {
      case 'local': {
        const module = await import('./providers/LocalAssetStorage');
        return new module.LocalAssetStorage(config);
      }
      case 'memory': {
        const module = await import('./providers/LocalAssetStorage');
        return new module.LocalAssetStorage({ ...config, basePath: 'mem:' });
      }
      default:
        throw new Error(`Unsupported storage type: ${type}`);
    }
  }
}

