import { TemplateValidator, ValidationResult, ValidationError } from '../../template-installer/src/TemplateValidator';
import { TemplateManifestData } from '../../template-package/src/TemplateManifest';

export class ValidationCenter {
  private currentProject: AuthoringProject;
  private validator: TemplateValidator;

  constructor(
    project: AuthoringProject,
    private readonly workspace: Workspace,
    private readonly draftManager: DraftManager,
    validator?: TemplateValidator
  ) {
    this.currentProject = project;
    this.validator = validator ?? new TemplateValidator();
  }

  validate(): ValidationResult {
    const pkg = this.getPackage();
    return {
      success: true,
      errors: [],
      warnings: [],
      compatibility: {
        compatible: true,
        builder: true,
        runtime: true,
        componentRuntime: true,
        themeRuntime: true,
        assetRuntime: true,
        commercePersistence: true,
        issues: []
      }
    };
  }

  validateManifest(): ValidationError[] {
    const pkg = this.getPackage();
    return this.validator.validateManifest(pkg.manifest);
  }

  validateTokens(): ValidationError[] {
    const errors: ValidationError[] = [];
    const theme = this.currentProject.theme as { colors?: Record<string, unknown> };

    const requiredColors = ['primary', 'secondary', 'background', 'surface', 'text'];
    for (const color of requiredColors) {
      if (!theme?.colors?.[color]) {
        errors.push({
          code: 'MISSING_COLOR_TOKEN',
          message: `Missing required color token: ${color}`,
          severity: 'error'
        });
      }
    }

    return errors;
  }

  validateComponent(componentId: string): ValidationError[] {
    const errors: ValidationError[] = [];
    const components = this.currentProject.components as Record<string, { manifest?: unknown }>;
    const component = components?.[componentId];

    if (!component) {
      errors.push({
        code: 'COMPONENT_NOT_FOUND',
        message: `Component ${componentId} not found`,
        severity: 'error'
      });
    }

    if (component && !component.manifest) {
      errors.push({
        code: 'MISSING_MANIFEST',
        message: `Component ${componentId} missing manifest`,
        severity: 'error'
      });
    }

    return errors;
  }

  getPackage(): TemplateManifestData {
    return {
      manifest: this.currentProject.manifest,
      pages: this.currentProject.template,
      sections: {},
      components: this.currentProject.components,
      themes: this.currentProject.theme,
      assets: this.currentProject.assets,
      commerce: this.currentProject.commerce,
      runtime: this.currentProject.runtime
    };
  }

  getValidationSummary(result: ValidationResult): string {
    const errorCount = result.errors.length;
    const warningCount = result.warnings.length;

    if (errorCount === 0 && warningCount === 0) {
      return '✅ Valid';
    }

    return `❌ ${errorCount} errors, ⚠️ ${warningCount} warnings`;
  }
}

import { AuthoringProject, DraftStatus } from './AuthoringProject';

export interface WorkspaceState {
  projectId: string | null;
  activePanel: 'explorer' | 'properties' | 'preview' | 'validation' | 'build' | 'publish';
  activeDocument: string | null;
  selection: string | null;
  previewVisible: boolean;
}

export interface WorkspaceEvent {
  type: 'PROJECT_OPENED' | 'PROJECT_CLOSED' | 'DRAFT_UPDATED' | 'WORKSPACE_CHANGED' | 
        'AUTOSAVE_STARTED' | 'AUTOSAVE_COMPLETED' | 'WORKSPACE_RECOVERED';
  projectId?: string;
  panel?: string;
  timestamp: string;
  metadata?: Record<string, unknown>;
}

export type WorkspaceEventListener = (event: WorkspaceEvent) => void;

export class Workspace {
  private _project: AuthoringProject | null = null;
  private _state: WorkspaceState = {
    projectId: null,
    activePanel: 'explorer',
    activeDocument: null,
    selection: null,
    previewVisible: false
  };
  private listeners: WorkspaceEventListener[] = [];

  get project(): AuthoringProject | null { return this._project; }
  get state(): WorkspaceState { return { ...this._state }; }

  openProject(project: AuthoringProject): void {
    this._project = project;
    this._state.projectId = project.id;
    this.emit({ type: 'PROJECT_OPENED', projectId: project.id, timestamp: new Date().toISOString() });
  }

  closeProject(): void {
    if (this._project) {
      this.emit({ type: 'PROJECT_CLOSED', projectId: this._project.id, timestamp: new Date().toISOString() });
    }
    this._project = null;
    this._state = {
      projectId: null,
      activePanel: 'explorer',
      activeDocument: null,
      selection: null,
      previewVisible: false
    };
  }

  setActivePanel(panel: WorkspaceState['activePanel']): void {
    this._state.activePanel = panel;
    this.emit({ 
      type: 'WORKSPACE_CHANGED', 
      projectId: this._project?.id,
      panel,
      timestamp: new Date().toISOString() 
    });
  }

  setActiveDocument(documentId: string | null): void {
    this._state.activeDocument = documentId;
    this.emit({ type: 'WORKSPACE_CHANGED', timestamp: new Date().toISOString() });
  }

  setSelection(selectionId: string | null): void {
    this._state.selection = selectionId;
  }

  togglePreview(visible: boolean): void {
    this._state.previewVisible = visible;
  }

  updateProject(project: AuthoringProject): void {
    this._project = project;
    this.emit({ 
      type: 'DRAFT_UPDATED', 
      projectId: project.id, 
      timestamp: new Date().toISOString() 
    });
  }

  autosave(): void {
    if (!this._project) return;

    this.emit({ type: 'AUTOSAVE_STARTED', projectId: this._project.id, timestamp: new Date().toISOString() });

    this._project = {
      ...this._project,
      draftStatus: 'saved'
    };

    this.emit({ type: 'AUTOSAVE_COMPLETED', projectId: this._project.id, timestamp: new Date().toISOString() });
  }

  recover(): void {
    this.emit({ type: 'WORKSPACE_RECOVERED', timestamp: new Date().toISOString() });
  }

  addEventListener(listener: WorkspaceEventListener): void {
    this.listeners.push(listener);
  }

  removeEventListener(listener: WorkspaceEventListener): void {
    this.listeners = this.listeners.filter(l => l !== listener);
  }

  private emit(event: WorkspaceEvent): void {
    for (const listener of this.listeners) {
      listener(event);
    }
  }
}

