import { CanvasState, CanvasAction, reduceCanvasState, createCanvasState, ResizeHandle, Alignment, SnapResult } from './CanvasState';

export interface DragCommandOptions {
  readonly document: BuilderDocument;
  readonly draggedIds: readonly string[];
  readonly sourcePageId: string;
  readonly sourceIndex: number;
  readonly targetPageId: string;
  readonly targetIndex: number;
}

export function createDragCommand(options: DragCommandOptions): BuilderCommand {
  return {
    type: 'MOVE_SECTION',
    pageId: options.targetPageId,
    fromIndex: options.sourceIndex,
    toIndex: options.targetIndex,
  };
}

export interface DragState {
  readonly isDragging: boolean;
  readonly draggedIds: readonly string[];
  readonly sourcePageId: string;
  readonly targetPageId: string;
  readonly targetIndex: number;
  readonly offset: { x: number; y: number };
}

export function reduceDragState(
  state: CanvasState,
  action: CanvasAction,
  grid: GridSystem
): CanvasState {
  return reduceCanvasState(state, action);
}

export function computeDropTarget(
  sections: SectionNode[],
  pointerY: number,
  sectionHeights: Map<string, number>,
  sectionGaps: number = 8
): number {
  let currentY = 0;
  for (let i = 0; i < sections.length; i++) {
    const height = sectionHeights.get(sections[i].id) ?? 0;
    if (pointerY < currentY + height / 2) {
      return i;
    }
    currentY += height + sectionGaps;
  }
  return sections.length;
}

export function snapDragToGrid(
  x: number,
  y: number,
  width: number,
  height: number,
  containerWidth: number,
  grid: GridSystem
): { x: number; y: number } {
  const result = grid.snap({ x, y, width, height, containerWidth });
  return { x: result.x, y: result.y };
}

// GridSystem.ts
// C7: Builder Pro — Grid snapping, guide lines, measurements

import { GridConfig, DEFAULT_GRID_CONFIG, SnapResult } from './CanvasState';

export interface SnapInput {
  readonly x: number;
  readonly y: number;
  readonly width: number;
  readonly height: number;
  readonly containerWidth: number;
}

export class GridSystem {
  private readonly config: GridConfig;

  constructor(config: Partial<GridConfig> = {}) {
    this.config = { ...DEFAULT_GRID_CONFIG, ...config };
  }

  public updateConfig(config: Partial<GridConfig>): void {
    const updated = { ...this.config, ...config };
    (this as any).config = updated;
  }

  public getConfig(): GridConfig {
    return this.config;
  }

  public snap(input: SnapInput): SnapResult {
    if (!this.config.snapToGrid) {
      return { x: input.x, y: input.y, snapped: false, guides: [] };
    }

    const columnWidth = this.calculateColumnWidth(input.containerWidth);
    const gutter = this.config.gutter;
    const margin = this.config.margin;

    const snappedX = Math.round((input.x - margin) / (columnWidth + gutter)) * (columnWidth + gutter) + margin;
    const snappedY = Math.round(input.y / this.config.gutter) * this.config.gutter;

    const guides = this.computeGuides(input, snappedX, snappedY, columnWidth);

    return {
      x: snappedX,
      y: snappedY,
      snapped: snappedX !== input.x || snappedY !== input.y,
      guides,
    };
  }

  public snapToElement(
    input: SnapInput,
    elementBounds: { x: number; y: number; width: number; height: number }
  ): SnapResult {
    const threshold = 8;
    const guides: Array<{ axis: 'x' | 'y'; position: number }> = [];

    let x = input.x;
    let y = input.y;
    let snapped = false;

    const elementCenterX = elementBounds.x + elementBounds.width / 2;
    const elementRight = elementBounds.x + elementBounds.width;
    const inputCenterX = input.x + input.width / 2;
    const inputRight = input.x + input.width;

    if (Math.abs(inputCenterX - elementCenterX) < threshold) {
      x = elementCenterX - input.width / 2;
      snapped = true;
      guides.push({ axis: 'x', position: elementCenterX });
    } else if (Math.abs(input.x - elementBounds.x) < threshold) {
      x = elementBounds.x;
      snapped = true;
      guides.push({ axis: 'x', position: elementBounds.x });
    } else if (Math.abs(inputRight - elementRight) < threshold) {
      x = elementRight - input.width;
      snapped = true;
      guides.push({ axis: 'x', position: elementRight });
    } else if (Math.abs(inputCenterX - elementCenterX) < threshold) {
      x = elementCenterX - input.width / 2;
      snapped = true;
      guides.push({ axis: 'x', position: elementCenterX });
    }

    if (Math.abs(input.y - elementBounds.y) < threshold) {
      y = elementBounds.y;
      snapped = true;
      guides.push({ axis: 'y', position: elementBounds.y });
    } else if (Math.abs(input.y + input.height - elementBounds.y + elementBounds.height) < threshold) {
      y = elementBounds.y + elementBounds.height - input.height;
      snapped = true;
      guides.push({ axis: 'y', position: elementBounds.y + elementBounds.height });
    } else if (Math.abs(input.y + input.height / 2 - (elementBounds.y + elementBounds.height / 2)) < threshold) {
      y = elementBounds.y + elementBounds.height / 2 - input.height / 2;
      snapped = true;
      guides.push({ axis: 'y', position: elementBounds.y + elementBounds.height / 2 });
    }

    return { x, y, snapped, guides };
  }

  public toggleVisibility(): GridConfig {
    return { ...this.config, showGuides: !this.config.showGuides };
  }

  private calculateColumnWidth(containerWidth: number): number {
    const totalGutter = this.config.gutter * (this.config.columns - 1);
    const totalMargin = this.config.margin * 2;
    return (containerWidth - totalMargin - totalGutter) / this.config.columns;
  }

  private computeGuides(
    input: SnapInput,
    snappedX: number,
    snappedY: number,
    columnWidth: number
  ): Array<{ axis: 'x' | 'y'; position: number }> {
    const guides: Array<{ axis: 'x' | 'y'; position: number }> = [];

    if (!this.config.showGuides) {
      return guides;
    }

    const centerX = snappedX + input.width / 2;
    const centerY = snappedY + input.height / 2;

    for (let i = 0; i < this.config.columns; i++) {
      const colX = this.config.margin + i * (columnWidth + this.config.gutter);
      const colCenterX = colX + columnWidth / 2;

      if (Math.abs(centerX - colCenterX) < 1) {
        guides.push({ axis: 'x', position: colCenterX });
      }
    }

    if (snappedY === 0) {
      guides.push({ axis: 'y', position: 0 });
    }

    return guides;
  }
}

// LayoutEngine.ts
// C7.5: Builder Pro — layout engine (alignment, distribution, snapping)

import { BuilderDocument } from './BuilderDocument';
import { BuilderCommand } from './BuilderCommands';
import { Alignment } from './CanvasState';
import { GridSystem } from './GridSystem';

export function createAlignCommand(options: {
  readonly document: BuilderDocument;
  readonly pageId: string;
  readonly sectionIds: readonly string[];
  readonly alignment: Alignment;
}): BuilderCommand {
  return {
    type: 'ALIGN_SECTIONS',
    pageId: options.pageId,
    sectionIds: options.sectionIds,
    alignment: options.alignment,
  };
}

export function computeAlignment(
  sections: ReadonlyArray<{ x: number; y: number; width: number; height: number }>,
  alignment: Alignment
): ReadonlyArray<{ x: number; y: number; width: number; height: number }> {
  if (sections.length === 0) return sections;

  switch (alignment) {
    case 'LEFT':
      return sections.map(s => ({ ...s, x: 0 }));
    case 'CENTER':
      return sections.map(s => ({ ...s, x: 50, align: 'center' as const }));
    case 'RIGHT':
      return sections.map(s => ({ ...s, x: 100, align: 'right' as const }));
    case 'STRETCH':
      return sections.map(s => ({ ...s, width: 100, align: 'stretch' as const }));
    case 'TOP':
      return sections.map(s => ({ ...s, y: 0 }));
    case 'MIDDLE': {
      const minY = Math.min(...sections.map(s => s.y));
      const maxY = Math.max(...sections.map(s => s.y + s.height));
      const centerY = (minY + maxY) / 2;
      return sections.map(s => ({ ...s, y: centerY - s.height / 2, valign: 'middle' as const }));
    }
    case 'BOTTOM': {
      const maxY = Math.max(...sections.map(s => s.y + s.height));
      return sections.map(s => ({ ...s, y: maxY - s.height, valign: 'bottom' as const }));
    }
    case 'DISTRIBUTE_HORIZONTAL': {
      const totalWidth = sections.reduce((sum, s) => sum + s.width, 0);
      const availableWidth = 100 - totalWidth;
      const gap = sections.length > 1 ? availableWidth / (sections.length - 1) : 0;
      let currentX = 0;
      return sections.map(s => {
        const next = { ...s, x: currentX };
        currentX += s.width + gap;
        return next;
      });
    }
    case 'DISTRIBUTE_VERTICAL': {
      const totalHeight = sections.reduce((sum, s) => sum + s.height, 0);
      const availableHeight = 100 - totalHeight;
      const gap = sections.length > 1 ? availableHeight / (sections.length - 1) : 0;
      let currentY = 0;
      return sections.map(s => {
        const next = { ...s, y: currentY };
        currentY += s.height + gap;
        return next;
      });
    }
    case 'EQUAL_HEIGHT': {
      const maxHeight = Math.max(...sections.map(s => s.height));
      return sections.map(s => ({ ...s, height: maxHeight }));
    }
    case 'EQUAL_WIDTH': {
      const maxWidth = Math.max(...sections.map(s => s.width));
      return sections.map(s => ({ ...s, width: maxWidth }));
    }
    default:
      return sections;
  }
}

/**
 * PreviewRuntimeAdapter — C6.1-C / C6.3-F
 *
 * The ONE place in builder-core that imports from runtime-core.
 * All other builder-core files must NOT import runtime-core.
 *
 * This adapter:
 *   1. Subscribes to the runtimeSide of a MemoryChannel
 *   2. On DOCUMENT_UPDATE: delegates to PreviewRuntime
 *   3. Sends back a PreviewAck (RENDERED or ERROR)
 *
 * C6.3-F architectural principle:
 *   Adapter knows ONLY about PreviewRuntime.
 *   It does NOT know about TemplateRuntime, ComponentRuntime,
 *   ThemeRuntime, AssetResolver, or PreviewPipeline.
 *   All runtime internals are encapsulated behind PreviewRuntime.
 *
 * NOTE: runtime-core import is intentionally dynamic-style via a factory
 * parameter so that builder-core package itself remains free of a hard
 * compile-time dep on runtime-core. Consumers wire them together at the
 * app level.
 */

import { CompiledDocument } from './BuilderDocument';
import { PreviewMessage, PreviewAck } from './PreviewMessage';
import { PreviewRuntime, PreviewRuntimeResult } from '../../theme-runtime/src/PreviewRuntime';

// ---------------------------------------------------------------------------
// Adapter interface
// ---------------------------------------------------------------------------

export interface PreviewRenderer {
  render(compiled: CompiledDocument): Promise<{ html: string; renderTimeMs: number }>;
}

export interface PreviewRuntimeAdapter {
  handleMessage(message: PreviewMessage): Promise<PreviewAck>;
  destroy(): void;
}

// ---------------------------------------------------------------------------
// Factory
// ---------------------------------------------------------------------------

export function createPreviewRuntimeAdapter(
  runtime: PreviewRuntime,
  onRender?: (html: string) => void
): PreviewRuntimeAdapter {
  let destroyed = false;

  return {
    async handleMessage(message) {
      if (destroyed) {
        return {
          ackType: 'ERROR',
          correlationId: message.correlationId,
          timestamp: Date.now(),
          error: 'Adapter destroyed',
        };
      }

      if (message.messageType === 'PING') {
        return {
          ackType: 'PONG',
          correlationId: message.correlationId,
          timestamp: Date.now(),
        };
      }

      if (message.messageType === 'DOCUMENT_UPDATE') {
        const start = Date.now();
        try {
          const { compile } = await import('./BuilderDocument');
          const compiled = compile(message.document) as CompiledDocument;

          runtime.updateSession({
            document: {
              storeId: compiled.storeId,
              tenantId: compiled.tenantId,
              storeName: compiled.storeName,
              storeSlug: compiled.storeSlug,
              publicationStatus: compiled.publicationStatus,
              branding: compiled.branding,
              pages: compiled.pages.map((page) => ({
                id: page.id,
                slug: page.slug,
                name: page.name,
                sections: page.sections.map((section) => ({
                  id: section.id,
                  type: section.type,
                  label: section.label,
                  props: section.props,
                  order: section.order,
                  visible: section.visible,
                })),
              })),
              locale: compiled.locale,
              currency: compiled.currency,
            },
          });

          const result = await runtime.renderPage(message.correlationId);
          onRender?.(result.html);

          return {
            ackType: 'RENDERED',
            correlationId: message.correlationId,
            timestamp: Date.now(),
            renderTimeMs: result.renderTimeMs,
          };
        } catch (err) {
          return {
            ackType: 'ERROR',
            correlationId: message.correlationId,
            timestamp: Date.now(),
            error: err instanceof Error ? err.message : String(err),
          };
        }
      }

      if (message.messageType === 'SECTION_UPDATE') {
        try {
          const result = await runtime.renderSection(
            message.pageId,
            message.sectionId,
            message.props,
            message.correlationId
          );
          onRender?.(result.html);

          return {
            ackType: 'RENDERED',
            correlationId: message.correlationId,
            timestamp: Date.now(),
            renderTimeMs: result.renderTimeMs,
            sectionId: message.sectionId,
          };
        } catch (err) {
          return {
            ackType: 'ERROR',
            correlationId: message.correlationId,
            timestamp: Date.now(),
            error: err instanceof Error ? err.message : String(err),
            sectionId: message.sectionId,
          };
        }
      }

      if (message.messageType === 'VIEWPORT_CHANGE') {
        runtime.updateSession({
          viewport: {
            width: message.width,
            label: message.label,
          },
        });

        try {
          const result = await runtime.renderPage(message.correlationId);
          onRender?.(result.html);

          return {
            ackType: 'RENDERED',
            correlationId: message.correlationId,
            timestamp: Date.now(),
            renderTimeMs: result.renderTimeMs,
          };
        } catch (err) {
          return {
            ackType: 'ERROR',
            correlationId: message.correlationId,
            timestamp: Date.now(),
            error: err instanceof Error ? err.message : String(err),
          };
        }
      }

      return {
        ackType: 'RENDERED',
        correlationId: message.correlationId,
        timestamp: Date.now(),
        renderTimeMs: 0,
      };
    },

    destroy() {
      destroyed = true;
    },
  };
}

// ResizeEngine.ts
// C7.4: Builder Pro — resize engine

import { BuilderDocument, SectionNode } from './BuilderDocument';
import { BuilderCommand } from './BuilderCommands';
import { GridSystem, SnapInput } from './GridSystem';
import { CanvasState, CanvasAction, reduceCanvasState, ResizeHandle, ResizeState as CanvasResizeState } from './CanvasState';

export interface ResizeCommandOptions {
  readonly document: BuilderDocument;
  readonly sectionId: string;
  readonly handle: ResizeHandle;
  readonly startSize: { width: number; height: number };
  readonly currentSize: { width: number; height: number };
}

export function createResizeCommand(options: ResizeCommandOptions): BuilderCommand {
  return {
    type: 'UPDATE_PROPS',
    pageId: '',
    sectionId: options.sectionId,
    props: {
      width: options.currentSize.width,
      height: options.currentSize.height,
    },
  };
}

export function reduceResizeState(
  state: CanvasState,
  action: CanvasAction
): CanvasState {
  return reduceCanvasState(state, action);
}

export function constrainResize(
  width: number,
  height: number,
  minSize: { width: number; height: number } = { width: 100, height: 100 },
  maxSize: { width: number; height: number } = { width: 2000, height: 2000 }
): { width: number; height: number } {
  return {
    width: Math.max(minSize.width, Math.min(maxSize.width, width)),
    height: Math.max(minSize.height, Math.min(maxSize.height, height)),
  };
}

export function applyAspectRatio(
  width: number,
  height: number,
  aspectRatio: number,
  handle: ResizeHandle
): { width: number; height: number } {
  if (handle === 'n' || handle === 's') {
    return { width, height: width / aspectRatio };
  }
  return { width: height * aspectRatio, height };
}

export function snapResizeToGrid(
  width: number,
  height: number,
  grid: GridSystem
): { width: number; height: number } {
  const snappedW = Math.round(width / grid.getConfig().gutter) * grid.getConfig().gutter;
  const snappedH = Math.round(height / grid.getConfig().gutter) * grid.getConfig().gutter;
  return { width: snappedW, height: snappedH };
}

// ResponsiveEditor.ts
// C7: Builder Pro — responsive properties per breakpoint

import { StoreConfig } from '../../runtime-core/src/RuntimeContext';
import { RuntimePage, RuntimeSection } from '../../runtime-core/src/RuntimeSection';
import { ViewportLabel } from './CanvasState';

export type Breakpoint = ViewportLabel;

export interface ResponsiveValue<T> {
  readonly desktop?: T;
  readonly tablet?: T;
  readonly mobile?: T;
}

export interface ResponsiveSectionProps {
  readonly sectionId: string;
  readonly props: Record<string, ResponsiveValue<any>>;
  readonly activeBreakpoint: Breakpoint;
}

export class ResponsiveEditor {
  private readonly breakpoints: ReadonlyArray<Breakpoint> = ['DESKTOP', 'TABLET', 'MOBILE'];
  private activeBreakpoint: Breakpoint = 'DESKTOP';

  public setBreakpoint(breakpoint: Breakpoint): void {
    this.activeBreakpoint = breakpoint;
  }

  public getActiveBreakpoint(): Breakpoint {
    return this.activeBreakpoint;
  }

  public getEffectiveProps(
    sectionId: string,
    baseProps: Record<string, any>,
    responsiveProps: Record<string, ResponsiveValue<any>>
  ): Record<string, any> {
    const effective: Record<string, any> = { ...baseProps };

    for (const [propName, responsiveValue] of Object.entries(responsiveProps)) {
      const breakpointValue = responsiveValue[this.activeBreakpoint.toLowerCase() as keyof ResponsiveValue<any>];
      if (breakpointValue !== undefined) {
        effective[propName] = breakpointValue;
      }
    }

    return effective;
  }

  public setResponsiveProp(
    sectionId: string,
    propName: string,
    value: any,
    breakpoint: Breakpoint
  ): Record<string, ResponsiveValue<any>> {
    return {
      [sectionId]: {
        ...({} as Record<string, ResponsiveValue<any>>),
        [breakpoint.toLowerCase()]: value,
      },
    };
  }

  public exportToStoreConfig(
    pages: ReadonlyArray<RuntimePage>,
    responsiveProps: Map<string, Record<string, ResponsiveValue<any>>>
  ): StoreConfig {
    const updatedPages = pages.map((page) => ({
      ...page,
      sections: page.sections.map((section: RuntimeSection) => {
        const sectionResponsive = responsiveProps.get(section.id);
        if (!sectionResponsive) {
          return section;
        }

        const effectiveProps = this.getEffectiveProps(section.id, section.props, sectionResponsive);
        return { ...section, props: effectiveProps };
      }),
    }));

    return {
      storeId: '',
      storeName: '',
      publicationStatus: 'DRAFT',
      branding: {
        primaryColor: '',
        secondaryColor: '',
        font: '',
      },
      pages: updatedPages,
    };
  }
}

