describe('createMemoryChannel', () => {
  it('delivers messages from builder to runtime side', () => {
    const { builderChannel, runtimeSide } = createMemoryChannel();
    const received: unknown[] = [];
    runtimeSide.onMessage(msg => received.push(msg));

