  });

  it('delivers acks from runtime to builder', () => {
    const { builderChannel, runtimeSide } = createMemoryChannel();
    const acks: unknown[] = [];
    builderChannel.onAck(ack => acks.push(ack));

    runtimeSide.sendAck({
      ackType: 'RENDERED',
      correlationId: 'test_123',
      timestamp: Date.now(),
      renderTimeMs: 42,
