import { z } from 'zod';
import { PlatformEventBusImpl } from '../../platform-core/src/events/PlatformEventBus';
import { ConsolePlatformLogger } from '../../platform-core/src/logger/Logger';
import { EventRegistry } from '../../platform-core/src/events/EventRegistry';
import { TenantSecurityException } from './CommerceEngine';

export const CustomerAddressSchema = z.object({
  id: z.string().min(1),
  type: z.enum(['SHIPPING', 'BILLING']),
  fullName: z.string().min(1),
  street: z.string().min(1),
  city: z.string().min(1),
  zipCode: z.string().min(1),
  country: z.string().min(1),
  isDefault: z.boolean(),
});
export type CustomerAddress = z.infer<typeof CustomerAddressSchema>;

export const CustomerProfileSchema = z.object({
  firstName: z.string().min(1),
  lastName: z.string().min(1),
  phone: z.string().optional(),
});
export type CustomerProfile = z.infer<typeof CustomerProfileSchema>;

export const CustomerPreferencesSchema = z.object({
  marketingConsent: z.boolean(),
  preferredCurrency: z.string().length(3),
  language: z.string().min(2),
});
export type CustomerPreferences = z.infer<typeof CustomerPreferencesSchema>;

export const CustomerSchema = z.object({
  id: z.string().min(1),
  tenantId: z.string().min(1),
  email: z.string().email(),
  profile: CustomerProfileSchema,
  addresses: z.array(CustomerAddressSchema),
  preferences: CustomerPreferencesSchema,
  createdAt: z.string().datetime(),
  updatedAt: z.string().datetime(),
});
export type Customer = z.infer<typeof CustomerSchema>;

export interface RegisterCustomerDto {
  email: string;
  profile: CustomerProfile;
  preferences?: Partial<CustomerPreferences>;
}

export interface UpdateProfileDto {
  firstName?: string;
  lastName?: string;
  phone?: string;
}

export class DuplicateCustomerException extends Error {
  constructor(message: string) {
    super(message);
    this.name = 'DuplicateCustomerException';
  }
}

export class CustomerAccountEngine {
  private readonly eventBus: PlatformEventBusImpl;
  private readonly logger: ConsolePlatformLogger;
  private readonly customers = new Map<string, Customer>(); // In-memory simulated repository

  constructor(options: {
    eventBus: PlatformEventBusImpl;
    logger: ConsolePlatformLogger;
  }) {
    this.eventBus = options.eventBus;
    this.logger = options.logger;

    // Register all customer lifecycle events
    const customerEvents = [
      'Customer.Created',
      'Customer.Updated',
      'Customer.AddressAdded',
      'Customer.PreferencesChanged',
    ];
    for (const evt of customerEvents) {
      EventRegistry.register(evt);
    }
  }

  private enforceTenantIsolation(tenantId: string, targetTenantId: string, contextMessage: string): void {
    if (tenantId !== targetTenantId) {
      throw new TenantSecurityException(
        `Cross-tenant access blocked during customer operation: ${contextMessage}. Active: ${tenantId}, Target: ${targetTenantId}`
      );
    }
  }

  /**
   * Retrieves a customer by ID (verifying tenant isolation).
   */
  public async getCustomer(tenantId: string, customerId: string): Promise<Customer> {
    const customer = this.customers.get(customerId);
    if (!customer) {
      throw new Error(`Customer not found: ${customerId}`);
    }
    this.enforceTenantIsolation(tenantId, customer.tenantId, 'Get customer profile');
    return customer;
  }

  /**
   * Safe manual injection for testing or seeding.
   */
  public setCustomerForTesting(customer: Customer): void {
    this.customers.set(customer.id, customer);
  }

  /**
   * Registers a new customer under a tenant.
   */
  public async registerCustomer(
    tenantId: string,
    dto: RegisterCustomerDto,
    correlationId?: string
  ): Promise<Customer> {
    const cid = correlationId || `cust_reg_${Date.now()}`;

    // Ensure email uniqueness within the scope of this specific tenant
    for (const existing of this.customers.values()) {
      if (existing.tenantId === tenantId && existing.email.toLowerCase() === dto.email.toLowerCase()) {
        throw new DuplicateCustomerException(
          `Customer with email '${dto.email}' already exists in tenant '${tenantId}'`
        );
      }
    }

    const customerId = `cust_${Math.random().toString(36).substr(2, 9)}`;

    const customer: Customer = {
      id: customerId,
      tenantId,
      email: dto.email,
      profile: dto.profile,
      addresses: [],
      preferences: {
        marketingConsent: dto.preferences?.marketingConsent ?? false,
        preferredCurrency: dto.preferences?.preferredCurrency ?? 'PLN',
        language: dto.preferences?.language ?? 'pl',
      },
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
    };

    CustomerSchema.parse(customer);
    this.customers.set(customerId, customer);

    await this.eventBus.publish({
      eventId: `evt_cust_created_${Math.random().toString(36).substr(2, 9)}`,
      eventType: 'Customer.Created',
      timestamp: new Date().toISOString(),
      correlationId: cid,
      tenantId,
      payload: { customerId, email: customer.email },
    });

    return customer;
  }

  /**
   * Updates profile information.
   */
  public async updateProfile(
    tenantId: string,
    customerId: string,
    dto: UpdateProfileDto,
    correlationId?: string
  ): Promise<Customer> {
    const cid = correlationId || `cust_up_${Date.now()}`;
    const customer = await this.getCustomer(tenantId, customerId);

    const updatedCustomer: Customer = {
      ...customer,
      profile: {
        firstName: dto.firstName ?? customer.profile.firstName,
        lastName: dto.lastName ?? customer.profile.lastName,
        phone: dto.phone !== undefined ? dto.phone : customer.profile.phone,
      },
      updatedAt: new Date().toISOString(),
    };

    CustomerSchema.parse(updatedCustomer);
    this.customers.set(customerId, updatedCustomer);

    await this.eventBus.publish({
      eventId: `evt_cust_up_${Math.random().toString(36).substr(2, 9)}`,
      eventType: 'Customer.Updated',
      timestamp: new Date().toISOString(),
      correlationId: cid,
      tenantId,
      payload: { customerId },
    });

    return updatedCustomer;
  }

  /**
   * Adds an address to the customer profile.
   */
  public async addAddress(
    tenantId: string,
    customerId: string,
    addressDto: Omit<CustomerAddress, 'id'>,
    correlationId?: string
  ): Promise<Customer> {
    const cid = correlationId || `cust_addr_${Date.now()}`;
    const customer = await this.getCustomer(tenantId, customerId);

    const addressId = `addr_${Math.random().toString(36).substr(2, 9)}`;
    const newAddress: CustomerAddress = {
      ...addressDto,
      id: addressId,
    };

    // If new address is default, reset existing defaults of the same type
    let updatedAddresses = customer.addresses.map((addr) => {
      if (newAddress.isDefault && addr.type === newAddress.type) {
        return { ...addr, isDefault: false };
      }
      return addr;
    });

    updatedAddresses.push(newAddress);

    const updatedCustomer: Customer = {
      ...customer,
      addresses: updatedAddresses,
      updatedAt: new Date().toISOString(),
    };

    CustomerSchema.parse(updatedCustomer);
    this.customers.set(customerId, updatedCustomer);

    await this.eventBus.publish({
      eventId: `evt_cust_addr_${Math.random().toString(36).substr(2, 9)}`,
      eventType: 'Customer.AddressAdded',
      timestamp: new Date().toISOString(),
      correlationId: cid,
      tenantId,
      payload: { customerId, addressId },
    });

    return updatedCustomer;
  }

  /**
   * Removes an address.
   */
  public async removeAddress(
    tenantId: string,
    customerId: string,
    addressId: string,
    correlationId?: string
  ): Promise<Customer> {
    const customer = await this.getCustomer(tenantId, customerId);

    const updatedAddresses = customer.addresses.filter((addr) => addr.id !== addressId);

    const updatedCustomer: Customer = {
      ...customer,
      addresses: updatedAddresses,
      updatedAt: new Date().toISOString(),
    };

    CustomerSchema.parse(updatedCustomer);
    this.customers.set(customerId, updatedCustomer);
    return updatedCustomer;
  }

  /**
   * Updates preferences (consent, preferred language/currency).
   */
  public async updatePreferences(
    tenantId: string,
    customerId: string,
    preferences: Partial<CustomerPreferences>,
    correlationId?: string
  ): Promise<Customer> {
    const cid = correlationId || `cust_pref_${Date.now()}`;
    const customer = await this.getCustomer(tenantId, customerId);

    const updatedCustomer: Customer = {
      ...customer,
      preferences: {
        marketingConsent: preferences.marketingConsent ?? customer.preferences.marketingConsent,
        preferredCurrency: preferences.preferredCurrency ?? customer.preferences.preferredCurrency,
        language: preferences.language ?? customer.preferences.language,
      },
      updatedAt: new Date().toISOString(),
    };

    CustomerSchema.parse(updatedCustomer);
    this.customers.set(customerId, updatedCustomer);

    await this.eventBus.publish({
      eventId: `evt_cust_pref_${Math.random().toString(36).substr(2, 9)}`,
      eventType: 'Customer.PreferencesChanged',
      timestamp: new Date().toISOString(),
      correlationId: cid,
      tenantId,
      payload: { customerId },
    });

    return updatedCustomer;
  }
}

import { z } from 'zod';
import { PlatformEventBusImpl } from '../../platform-core/src/events/PlatformEventBus';
import { ConsolePlatformLogger } from '../../platform-core/src/logger/Logger';
import { EventRegistry } from '../../platform-core/src/events/EventRegistry';
import { TenantSecurityException } from './CommerceEngine';
import { InvalidOrderStateException } from './CheckoutFlow';
export { InvalidOrderStateException };

export const ProcessedOrderStateSchema = z.enum([
  'CREATED',
  'PAYMENT_PENDING',
  'PAID',
  'PROCESSING',
  'READY_FOR_FULFILLMENT',
  'FULFILLED',
  'CANCELLED',
  'REFUNDED',
]);
export type ProcessedOrderState = z.infer<typeof ProcessedOrderStateSchema>;

export const ProcessedOrderItemSchema = z.object({
  productId: z.string().min(1),
  quantity: z.number().int().positive(),
  unitPriceGross: z.number().int().nonnegative(),
  totalGross: z.number().int().nonnegative(),
});
export type ProcessedOrderItem = z.infer<typeof ProcessedOrderItemSchema>;

export const ShippingDetailsSchema = z.object({
  fullName: z.string().min(1),
  street: z.string().min(1),
  city: z.string().min(1),
  zipCode: z.string().min(1),
  country: z.string().min(1),
});
export type ShippingDetails = z.infer<typeof ShippingDetailsSchema>;

export const ProcessedOrderSchema = z.object({
  id: z.string().min(1),
  tenantId: z.string().min(1),
  customerId: z.string().min(1),
  items: z.array(ProcessedOrderItemSchema),
  subtotalGross: z.number().int().nonnegative(),
  taxTotal: z.number().int().nonnegative(),
  grandTotalGross: z.number().int().nonnegative(),
  currency: z.string().length(3),
  paymentIntentId: z.string().optional(),
  status: ProcessedOrderStateSchema,
  shippingAddress: ShippingDetailsSchema,
  createdAt: z.string().datetime(),
  updatedAt: z.string().datetime(),
});
export type ProcessedOrder = z.infer<typeof ProcessedOrderSchema>;

export class OrderProcessingEngine {
  private readonly eventBus: PlatformEventBusImpl;
  private readonly logger: ConsolePlatformLogger;
  private readonly orders = new Map<string, ProcessedOrder>(); // In-memory simulated repository

  private readonly allowedTransitions: Record<ProcessedOrderState, Set<ProcessedOrderState>> = {
    CREATED: new Set(['PAYMENT_PENDING']),
    PAYMENT_PENDING: new Set(['PAID', 'CANCELLED']),
    PAID: new Set(['PROCESSING', 'CANCELLED']),
    PROCESSING: new Set(['READY_FOR_FULFILLMENT']),
    READY_FOR_FULFILLMENT: new Set(['FULFILLED']),
    FULFILLED: new Set(['REFUNDED']),
    CANCELLED: new Set([]),
    REFUNDED: new Set([]),
  };

  constructor(options: {
    eventBus: PlatformEventBusImpl;
    logger: ConsolePlatformLogger;
  }) {
    this.eventBus = options.eventBus;
    this.logger = options.logger;

    // Register all order lifecycle events
    const orderEvents = [
      'Order.Created',
      'Order.PaymentConfirmed',
      'Order.ProcessingStarted',
      'Order.Fulfilled',
      'Order.Cancelled',
      'Order.Refunded',
    ];
    for (const evt of orderEvents) {
      EventRegistry.register(evt);
    }

    // Async subscriber to Payment.Completed
    this.eventBus.subscribe<{ orderId?: string; paymentIntentId?: string }>('Payment.Completed', async (event) => {
      const { orderId, paymentIntentId } = event.payload;
      const tenantId = event.tenantId;
      if (tenantId && orderId && paymentIntentId) {
        try {
          await this.confirmPayment(tenantId, orderId, paymentIntentId, event.correlationId);
        } catch (err: any) {
          this.logger.error({
            message: `Auto-confirm payment failed for order ${orderId}: ${err.message}`,
            correlationId: event.correlationId,
            tenantId: event.tenantId,
          });
        }
      }
    });
  }

  private enforceTenantIsolation(tenantId: string, targetTenantId: string, contextMessage: string): void {
    if (tenantId !== targetTenantId) {
      throw new TenantSecurityException(
        `Cross-tenant access blocked during order processing: ${contextMessage}. Active: ${tenantId}, Target: ${targetTenantId}`
      );
    }
  }

  private transitionState(current: ProcessedOrderState, target: ProcessedOrderState, orderId: string): void {
    const allowed = this.allowedTransitions[current];
    if (!allowed || !allowed.has(target)) {
      throw new InvalidOrderStateException(
        `Invalid status transition for Order '${orderId}': '${current}' -> '${target}'`
      );
    }
  }

  /**
   * Retrieves an order by ID (verifying RLS).
   */
  public async getOrder(tenantId: string, orderId: string): Promise<ProcessedOrder> {
    const order = this.orders.get(orderId);
    if (!order) {
      throw new Error(`Order not found: ${orderId}`);
    }
    this.enforceTenantIsolation(tenantId, order.tenantId, 'Get order details');
    return order;
  }

  /**
   * Safe manual injection for testing or DB seeding.
   */
  public setOrderForTesting(order: ProcessedOrder): void {
    this.orders.set(order.id, order);
  }

  /**
   * Creates a new order in CREATED state.
   */
  public async createOrder(
    tenantId: string,
    customerId: string,
    items: ProcessedOrderItem[],
    shippingAddress: ShippingDetails,
    currency = 'PLN',
    correlationId?: string
  ): Promise<ProcessedOrder> {
    const cid = correlationId || `ord_create_${Date.now()}`;
    const orderId = `ord_${Math.random().toString(36).substr(2, 9)}`;

    let subtotalGross = 0;
    for (const item of items) {
      subtotalGross += item.totalGross;
    }

    // Assume flat tax rate 23% for totals calculation
    const taxTotal = Math.round(subtotalGross - (subtotalGross / 1.23));

    const order: ProcessedOrder = {
      id: orderId,
      tenantId,
      customerId,
      items,
      subtotalGross,
      taxTotal,
      grandTotalGross: subtotalGross,
      currency,
      status: 'CREATED',
      shippingAddress,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
    };

    ProcessedOrderSchema.parse(order);
    this.orders.set(orderId, order);

    await this.eventBus.publish({
      eventId: `evt_ord_created_${Math.random().toString(36).substr(2, 9)}`,
      eventType: 'Order.Created',
      timestamp: new Date().toISOString(),
      correlationId: cid,
      tenantId,
      payload: { orderId },
    });

    return order;
  }

  /**
   * Moves status CREATED -> PAYMENT_PENDING
   */
  public async invoiceOrder(
    tenantId: string,
    orderId: string,
    correlationId?: string
  ): Promise<ProcessedOrder> {
    const cid = correlationId || `ord_invoice_${Date.now()}`;
    const order = await this.getOrder(tenantId, orderId);

    this.transitionState(order.status, 'PAYMENT_PENDING', orderId);

    const updatedOrder: ProcessedOrder = {
      ...order,
      status: 'PAYMENT_PENDING',
      updatedAt: new Date().toISOString(),
    };

    this.orders.set(orderId, updatedOrder);
    return updatedOrder;
  }

  /**
   * Confirms payment for order: PAYMENT_PENDING -> PAID
   */
  public async confirmPayment(
    tenantId: string,
    orderId: string,
    paymentIntentId: string,
    correlationId?: string
  ): Promise<ProcessedOrder> {
    const cid = correlationId || `ord_pay_confirm_${Date.now()}`;
    const order = await this.getOrder(tenantId, orderId);

    if (order.status === 'PAID') {
      return order;
    }

    this.transitionState(order.status, 'PAID', orderId);

    const updatedOrder: ProcessedOrder = {
      ...order,
      status: 'PAID',
      paymentIntentId,
      updatedAt: new Date().toISOString(),
    };

    this.orders.set(orderId, updatedOrder);

    await this.eventBus.publish({
      eventId: `evt_ord_paid_${Math.random().toString(36).substr(2, 9)}`,
      eventType: 'Order.PaymentConfirmed',
      timestamp: new Date().toISOString(),
      correlationId: cid,
      tenantId,
      payload: { orderId, paymentIntentId },
    });

    return updatedOrder;
  }

  /**
   * Moves status: PAID -> PROCESSING
   */
  public async startProcessing(
    tenantId: string,
    orderId: string,
    correlationId?: string
  ): Promise<ProcessedOrder> {
    const cid = correlationId || `ord_proc_${Date.now()}`;
    const order = await this.getOrder(tenantId, orderId);

    this.transitionState(order.status, 'PROCESSING', orderId);

    const updatedOrder: ProcessedOrder = {
      ...order,
      status: 'PROCESSING',
      updatedAt: new Date().toISOString(),
    };

    this.orders.set(orderId, updatedOrder);

    await this.eventBus.publish({
      eventId: `evt_ord_proc_${Math.random().toString(36).substr(2, 9)}`,
      eventType: 'Order.ProcessingStarted',
      timestamp: new Date().toISOString(),
      correlationId: cid,
      tenantId,
      payload: { orderId },
    });

    return updatedOrder;
  }

  /**
   * Moves status: PROCESSING -> READY_FOR_FULFILLMENT
   */
  public async prepareFulfillment(
    tenantId: string,
    orderId: string,
    correlationId?: string
  ): Promise<ProcessedOrder> {
    const order = await this.getOrder(tenantId, orderId);
    this.transitionState(order.status, 'READY_FOR_FULFILLMENT', orderId);

    const updatedOrder: ProcessedOrder = {
      ...order,
      status: 'READY_FOR_FULFILLMENT',
      updatedAt: new Date().toISOString(),
    };

    this.orders.set(orderId, updatedOrder);
    return updatedOrder;
  }

  /**
   * Moves status: READY_FOR_FULFILLMENT -> FULFILLED
   */
  public async fulfillOrder(
    tenantId: string,
    orderId: string,
    correlationId?: string
  ): Promise<ProcessedOrder> {
    const cid = correlationId || `ord_fulfill_${Date.now()}`;
    const order = await this.getOrder(tenantId, orderId);

    this.transitionState(order.status, 'FULFILLED', orderId);

    const updatedOrder: ProcessedOrder = {
      ...order,
      status: 'FULFILLED',
      updatedAt: new Date().toISOString(),
    };

    this.orders.set(orderId, updatedOrder);

    await this.eventBus.publish({
      eventId: `evt_ord_fulfilled_${Math.random().toString(36).substr(2, 9)}`,
      eventType: 'Order.Fulfilled',
      timestamp: new Date().toISOString(),
      correlationId: cid,
      tenantId,
      payload: { orderId },
    });

    return updatedOrder;
  }

  /**
   * Moves status to CANCELLED (allowed from PAYMENT_PENDING or PAID)
   */
  public async cancelOrder(
    tenantId: string,
    orderId: string,
    correlationId?: string
  ): Promise<ProcessedOrder> {
    const cid = correlationId || `ord_cancel_${Date.now()}`;
    const order = await this.getOrder(tenantId, orderId);

    this.transitionState(order.status, 'CANCELLED', orderId);

    const updatedOrder: ProcessedOrder = {
      ...order,
      status: 'CANCELLED',
      updatedAt: new Date().toISOString(),
    };

    this.orders.set(orderId, updatedOrder);

    await this.eventBus.publish({
      eventId: `evt_ord_cancelled_${Math.random().toString(36).substr(2, 9)}`,
      eventType: 'Order.Cancelled',
      timestamp: new Date().toISOString(),
      correlationId: cid,
      tenantId,
      payload: { orderId },
    });

    return updatedOrder;
  }

  /**
   * Moves status: FULFILLED -> REFUNDED
   */
  public async refundOrder(
    tenantId: string,
    orderId: string,
    correlationId?: string
  ): Promise<ProcessedOrder> {
    const cid = correlationId || `ord_refund_${Date.now()}`;
    const order = await this.getOrder(tenantId, orderId);

    this.transitionState(order.status, 'REFUNDED', orderId);

    const updatedOrder: ProcessedOrder = {
      ...order,
      status: 'REFUNDED',
      updatedAt: new Date().toISOString(),
    };

    this.orders.set(orderId, updatedOrder);

    await this.eventBus.publish({
      eventId: `evt_ord_refunded_${Math.random().toString(36).substr(2, 9)}`,
      eventType: 'Order.Refunded',
      timestamp: new Date().toISOString(),
      correlationId: cid,
      tenantId,
      payload: { orderId },
    });

    return updatedOrder;
  }
}

import { PlatformEventBusImpl } from '../../platform-core/src/events/PlatformEventBus';
import { ConsolePlatformLogger } from '../../platform-core/src/logger/Logger';
import { EventRegistry } from '../../platform-core/src/events/EventRegistry';
import { TenantSecurityException } from './CommerceEngine';
import {
  PaymentIntent,
  PaymentState,
  Transaction,
  Refund,
  PaymentProviderAdapter,
  InvalidPaymentStateException,
} from './PaymentProviderAdapter';

export class PaymentEngine {
  private readonly eventBus: PlatformEventBusImpl;
  private readonly logger: ConsolePlatformLogger;

  // Set of allowed transitions for the state machine
  private readonly allowedTransitions: Record<PaymentState, Set<PaymentState>> = {
    CREATED: new Set(['PROCESSING']),
    PROCESSING: new Set(['AUTHORIZED', 'CAPTURED', 'FAILED']),
    AUTHORIZED: new Set(['CAPTURED', 'FAILED']),
    CAPTURED: new Set(['REFUNDED']),
    FAILED: new Set([]),
    REFUNDED: new Set([]),
  };

  constructor(options: {
    eventBus: PlatformEventBusImpl;
    logger: ConsolePlatformLogger;
  }) {
    this.eventBus = options.eventBus;
    this.logger = options.logger;

    // Register all payment domain events
    const paymentEvents = [
      'Payment.Created',
      'Payment.ProcessingStarted',
      'Payment.Completed',
      'Payment.Failed',
      'Payment.Refunded',
    ];
    for (const evt of paymentEvents) {
      EventRegistry.register(evt);
    }
  }

  private enforceTenantIsolation(tenantId: string, targetTenantId: string, contextMessage: string): void {
    if (tenantId !== targetTenantId) {
      throw new TenantSecurityException(
        `Cross-tenant access blocked during payment operation: ${contextMessage}. Active: ${tenantId}, Target: ${targetTenantId}`
      );
    }
  }

  private transitionState(current: PaymentState, target: PaymentState, intentId: string): void {
    const allowed = this.allowedTransitions[current];
    if (!allowed || !allowed.has(target)) {
      throw new InvalidPaymentStateException(
        `Invalid status transition for PaymentIntent '${intentId}': '${current}' -> '${target}'`
      );
    }
  }

  /**
   * Initializes a payment intent through a specified adapter.
   */
  public async createPaymentIntent(
    tenantId: string,
    orderId: string,
    amountGross: number,
    currency: string,
    adapter: PaymentProviderAdapter,
    correlationId?: string
  ): Promise<PaymentIntent> {
    const cid = correlationId || `pay_create_${Date.now()}`;

    this.logger.info({
      message: `Creating PaymentIntent for order: ${orderId} using provider: ${adapter.id}`,
      correlationId: cid,
      tenantId,
    });

    // Create the external intent in the payment gateway
    const externalResult = await adapter.createIntent({
      orderId,
      amountGross,
      currency,
    });

    const intent: PaymentIntent = {
      id: `intent_${Math.random().toString(36).substr(2, 9)}`,
      tenantId,
      orderId,
      amountGross,
      currency,
      status: 'CREATED',
      providerId: adapter.id,
      externalId: externalResult.externalId,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
    };

    await this.eventBus.publish({
      eventId: `evt_pay_created_${Math.random().toString(36).substr(2, 9)}`,
      eventType: 'Payment.Created',
      timestamp: new Date().toISOString(),
      correlationId: cid,
      tenantId,
      payload: { paymentIntentId: intent.id, orderId },
    });

    return intent;
  }

  /**
   * Transitions payment status: CREATED -> PROCESSING
   */
  public async startProcessing(
    tenantId: string,
    intent: PaymentIntent,
    correlationId?: string
  ): Promise<PaymentIntent> {
    const cid = correlationId || `pay_proc_${Date.now()}`;
    this.enforceTenantIsolation(tenantId, intent.tenantId, 'Start processing payment');
    this.transitionState(intent.status, 'PROCESSING', intent.id);

    const updatedIntent: PaymentIntent = {
      ...intent,
      status: 'PROCESSING',
      updatedAt: new Date().toISOString(),
    };

    await this.eventBus.publish({
      eventId: `evt_pay_proc_${Math.random().toString(36).substr(2, 9)}`,
      eventType: 'Payment.ProcessingStarted',
      timestamp: new Date().toISOString(),
      correlationId: cid,
      tenantId,
      payload: { paymentIntentId: intent.id },
    });

    return updatedIntent;
  }

  /**
   * Transitions payment status: PROCESSING/AUTHORIZED -> CAPTURED (Completed)
   */
  public async completePayment(
    tenantId: string,
    intent: PaymentIntent,
    correlationId?: string
  ): Promise<PaymentIntent> {
    const cid = correlationId || `pay_comp_${Date.now()}`;
    this.enforceTenantIsolation(tenantId, intent.tenantId, 'Complete payment');
    this.transitionState(intent.status, 'CAPTURED', intent.id);

    const updatedIntent: PaymentIntent = {
      ...intent,
      status: 'CAPTURED',
      updatedAt: new Date().toISOString(),
    };

    await this.eventBus.publish({
      eventId: `evt_pay_completed_${Math.random().toString(36).substr(2, 9)}`,
      eventType: 'Payment.Completed',
      timestamp: new Date().toISOString(),
      correlationId: cid,
      tenantId,
      payload: { paymentIntentId: intent.id, orderId: intent.orderId },
    });

    return updatedIntent;
  }

  /**
   * Transitions payment status: PROCESSING/AUTHORIZED -> FAILED
   */
  public async failPayment(
    tenantId: string,
    intent: PaymentIntent,
    correlationId?: string
  ): Promise<PaymentIntent> {
    const cid = correlationId || `pay_fail_${Date.now()}`;
    this.enforceTenantIsolation(tenantId, intent.tenantId, 'Fail payment');
    this.transitionState(intent.status, 'FAILED', intent.id);

    const updatedIntent: PaymentIntent = {
      ...intent,
      status: 'FAILED',
      updatedAt: new Date().toISOString(),
    };

    await this.eventBus.publish({
      eventId: `evt_pay_failed_${Math.random().toString(36).substr(2, 9)}`,
      eventType: 'Payment.Failed',
      timestamp: new Date().toISOString(),
      correlationId: cid,
      tenantId,
      payload: { paymentIntentId: intent.id, orderId: intent.orderId },
    });

    return updatedIntent;
  }

  /**
   * Processes a refund, transitioning CAPTURED -> REFUNDED
   */
  public async refundPayment(
    tenantId: string,
    intent: PaymentIntent,
    amount: number,
    reason: string,
    adapter: PaymentProviderAdapter,
    correlationId?: string
  ): Promise<{ intent: PaymentIntent; refund: Refund }> {
    const cid = correlationId || `pay_refund_${Date.now()}`;
    this.enforceTenantIsolation(tenantId, intent.tenantId, 'Refund payment');
    this.transitionState(intent.status, 'REFUNDED', intent.id);

    if (!intent.externalId) {
      throw new Error(`Cannot refund PaymentIntent '${intent.id}' because it has no externalId.`);
    }

    const refundResult = await adapter.refundPayment(intent.externalId, amount);

    const refund: Refund = {
      id: `ref_${Math.random().toString(36).substr(2, 9)}`,
      tenantId,
      paymentIntentId: intent.id,
      amount,
      reason,
      status: refundResult.success ? 'COMPLETED' : 'FAILED',
      createdAt: new Date().toISOString(),
    };

    const updatedIntent: PaymentIntent = {
      ...intent,
      status: 'REFUNDED',
      updatedAt: new Date().toISOString(),
    };

    await this.eventBus.publish({
      eventId: `evt_pay_refunded_${Math.random().toString(36).substr(2, 9)}`,
      eventType: 'Payment.Refunded',
      timestamp: new Date().toISOString(),
      correlationId: cid,
      tenantId,
      payload: { paymentIntentId: intent.id, refundId: refund.id, success: refundResult.success },
    });

    return { intent: updatedIntent, refund };
  }
}

export type PaymentState = 'CREATED' | 'PROCESSING' | 'AUTHORIZED' | 'CAPTURED' | 'FAILED' | 'REFUNDED';

export interface PaymentIntent {
  id: string;
  tenantId: string;
  orderId: string;
  amountGross: number;      // in smallest currency unit (cents, grosze)
  currency: string;
  status: PaymentState;
  providerId: string;
  externalId?: string;
  createdAt: string;
  updatedAt: string;
}

export interface Transaction {
  id: string;
  tenantId: string;
  paymentIntentId: string;
  type: 'CHARGE' | 'REFUND';
  amount: number;
  status: 'SUCCESS' | 'FAILED';
  rawResponse?: Record<string, any>;
  createdAt: string;
}

export interface Refund {
  id: string;
  tenantId: string;
  paymentIntentId: string;
  amount: number;
  reason: string;
  status: 'PENDING' | 'COMPLETED' | 'FAILED';
  createdAt: string;
}

export interface CreateProviderIntentDto {
  orderId: string;
  amountGross: number;
  currency: string;
  metadata?: Record<string, any>;
}

export interface PaymentProviderAdapter {
  readonly id: string;
  createIntent(dto: CreateProviderIntentDto): Promise<{
    externalId: string;
    clientSecret?: string;
    rawPayload: any;
  }>;
  getPaymentStatus(externalId: string): Promise<PaymentState>;
  refundPayment(externalId: string, amount: number): Promise<{
    refundExternalId: string;
    success: boolean;
    rawPayload: any;
  }>;
}

export class InvalidPaymentStateException extends Error {
  constructor(message: string) {
    super(message);
    this.name = 'InvalidPaymentStateException';
  }
}

export interface LabelGenerationResult {
  trackingNumber: string;
  labelUrl: string;
}

export interface ShippingProviderAdapter {
  getCarrierCode(): string; // e.g. "DHL", "INPOST"
  createShipment(recipientAddress: {
    fullName: string;
    street: string;
    city: string;
    zipCode: string;
    country: string;
  }): Promise<LabelGenerationResult>;
}

export class MockShippingProviderAdapter implements ShippingProviderAdapter {
  private readonly carrier: string;

  constructor(carrier: string) {
    this.carrier = carrier;
  }

  public getCarrierCode(): string {
    return this.carrier;
  }

  public async createShipment(recipientAddress: {
    fullName: string;
    street: string;
    city: string;
    zipCode: string;
    country: string;
  }): Promise<LabelGenerationResult> {
    const randomSuffix = Math.random().toString(36).substr(2, 9).toUpperCase();
    const trackingNumber = `${this.carrier}_TRK_${randomSuffix}`;
    const labelUrl = `https://labels.platform.com/${this.carrier.toLowerCase()}/${trackingNumber}.pdf`;

    return {
      trackingNumber,
      labelUrl,
    };
  }
}

