describe('Customer Account Engine', () => {
  let engine: CustomerAccountEngine;
  let eventBus: PlatformEventBusImpl;
  let logger: ConsolePlatformLogger;
  let originalEnv: string | undefined;

  beforeEach(() => {
    originalEnv = process.env.NODE_ENV;
    (process.env as any).NODE_ENV = 'development';
    ConfigurationManager.resetInstanceForTesting();

    logger = new ConsolePlatformLogger();
    eventBus = new PlatformEventBusImpl(logger);
    logger.setEventBus(eventBus);

    engine = new CustomerAccountEngine({ eventBus, logger });
  });

  afterEach(() => {
    (process.env as any).NODE_ENV = originalEnv;
    ConfigurationManager.resetInstanceForTesting();
    vi.restoreAllMocks();
  });

  it('Should successfully register customer, update profile, preferences and emit events', async () => {
    const tenantId = 'tenant-shop-xyz';
    const email = 'client@example.com';

    const spyPublish = vi.spyOn(eventBus, 'publish');

    // 1. Register customer
    let customer = await engine.registerCustomer(tenantId, {
      email,
      profile: {
        firstName: 'Anna',
        lastName: 'Kowalska',
      },
      preferences: {
        language: 'pl',
        preferredCurrency: 'PLN',
        marketingConsent: true,
      },
    });

    expect(customer.tenantId).toBe(tenantId);
    expect(customer.email).toBe(email);
    expect(customer.profile.firstName).toBe('Anna');
    expect(customer.preferences.marketingConsent).toBe(true);
    expect(spyPublish).toHaveBeenCalled();

    // 2. Update Profile
    customer = await engine.updateProfile(tenantId, customer.id, {
      firstName: 'Ania',
      phone: '+48123456789',
    });
    expect(customer.profile.firstName).toBe('Ania');
    expect(customer.profile.phone).toBe('+48123456789');

    // 3. Update Preferences
    customer = await engine.updatePreferences(tenantId, customer.id, {
      marketingConsent: false,
    });
    expect(customer.preferences.marketingConsent).toBe(false);
  });

  it('Should prevent duplicate customer emails within the same tenant but allow across different tenants', async () => {
    const tenantA = 'tenant-a';
    const tenantB = 'tenant-b';
    const email = 'user@example.com';

    // Register in Tenant A
    await engine.registerCustomer(tenantA, {
      email,
      profile: { firstName: 'User', lastName: 'A' },
    });

    // Try duplicate in Tenant A -> throws DuplicateCustomerException
    await expect(
      engine.registerCustomer(tenantA, {
        email,
        profile: { firstName: 'Another', lastName: 'A' },
      })
    ).rejects.toThrow(DuplicateCustomerException);

    // Register same email in Tenant B -> allowed
    const customerB = await engine.registerCustomer(tenantB, {
      email,
      profile: { firstName: 'User', lastName: 'B' },
    });

    expect(customerB.tenantId).toBe(tenantB);
    expect(customerB.email).toBe(email);
  });

  it('Should manage customer addresses and reset defaults correctly', async () => {
    const tenantId = 'tenant-shop-xyz';
    let customer = await engine.registerCustomer(tenantId, {
      email: 'addresses@example.com',
      profile: { firstName: 'Jan', lastName: 'Kowalski' },
    });

    // Add first address (SHIPPING, default = true)
    customer = await engine.addAddress(tenantId, customer.id, {
      type: 'SHIPPING',
      fullName: 'Jan Kowalski',
      street: 'Wawelska 1',
      city: 'Krakow',
      zipCode: '30-001',
      country: 'PL',
      isDefault: true,
    });

    expect(customer.addresses.length).toBe(1);
    expect(customer.addresses[0].isDefault).toBe(true);

    const firstAddressId = customer.addresses[0].id;

    // Add second address (SHIPPING, default = true) -> resets the first one
    customer = await engine.addAddress(tenantId, customer.id, {
      type: 'SHIPPING',
      fullName: 'Jan Kowalski Office',
      street: 'Florianska 10',
      city: 'Krakow',
      zipCode: '31-002',
      country: 'PL',
      isDefault: true,
    });

    expect(customer.addresses.length).toBe(2);

    const addr1 = customer.addresses.find((a) => a.id === firstAddressId);
    const addr2 = customer.addresses.find((a) => a.id !== firstAddressId);

    expect(addr1?.isDefault).toBe(false);
    expect(addr2?.isDefault).toBe(true);

    // Remove address
    customer = await engine.removeAddress(tenantId, customer.id, firstAddressId);
    expect(customer.addresses.length).toBe(1);
    expect(customer.addresses[0].id).toBe(addr2?.id);
  });

  it('Should enforce tenant isolation and throw TenantSecurityException on cross-tenant access', async () => {
    const tenantA = 'tenant-a';
    const tenantB = 'tenant-b';

    const customerA = await engine.registerCustomer(tenantA, {
      email: 'a@example.com',
      profile: { firstName: 'Alice', lastName: 'A' },
    });

    // Tenant B trying to fetch Customer A -> throws
    await expect(
      engine.getCustomer(tenantB, customerA.id)
    ).rejects.toThrow(TenantSecurityException);

    // Tenant B trying to update Customer A -> throws
    await expect(
      engine.updateProfile(tenantB, customerA.id, { firstName: 'Hack' })
    ).rejects.toThrow(TenantSecurityException);
  });
});

import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';
import { PlatformEventBusImpl } from '../../platform-core/src/events/PlatformEventBus';
import { ConsolePlatformLogger } from '../../platform-core/src/logger/Logger';
import { ConfigurationManager } from '../../platform-core/src/config/PlatformConfig';
import { InventoryEngine } from './InventoryEngine';
import { InsufficientInventoryException } from './CartRuntime';
import { TenantSecurityException } from './CommerceEngine';

describe('Inventory Engine', () => {
  let engine: InventoryEngine;
  let eventBus: PlatformEventBusImpl;
  let logger: ConsolePlatformLogger;
  let originalEnv: string | undefined;

  beforeEach(() => {
    originalEnv = process.env.NODE_ENV;
    (process.env as any).NODE_ENV = 'development';
    ConfigurationManager.resetInstanceForTesting();

    logger = new ConsolePlatformLogger();
    eventBus = new PlatformEventBusImpl(logger);
    logger.setEventBus(eventBus);

    engine = new InventoryEngine({ eventBus, logger });
  });

  afterEach(() => {
    (process.env as any).NODE_ENV = originalEnv;
    ConfigurationManager.resetInstanceForTesting();
    vi.restoreAllMocks();
  });

  it('Should reserve, commit stock and generate correct movements', async () => {
    const tenantId = 'tenant-shop-xyz';
    const productId = 'prod_test_item';
    const orderId = 'ord_111';

    // 1. Initialize stock to 10
    engine.initializeStock(tenantId, productId, 10, 3);

    // 2. Reserve 4 units
    const reservation = await engine.reserveStock(tenantId, orderId, productId, 4, 30);
    expect(reservation.productId).toBe(productId);
    expect(reservation.quantity).toBe(4);
    expect(reservation.status).toBe('PENDING');

    // Verify stock state (available: 6, reserved: 4)
    let stock = await engine.getStock(tenantId, productId);
    expect(stock.quantityAvailable).toBe(6);
    expect(stock.quantityReserved).toBe(4);

    // 3. Commit stock
    const movement = await engine.commitStock(tenantId, reservation.id);
    expect(movement.productId).toBe(productId);
    expect(movement.quantityDelta).toBe(-4);
    expect(movement.type).toBe('RESERVATION_COMMIT');

    // Verify final stock state (available: 6, reserved: 0)
    stock = await engine.getStock(tenantId, productId);
    expect(stock.quantityAvailable).toBe(6);
    expect(stock.quantityReserved).toBe(0);

    const movements = engine.getMovementsForTesting(tenantId);
    expect(movements.length).toBe(1);
    expect(movements[0].id).toBe(movement.id);
  });

  it('Should throw InsufficientInventoryException when reserving exceeds available stock', async () => {
    const tenantId = 'tenant-shop-xyz';
    const productId = 'prod_test_item';

    engine.initializeStock(tenantId, productId, 5, 2);

    await expect(
      engine.reserveStock(tenantId, 'ord_123', productId, 6, 30)
    ).rejects.toThrow(InsufficientInventoryException);
  });

  it('Should release stock back to available list', async () => {
    const tenantId = 'tenant-shop-xyz';
    const productId = 'prod_test_item';
    const orderId = 'ord_111';

    engine.initializeStock(tenantId, productId, 10);

    const reservation = await engine.reserveStock(tenantId, orderId, productId, 3, 30);
    let stock = await engine.getStock(tenantId, productId);
    expect(stock.quantityAvailable).toBe(7);
    expect(stock.quantityReserved).toBe(3);

    // Release reservation
    await engine.releaseStock(tenantId, reservation.id);

    stock = await engine.getStock(tenantId, productId);
    expect(stock.quantityAvailable).toBe(10);
    expect(stock.quantityReserved).toBe(0);
  });

  it('Should emit low stock warning event when stock falls below threshold', async () => {
    const tenantId = 'tenant-shop-xyz';
    const productId = 'prod_test_item';

    engine.initializeStock(tenantId, productId, 10, 3);

    const spyPublish = vi.spyOn(eventBus, 'publish');

    // Reduce stock by 8 units (new level: 2 <= threshold 3)
    await engine.adjustStock(tenantId, productId, -8, 'ADJUSTMENT', 'Damage correction');

    expect(spyPublish).toHaveBeenCalled();
    const eventCall = spyPublish.mock.calls.find((call) => call[0].eventType === 'Inventory.LowStock');
    expect(eventCall).toBeDefined();
    expect(eventCall?.[0].payload.quantityAvailable).toBe(2);
  });

  it('Should enforce tenant boundaries and throw TenantSecurityException on cross-tenant operations', async () => {
    const tenantA = 'tenant-a';
    const tenantB = 'tenant-b';
    const productId = 'prod_test_item';

    engine.initializeStock(tenantA, productId, 10);

    const reservation = await engine.reserveStock(tenantA, 'ord_123', productId, 2, 30);

    // Tenant B attempts to commit Tenant A's reservation -> throws TenantSecurityException
    await expect(
      engine.commitStock(tenantB, reservation.id)
    ).rejects.toThrow(TenantSecurityException);

    // Tenant B attempts to release Tenant A's reservation -> throws TenantSecurityException
    await expect(
      engine.releaseStock(tenantB, reservation.id)
    ).rejects.toThrow(TenantSecurityException);
  });
});

import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';
import { PlatformEventBusImpl } from '../../platform-core/src/events/PlatformEventBus';
import { ConsolePlatformLogger } from '../../platform-core/src/logger/Logger';
import { ConfigurationManager } from '../../platform-core/src/config/PlatformConfig';
import { OrderProcessingEngine, InvalidOrderStateException, ProcessedOrderItem } from './OrderProcessingEngine';
import { TenantSecurityException } from './CommerceEngine';

describe('Order Processing Engine', () => {
  let engine: OrderProcessingEngine;
  let eventBus: PlatformEventBusImpl;
  let logger: ConsolePlatformLogger;
  let originalEnv: string | undefined;

  beforeEach(() => {
    originalEnv = process.env.NODE_ENV;
    (process.env as any).NODE_ENV = 'development';
    ConfigurationManager.resetInstanceForTesting();

    logger = new ConsolePlatformLogger();
    eventBus = new PlatformEventBusImpl(logger);
    logger.setEventBus(eventBus);

    engine = new OrderProcessingEngine({ eventBus, logger });
  });

  afterEach(() => {
    (process.env as any).NODE_ENV = originalEnv;
    ConfigurationManager.resetInstanceForTesting();
    vi.restoreAllMocks();
  });

  it('Should transition order states correctly in happy path: CREATED -> PAYMENT_PENDING -> PAID -> PROCESSING -> READY_FOR_FULFILLMENT -> FULFILLED', async () => {
    const tenantId = 'tenant-shop-xyz';
    const customerId = 'cust_123';

    const items: ProcessedOrderItem[] = [
      {
        productId: 'prod_1',
        quantity: 2,
        unitPriceGross: 1000,
        totalGross: 2000,
      },
    ];

    const shippingAddress = {
      fullName: 'Jan Kowalski',
      street: 'Krucza 5',
      city: 'Krakow',
      zipCode: '31-001',
      country: 'PL',
    };

    // 1. Create order
    let order = await engine.createOrder(tenantId, customerId, items, shippingAddress);
    expect(order.status).toBe('CREATED');
    expect(order.grandTotalGross).toBe(2000);

    // 2. Invoice order (CREATED -> PAYMENT_PENDING)
    order = await engine.invoiceOrder(tenantId, order.id);
    expect(order.status).toBe('PAYMENT_PENDING');

    // 3. Confirm Payment (PAYMENT_PENDING -> PAID)
    order = await engine.confirmPayment(tenantId, order.id, 'pi_stripe_abc');
    expect(order.status).toBe('PAID');
    expect(order.paymentIntentId).toBe('pi_stripe_abc');

    // 4. Start Processing (PAID -> PROCESSING)
    order = await engine.startProcessing(tenantId, order.id);
    expect(order.status).toBe('PROCESSING');

    // 5. Prepare (PROCESSING -> READY_FOR_FULFILLMENT)
    order = await engine.prepareFulfillment(tenantId, order.id);
    expect(order.status).toBe('READY_FOR_FULFILLMENT');

    // 6. Fulfill (READY_FOR_FULFILLMENT -> FULFILLED)
    order = await engine.fulfillOrder(tenantId, order.id);
    expect(order.status).toBe('FULFILLED');
  });

  it('Should automatically transition PAYMENT_PENDING to PAID when Payment.Completed event is received', async () => {
    const tenantId = 'tenant-shop-xyz';
    const customerId = 'cust_123';
    const items = [{ productId: 'p1', quantity: 1, unitPriceGross: 100, totalGross: 100 }];
    const shipping = { fullName: 'A', street: 'B', city: 'C', zipCode: 'D', country: 'E' };

    let order = await engine.createOrder(tenantId, customerId, items, shipping);
    order = await engine.invoiceOrder(tenantId, order.id);
    expect(order.status).toBe('PAYMENT_PENDING');

    // Publish simulated Payment.Completed event via event bus
    await eventBus.publish({
      eventId: 'evt_sim_pay_comp',
      eventType: 'Payment.Completed',
      timestamp: new Date().toISOString(),
      correlationId: 'corr_test_event',
      tenantId,
      payload: {
        orderId: order.id,
        paymentIntentId: 'pi_stripe_completed',
      },
    });

    // Wait short tick for microtask queue to run event handlers
    await new Promise((resolve) => setTimeout(resolve, 10));

    // Get order from engine and verify transition
    const updatedOrder = await engine.getOrder(tenantId, order.id);
    expect(updatedOrder.status).toBe('PAID');
    expect(updatedOrder.paymentIntentId).toBe('pi_stripe_completed');
  });

  it('Should throw TenantSecurityException on cross-tenant order modification attempts', async () => {
    const tenantA = 'tenant-a';
    const tenantB = 'tenant-b';
    const customerId = 'cust_123';
    const items = [{ productId: 'p1', quantity: 1, unitPriceGross: 100, totalGross: 100 }];
    const shipping = { fullName: 'A', street: 'B', city: 'C', zipCode: 'D', country: 'E' };

    const orderA = await engine.createOrder(tenantA, customerId, items, shipping);

    // Tenant B trying to access/modify Tenant A's order -> throws
    await expect(
      engine.invoiceOrder(tenantB, orderA.id)
    ).rejects.toThrow(TenantSecurityException);

    await expect(
      engine.getOrder(tenantB, orderA.id)
    ).rejects.toThrow(TenantSecurityException);
  });

  it('Should throw InvalidOrderStateException for illegal order transitions', async () => {
    const tenantId = 'tenant-shop-xyz';
    const customerId = 'cust_123';
    const items = [{ productId: 'p1', quantity: 1, unitPriceGross: 100, totalGross: 100 }];
    const shipping = { fullName: 'A', street: 'B', city: 'C', zipCode: 'D', country: 'E' };

    let order = await engine.createOrder(tenantId, customerId, items, shipping);

    // Cannot go directly CREATED -> PAID (must go through PAYMENT_PENDING)
    await expect(
      engine.confirmPayment(tenantId, order.id, 'pi_123')
    ).rejects.toThrow(InvalidOrderStateException);

    order = await engine.invoiceOrder(tenantId, order.id);

    // Can cancel from PAYMENT_PENDING
    order = await engine.cancelOrder(tenantId, order.id);
    expect(order.status).toBe('CANCELLED');

    // Cannot process cancelled order
    await expect(
      engine.startProcessing(tenantId, order.id)
