// ComponentManifest.ts
// C6.3-E: Component Runtime Engine — manifest loading and validation

import { z } from 'zod';
import { ComponentManifest, ComponentPropsSchema, ComponentLoader } from './ComponentTypes';

const ComponentPropsSchemaSchema = z.object({
  type: z.enum(['string', 'number', 'boolean', 'asset', 'rich_text', 'select', 'color']),
  required: z.boolean().optional(),
  default: z.any().optional(),
  options: z.array(z.any()).optional(),
});

const ComponentManifestSchema = z.object({
  id: z.string().min(1),
  version: z.string().min(1),
  category: z.enum(['layout', 'widget', 'atom', 'section', 'page']),
  displayName: z.string().min(1),
  description: z.string().optional(),
  propsSchema: z.record(z.string(), ComponentPropsSchemaSchema),
  runtime: z.object({
    loader: z.any(),
  }),
  dependencies: z.array(z.string()).optional(),
  capabilities: z.array(z.string()).optional(),
});

export type ComponentManifestInput = z.infer<typeof ComponentManifestSchema>;

export interface LoadedComponentManifest extends ComponentManifest {
  readonly loadedAt: string;
}

export class ComponentManifestLoader {
  async load(manifest: ComponentManifestInput): Promise<LoadedComponentManifest> {
    ComponentManifestSchema.parse(manifest);

    const loader = manifest.runtime.loader as ComponentLoader;

    return {
      id: manifest.id,
      version: manifest.version,
      category: manifest.category,
      displayName: manifest.displayName,
      description: manifest.description,
      propsSchema: manifest.propsSchema,
      runtime: {
        loader,
      },
      dependencies: manifest.dependencies,
      capabilities: manifest.capabilities,
      loadedAt: new Date().toISOString(),
    };
  }

  validate(manifest: ComponentManifestInput): boolean {
    return ComponentManifestSchema.safeParse(manifest).success;
  }
}

// ComponentRegistry.ts
// C6.3-E: Component Runtime Engine — component registry with tenant isolation

import { ComponentManifest, ComponentRegistration, ResolvedComponent } from './ComponentTypes';

export class ComponentRegistry {
  private readonly components = new Map<string, ComponentRegistration>();
  private readonly tenantScopes = new Map<string, Set<string>>();

  register(registration: ComponentRegistration, tenantId?: string): void {
    const key = registration.manifest.id;
    this.components.set(key, registration);

    if (tenantId) {
      let scope = this.tenantScopes.get(tenantId);
      if (!scope) {
        scope = new Set();
        this.tenantScopes.set(tenantId, scope);
      }
      scope.add(key);
    }
  }

  resolve(componentId: string, tenantId?: string): ComponentRegistration | undefined {
    const global = this.components.get(componentId);
    if (!tenantId) {
      return global;
    }
    const scope = this.tenantScopes.get(tenantId);
    if (scope && scope.has(componentId)) {
      return global;
    }
    return undefined;
  }

  has(componentId: string, tenantId?: string): boolean {
    return this.resolve(componentId, tenantId) !== undefined;
  }

  list(tenantId?: string): ComponentRegistration[] {
    if (!tenantId) {
      return Array.from(this.components.values());
    }

    const scope = this.tenantScopes.get(tenantId);
    if (!scope) {
      return [];
    }

    return Array.from(scope)
      .map((id) => this.components.get(id))
      .filter((registration): registration is ComponentRegistration => registration !== undefined);
  }

  remove(componentId: string, tenantId?: string): boolean {
    const existed = this.components.has(componentId);

    if (tenantId) {
      const scope = this.tenantScopes.get(tenantId);
      scope?.delete(componentId);
    }

    this.components.delete(componentId);
    return existed;
  }

  clear(tenantId?: string): void {
    if (tenantId) {
      const scope = this.tenantScopes.get(tenantId);
      if (scope) {
        for (const id of scope) {
          this.components.delete(id);
        }
        scope.clear();
      }
    } else {
      this.components.clear();
      this.tenantScopes.clear();
    }
  }
}

// ComponentRenderer.ts
// C6.3-E: Component Runtime Engine — component rendering with props binding

import React from 'react';
import { renderToString } from 'react-dom/server';
import { ComponentManifest, ComponentRenderContext, ResolvedComponent } from './ComponentTypes';

export class ComponentRenderException extends Error {
  constructor(componentId: string, cause: unknown) {
    const message = cause instanceof Error ? cause.message : String(cause);
    super(`Failed to render component: '${componentId}': ${message}`);
    this.name = 'ComponentRenderException';
    this.cause = cause;
  }
}

export class ComponentRenderer {
  constructor(private readonly resolver: {
    resolve(componentId: string, tenantId?: string): Promise<ResolvedComponent>;
  }) {}

  async render(
    componentId: string,
    props: Record<string, any>,
    context: ComponentRenderContext
  ): Promise<string> {
    const resolved = await this.resolver.resolve(componentId);
    const normalizedProps = await this.normalizeProps(resolved.manifest, props, context);

    try {
      const Component = resolved.component;
      const element = React.createElement(Component, {
        ...normalizedProps,
        __componentContext: context,
      });

      return renderToString(element);
    } catch (err) {
      throw new ComponentRenderException(componentId, err);
    }
  }

  private async normalizeProps(
    manifest: ComponentManifest,
    props: Record<string, any>,
    context: ComponentRenderContext
  ): Promise<Record<string, any>> {
    const normalized: Record<string, any> = {};

    for (const [key, schema] of Object.entries(manifest.propsSchema)) {
      if (key in props) {
        const value = props[key];

        if (schema.type === 'asset' && typeof value === 'object' && value !== null && 'id' in value) {
          normalized[key] = this.resolveAsset(value, context);
        } else if (schema.type === 'color') {
          normalized[key] = this.normalizeColor(value, schema.default);
        } else if (schema.type === 'string') {
          normalized[key] = String(value ?? schema.default ?? '');
        } else if (schema.type === 'number') {
          normalized[key] = Number(value ?? schema.default ?? 0);
        } else if (schema.type === 'boolean') {
          normalized[key] = Boolean(value ?? schema.default ?? false);
        } else {
          normalized[key] = value ?? schema.default;
        }
      } else if (schema.required) {
        normalized[key] = schema.default;
      }
    }

    return normalized;
  }

  private async resolveAsset(
    assetReference: { id: string; type: string },
    context: ComponentRenderContext
  ): Promise<string> {
    return context.assets.resolve(assetReference);
  }

  private normalizeColor(value: any, defaultValue: string): string {
    if (typeof value === 'string' && /^#[0-9a-fA-F]{6}$/.test(value)) {
      return value;
    }
    if (typeof value === 'string' && value.startsWith('var(')) {
      return value;
    }
    return defaultValue || '#000000';
  }
}

// ComponentResolver.ts
// C6.3-E: Component Runtime Engine — dynamic component resolution and loading

import { ComponentManifest, ResolvedComponent } from './ComponentTypes';
import { ComponentRegistry } from './ComponentRegistry';

export class ComponentLoadException extends Error {
  constructor(componentId: string, cause: unknown) {
    super(`Failed to load component: '${componentId}'`);
    this.name = 'ComponentLoadException';
    this.cause = cause;
  }
}

export class ComponentNotFoundException extends Error {
  constructor(componentId: string) {
    super(`Component not found in registry: '${componentId}'`);
    this.name = 'ComponentNotFoundException';
  }
}

export class ComponentResolver {
  private readonly cache = new Map<string, ResolvedComponent>();

  constructor(private readonly registry: ComponentRegistry) {}

  async resolve(componentId: string, tenantId?: string): Promise<ResolvedComponent> {
    const cacheKey = tenantId ? `${tenantId}:${componentId}` : componentId;

    if (this.cache.has(cacheKey)) {
      return this.cache.get(cacheKey)!;
    }

    const registration = this.registry.resolve(componentId, tenantId);
    if (!registration) {
      throw new ComponentNotFoundException(componentId);
    }

    const component = await this.loadComponent(registration.manifest);
    const resolved: ResolvedComponent = {
      manifest: registration.manifest,
      component,
    };

    this.cache.set(cacheKey, resolved);
    return resolved;
  }

  async resolveAll(componentIds: string[], tenantId?: string): Promise<ResolvedComponent[]> {
    const promises = componentIds.map((id) => this.resolve(id, tenantId));
    return Promise.all(promises);
  }

  clearCache(componentId?: string): void {
    if (componentId) {
      this.cache.delete(componentId);
    } else {
      this.cache.clear();
    }
  }

  private async loadComponent(manifest: ComponentManifest): Promise<React.ComponentType<Record<string, any>>> {
    try {
      const module = await manifest.runtime.loader();
      const Component = module.default;

      if (!Component || typeof Component !== 'function') {
        throw new Error(`Component '${manifest.id}' does not export a default React component`);
      }

      return Component;
    } catch (err) {
      throw new ComponentLoadException(manifest.id, err);
    }
  }
}

// ComponentTypes.ts
// C6.3-E: Component Runtime Engine — core type contracts

export type ComponentCategory = 'layout' | 'widget' | 'atom' | 'section' | 'page';

export type ComponentLoader = () => Promise<{
  default: React.ComponentType<Record<string, any>>;
}>;

export interface ComponentPropsSchema {
  type: 'string' | 'number' | 'boolean' | 'asset' | 'rich_text' | 'select' | 'color';
  required?: boolean;
  default?: any;
  options?: readonly any[];
}

export interface ComponentManifest {
  readonly id: string;
  readonly version: string;
  readonly category: ComponentCategory;
  readonly displayName: string;
  readonly description?: string;
  readonly propsSchema: Record<string, ComponentPropsSchema>;
  readonly runtime: {
    loader: ComponentLoader;
  };
  readonly dependencies?: readonly string[];
  readonly capabilities?: readonly string[];
}

export interface ComponentRegistration {
  readonly manifest: ComponentManifest;
  readonly loadedAt: string;
  readonly tenantId?: string;
}

export interface ResolvedComponent {
  readonly manifest: ComponentManifest;
  readonly component: React.ComponentType<Record<string, any>>;
}

export interface ComponentRenderContext {
  readonly tenantId: string;
  readonly theme: {
    readonly primaryColor: string;
    readonly secondaryColor: string;
    readonly fontFamily: string;
    readonly backgroundColor: string;
    readonly borderRadius: string;
  };
  readonly assets: {
    resolve(reference: { id: string; type: string }, options?: Record<string, any>): Promise<string>;
  };
  readonly locale: string;
  readonly currency: string;
  readonly runtimeMode: 'preview' | 'publish' | 'editor';
}

