import { DefaultStoreManager, StoreManager } from '../../mission-control-core/src/StoreManagement';
import { CustomerContext } from './CustomerContext';

export interface PublishResult {
  success: boolean;
  deploymentUrl?: string;
  buildId?: string;
  errors: string[];
}

export interface PublishService {
  publish(ctx: CustomerContext): Promise<PublishResult>;
}

export class DefaultPublishService implements PublishService {
  private readonly storeManager: StoreManager;

  constructor(storeManager?: StoreManager) {
    this.storeManager = storeManager || new DefaultStoreManager();
  }

  async publish(ctx: CustomerContext): Promise<PublishResult> {
    if (!ctx.tenantId || !ctx.storeId) {
      throw new Error('Unauthorized: Invalid customer context');
    }

    // Create an AdminContext internally to invoke the store manager's publish logic
    const adminCtx = {
      userId: ctx.userId,
      role: 'OPERATOR' as const,
      permissions: [],
      correlationId: `pub_cust_${Date.now()}`
    };

    try {
      const res = await this.storeManager.publishStore(adminCtx, ctx.tenantId, ctx.storeId);
      return {
        success: res.status === 'SUCCESS' || res.success === true,
        deploymentUrl: res.deploymentUrl,
        buildId: res.buildId || res.metadata?.publishReport?.buildId,
        errors: res.errors || []
      };
    } catch (err: any) {
      return {
        success: false,
        errors: [err.message]
      };
    }
  }
}

import { getServiceSupabase } from '@/lib/supabase';
import { CustomerContext } from './CustomerContext';

export interface StoreDashboardService {
  getOverview(ctx: CustomerContext): Promise<any>;
  getStoreStatus(ctx: CustomerContext): Promise<any>;
  getUsage(ctx: CustomerContext): Promise<any>;
}

export class DefaultStoreDashboardService implements StoreDashboardService {
  private checkAccess(ctx: CustomerContext) {
    if (!ctx.tenantId || !ctx.storeId) {
      throw new Error('Unauthorized: Invalid customer context');
    }
  }

  async getOverview(ctx: CustomerContext): Promise<any> {
    this.checkAccess(ctx);
    const supabase = getServiceSupabase();

    // 1. Fetch store info
    const { data: store, error: storeErr } = await supabase
      .from('stores')
      .select('name, status, config, domain, slug')
      .eq('id', ctx.storeId)
      .eq('tenant_id', ctx.tenantId)
      .maybeSingle();

    if (storeErr || !store) {
      throw new Error(`Store not found or access denied: ${storeErr?.message || ''}`);
    }

    // 2. Fetch page and product counts
    const { count: pagesCount } = await supabase
      .from('pages')
      .select('*', { count: 'exact', head: true })
      .eq('store_id', ctx.storeId);

    const { count: productsCount } = await supabase
      .from('products')
      .select('*', { count: 'exact', head: true })
      .eq('store_id', ctx.storeId);

    // 3. Fetch orders / revenue from commerce orders table (mock fallback if table doesn't exist yet)
    let ordersCount = 0;
    let revenue = 0;
    try {
      const { data: orders } = await supabase
        .from('orders')
        .select('total_amount')
        .eq('store_id', ctx.storeId);

      if (orders) {
        ordersCount = orders.length;
        revenue = orders.reduce((sum, o) => sum + (o.total_amount || 0), 0);
      }
    } catch {
      // Fallback if orders table doesn't exist/empty
    }

    return {
      storeId: ctx.storeId,
      name: store.name,
      slug: store.slug,
      domain: store.domain,
      status: store.status,
      pagesCount: pagesCount || 0,
      productsCount: productsCount || 0,
      ordersCount,
      revenue,
      branding: store.config?.branding || {},
    };
  }

  async getStoreStatus(ctx: CustomerContext): Promise<any> {
    this.checkAccess(ctx);
    const supabase = getServiceSupabase();

    const { data: store, error } = await supabase
      .from('stores')
      .select('status, config, updated_at')
      .eq('id', ctx.storeId)
      .eq('tenant_id', ctx.tenantId)
      .maybeSingle();

    if (error || !store) {
      throw new Error(`Failed to retrieve store status: ${error?.message || ''}`);
    }

    // Find the latest deployment
    const { data: deployment } = await supabase
      .from('deployments')
      .select('id, status, url, created_at')
      .eq('store_id', ctx.storeId)
      .order('created_at', { ascending: false })
      .limit(1)
      .maybeSingle();

    return {
      status: store.status,
      publicationStatus: store.config?.publicationStatus || 'DRAFT',
      lastUpdated: store.updated_at,
      latestDeployment: deployment ? {
        id: deployment.id,
        status: deployment.status,
        url: deployment.url,
        deployedAt: deployment.created_at
      } : null
    };
  }

  async getUsage(ctx: CustomerContext): Promise<any> {
    this.checkAccess(ctx);
    const supabase = getServiceSupabase();

    // Fetch tenant limits
    const { data: tenant } = await supabase
      .from('tenants')
      .select('package_id')
      .eq('id', ctx.tenantId)
      .maybeSingle();

    // Mock limits based on tier package
    const packageId = tenant?.package_id || 'standard';
    const limits = packageId === 'enterprise'
      ? { maxPages: 100, maxProducts: 5000 }
      : packageId === 'growth'
        ? { maxPages: 25, maxProducts: 500 }
        : { maxPages: 5, maxProducts: 50 }; // standard/free fallback

    const { count: pagesCount } = await supabase
      .from('pages')
      .select('*', { count: 'exact', head: true })
      .eq('store_id', ctx.storeId);

    const { count: productsCount } = await supabase
      .from('products')
      .select('*', { count: 'exact', head: true })
      .eq('store_id', ctx.storeId);

    return {
      packageId,
      usage: {
        pages: {
          current: pagesCount || 0,
          limit: limits.maxPages
        },
        products: {
          current: productsCount || 0,
          limit: limits.maxProducts
        }
      }
    };
  }
}

import { getServiceSupabase } from '@/lib/supabase';
import { CustomerContext } from './CustomerContext';

export interface StoreSettings {
  name?: string;
  logoUrl?: string;
  branding?: {
    primaryColor?: string;
    secondaryColor?: string;
    font?: string;
    description?: string;
  };
  domain?: string;
  seo?: {
    titleTemplate?: string;
    metaDescription?: string;
    ogImage?: string;
  };
}

export interface StoreSettingsService {
  getSettings(ctx: CustomerContext): Promise<StoreSettings>;
  updateSettings(ctx: CustomerContext, settings: StoreSettings): Promise<StoreSettings>;
}

export class DefaultStoreSettingsService implements StoreSettingsService {
  private checkAccess(ctx: CustomerContext) {
    if (!ctx.tenantId || !ctx.storeId) {
      throw new Error('Unauthorized: Invalid customer context');
    }
  }

  async getSettings(ctx: CustomerContext): Promise<StoreSettings> {
    this.checkAccess(ctx);
    const supabase = getServiceSupabase();

    const { data: store, error } = await supabase
      .from('stores')
      .select('name, domain, config')
      .eq('id', ctx.storeId)
      .eq('tenant_id', ctx.tenantId)
      .maybeSingle();

    if (error || !store) {
      throw new Error(`Failed to retrieve store settings: ${error?.message || ''}`);
    }

    const config = store.config || {};

    return {
      name: store.name,
      domain: store.domain || undefined,
      logoUrl: config.logoUrl || undefined,
      branding: config.branding || undefined,
      seo: config.seo || undefined,
    };
  }

  async updateSettings(ctx: CustomerContext, settings: StoreSettings): Promise<StoreSettings> {
    this.checkAccess(ctx);
    const supabase = getServiceSupabase();

    // 1. Fetch current config to merge
    const { data: store, error: fetchErr } = await supabase
      .from('stores')
      .select('name, domain, config')
      .eq('id', ctx.storeId)
      .eq('tenant_id', ctx.tenantId)
      .maybeSingle();

    if (fetchErr || !store) {
      throw new Error(`Store not found or access denied: ${fetchErr?.message || ''}`);
    }

    const currentConfig = store.config || {};

    // 2. Prepare updated config
    const updatedConfig = {
      ...currentConfig,
    };

    if (settings.logoUrl !== undefined) updatedConfig.logoUrl = settings.logoUrl;
    if (settings.branding !== undefined) {
      updatedConfig.branding = {
        ...(currentConfig.branding || {}),
        ...settings.branding,
      };
    }
    if (settings.seo !== undefined) {
      updatedConfig.seo = {
        ...(currentConfig.seo || {}),
        ...settings.seo,
      };
    }

    // 3. Update store row
    const updateData: Record<string, any> = {
      config: updatedConfig,
      updated_at: new Date().toISOString(),
    };

    if (settings.name !== undefined) updateData.name = settings.name;
    if (settings.domain !== undefined) updateData.domain = settings.domain;

    const { error: updateErr } = await supabase
      .from('stores')
      .update(updateData)
      .eq('id', ctx.storeId)
      .eq('tenant_id', ctx.tenantId);

    if (updateErr) {
      throw new Error(`Failed to update store settings: ${updateErr.message}`);
    }

    return {
      name: settings.name ?? store.name,
      domain: settings.domain ?? store.domain ?? undefined,
      logoUrl: updatedConfig.logoUrl,
      branding: updatedConfig.branding,
      seo: updatedConfig.seo,
    };
  }
}

