import { Metric, MetricType, HealthCheck, TraceContext } from './ObservabilityDomain';

export class MetricsEngine {
  private metrics: Map<string, Metric[]> = new Map();

  record(type: MetricType, value: number, labels: Record<string, string> = {}): void {
    const metric: Metric = {
      id: `metric-${Date.now()}`,
      type,
      value,
      labels,
      timestamp: new Date().toISOString()
    };

    const existing = this.metrics.get(type) || [];
    existing.push(metric);
    this.metrics.set(type, existing);
  }

  getMetrics(type: MetricType, since?: string): Metric[] {
    const all = this.metrics.get(type) || [];
    return since ? all.filter(m => m.timestamp >= since) : all;
  }

  getSummary(type: MetricType): { avg: number; min: number; max: number; count: number } {
    const metrics = this.getMetrics(type);
    if (metrics.length === 0) return { avg: 0, min: 0, max: 0, count: 0 };

    const values = metrics.map(m => m.value);
    return {
      avg: values.reduce((a, b) => a + b, 0) / values.length,
      min: Math.min(...values),
      max: Math.max(...values),
      count: values.length
    };
  }
}

import { MarketplaceInstaller } from './MarketplaceInstaller';
import { InstallationPlan } from './InstallationPlan';
import { PackageRegistry } from '../PackageRegistry';
import { DependencyValidator } from './DependencyValidator';
import { CompatibilityValidator } from './CompatibilityValidator';

export class DefaultMarketplaceInstaller implements MarketplaceInstaller {
  private readonly installedStores = new Set<string>();

  constructor(private readonly registry: PackageRegistry) {}

  async createInstallationPlan(packageIds: ReadonlyArray<string>, coreVersion: string): Promise<InstallationPlan> {
    const steps: { packageId: string; manifest: any; content: Uint8Array }[] = [];
    const resolvedManifests: any[] = [];

    // Resolve all requested packages and their dependencies recursively
    const queue = [...packageIds];
    const visited = new Set<string>();

    while (queue.length > 0) {
      const id = queue.shift()!;
      if (visited.has(id)) {
        continue;
      }
      visited.add(id);

      const entry = await this.registry.getPackage(id, 'latest');
      if (!entry) {
        throw new Error(`Package '${id}' not found in registry`);
      }

      // Check compatibility
      const compat = CompatibilityValidator.validate(entry.manifest, {
        coreVersion,
        platformVersion: '1.0.0'
      });
      if (!compat.compatible) {
        throw new Error(`Package '${id}' is incompatible: ${compat.reasons.join(', ')}`);
      }

      resolvedManifests.push(entry.manifest);
      steps.push({
        packageId: id,
        manifest: entry.manifest,
        content: entry.content
      });

      // Add dependencies to queue
      for (const depId of Object.keys(entry.manifest.dependencies)) {
        if (!visited.has(depId)) {
          queue.push(depId);
        }
      }
    }

    // Validate the complete dependency graph
    const depValidator = new DependencyValidator(this.registry);
    const report = await depValidator.validate(resolvedManifests);
    if (!report.valid) {
      throw new Error(`Dependency validation failed: ${report.errors.join(', ')}`);
    }

    // Determine unique capabilities
    const capabilities = Array.from(
      new Set(resolvedManifests.flatMap(m => m.capabilities))
    );

    return {
      steps,
      capabilities,
      warnings: [],
      migrationRequired: false
    };
  }

  async install(plan: InstallationPlan, tenantId: string, storeId: string): Promise<void> {
    const key = `${tenantId}:${storeId}`;
    if (this.installedStores.has(key)) {
      // Simulate idempotent skip or update
      return;
    }
    this.installedStores.add(key);
  }

  async rollback(plan: InstallationPlan, tenantId: string, storeId: string): Promise<void> {
    const key = `${tenantId}:${storeId}`;
    this.installedStores.delete(key);
  }

  isInstalled(tenantId: string, storeId: string): boolean {
    return this.installedStores.has(`${tenantId}:${storeId}`);
  }
}

import { PackageManifest } from '../PackageManifest';
import { MigrationStep, MigrationEngine } from './MigrationEngine';

export interface UpgradePlan {
  readonly packageId: string;
  readonly fromVersion: string;
  readonly toVersion: string;
  readonly updateAvailable: boolean;
  readonly isBreaking: boolean;
  readonly migrationRequired: boolean;
  readonly migrations: ReadonlyArray<MigrationStep>;
  readonly warnings: ReadonlyArray<string>;
}

export class UpgradePlanner {
  static planUpgrade(
    installed: PackageManifest,
    target: PackageManifest,
    coreVersion: string
  ): UpgradePlan {
    const fromVersion = installed.version;
    const toVersion = target.version;

    const updateAvailable = fromVersion !== toVersion;

    // Breaking check
    const [instMajor] = fromVersion.replace(/^v/, '').split('.').map(Number);
    const [tarMajor] = toVersion.replace(/^v/, '').split('.').map(Number);
    const isBreaking = tarMajor > instMajor;

    const migrations = MigrationEngine.getMigrationSteps(installed, target);
    const warnings: string[] = [];

    if (target.deprecated) {
      warnings.push(
        `Package '${target.id}' is deprecated since ${target.deprecatedSince || 'unknown'}.` +
        (target.replacement ? ` Use '${target.replacement}' instead.` : '')
      );
    }

    return {
      packageId: installed.id,
      fromVersion,
      toVersion,
      updateAvailable,
      isBreaking,
      migrationRequired: migrations.length > 0 || isBreaking,
      migrations,
      warnings
    };
  }
}

import { PlatformState, BootstrapContext } from '../types';
import { ConfigurationManager } from '../config/PlatformConfig';
import { ConsolePlatformLogger } from '../logger/Logger';
import { PlatformEventBusImpl } from '../events/PlatformEventBus';
import { DiagnosticsRegistry } from '../diagnostics/DiagnosticsRegistry';
import { TenantResolver, TenantDatabaseProvider, TenantContext } from '../tenant';
import { TenantResolutionError } from '../errors/PlatformError';

/**
 * Platform is the central orchestrator responsible for initialization
 * and cycle management of the platform engine.
 */
export class Platform {
  private state: PlatformState = 'CREATED';
  private readonly startTime: number;
  private readonly initializedModules: string[] = [];
  private eventBus: PlatformEventBusImpl | null = null;
  private logger: ConsolePlatformLogger | null = null;
  private readonly diagnostics: DiagnosticsRegistry;

  constructor() {
    this.startTime = Date.now();
    this.diagnostics = new DiagnosticsRegistry();
  }

  public getState(): PlatformState {
    return this.state;
  }

  public getEventBus(): PlatformEventBusImpl {
    if (!this.eventBus) {
      throw new Error('EventBus is not initialized. Run bootstrap first.');
    }
    return this.eventBus;
  }

  public getLogger(): ConsolePlatformLogger {
    if (!this.logger) {
      throw new Error('Logger is not initialized. Run bootstrap first.');
    }
    return this.logger;
  }

  public getDiagnostics(): DiagnosticsRegistry {
    return this.diagnostics;
  }

  /**
   * Triggers the platform bootstrapper sequence.
   */
  public async bootstrap(): Promise<BootstrapContext> {
    this.state = 'INITIALIZING';
    const errors: Array<{ module: string; message: string; timestamp: string }> = [];
    const correlationId = `boot_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;

    try {
      // 1. Configuration loading
      const configMgr = ConfigurationManager.getInstance();
      const config = configMgr.get();
      this.initializedModules.push('Configuration');

      // 2. Logger initialization
      this.logger = new ConsolePlatformLogger();
      this.initializedModules.push('Logger');

      // 3. Event Bus startup
      this.eventBus = new PlatformEventBusImpl(this.logger);
      this.logger.setEventBus(this.eventBus);
      this.initializedModules.push('EventBus');

      // Emit Bootstrap.Started
      await this.eventBus.publish({
        eventId: `evt_boot_start_${Math.random().toString(36).substr(2, 9)}`,
        eventType: 'Bootstrap.Started',
        timestamp: new Date().toISOString(),
        correlationId,
        payload: { environment: config.environment, version: config.version },
      });

      // Emit ModuleInitialized events
      for (const mod of ['Configuration', 'Logger', 'EventBus']) {
        await this.eventBus.publish({
          eventId: `evt_mod_${mod.toLowerCase()}_${Math.random().toString(36).substr(2, 9)}`,
          eventType: 'Bootstrap.ModuleInitialized',
          timestamp: new Date().toISOString(),
          correlationId,
          payload: { moduleName: mod },
        });
      }

      // 4. Diagnostics setup
      this.initializedModules.push('Diagnostics');

      // Register standard diagnostic health checks
      this.diagnostics.register({
        name: 'EventBus',
        check: async () => ({ status: 'READY', timestamp: new Date().toISOString() }),
      });
      this.diagnostics.register({
        name: 'Logger',
        check: async () => ({ status: 'READY', timestamp: new Date().toISOString() }),
      });

      await this.eventBus.publish({
        eventId: `evt_mod_diag_${Math.random().toString(36).substr(2, 9)}`,
        eventType: 'Bootstrap.ModuleInitialized',
        timestamp: new Date().toISOString(),
        correlationId,
        payload: { moduleName: 'Diagnostics' },
      });

      // 5. Self-Check (Health check evaluation)
      const health = await this.diagnostics.evaluate();
      if (health.status === 'FAILED') {
        this.state = 'FAILED';
      } else if (health.status === 'DEGRADED') {
        this.state = 'DEGRADED';
      } else {
        this.state = 'READY';
      }

      const bootstrapTimeMs = Date.now() - this.startTime;

      if (this.state === 'READY') {
        await this.eventBus.publish({
          eventId: `evt_boot_ready_${Math.random().toString(36).substr(2, 9)}`,
          eventType: 'Bootstrap.Ready',
          timestamp: new Date().toISOString(),
          correlationId,
          payload: { bootstrapTimeMs },
        });
      } else if (this.state === 'DEGRADED') {
        await this.eventBus.publish({
          eventId: `evt_boot_degraded_${Math.random().toString(36).substr(2, 9)}`,
          eventType: 'Bootstrap.Degraded',
          timestamp: new Date().toISOString(),
          correlationId,
          payload: { bootstrapTimeMs, reason: 'Non-critical health check degraded' },
        });
      } else {
        throw new Error('Self-check evaluation returned FAILED state.');
      }

      this.logger.info({
        message: `Platform bootstrap completed in ${bootstrapTimeMs}ms. Status: ${this.state}`,
        correlationId,
        metadata: { bootstrapTimeMs, state: this.state },
      });

      if (this.dbProvider) {
        this.tenantResolver = new TenantResolver({
          dbProvider: this.dbProvider,
          eventBus: this.eventBus,
          logger: this.logger,
          environment: config.environment,
        });
      }

      return {
        platformVersion: config.version,
        environment: config.environment,
        initializedModules: this.initializedModules,
        healthStatus: this.state,
        bootstrapTimeMs,
        errors,
      };

    } catch (err: any) {
      this.state = 'FAILED';
      const errorMessage = err instanceof Error ? err.message : 'Unknown bootstrap error';
      errors.push({ module: 'BOOTSTRAP', message: errorMessage, timestamp: new Date().toISOString() });

      console.error(`❌ PLATFORM BOOTSTRAP FAILED: ${errorMessage}`);

      if (this.eventBus) {
        this.eventBus.publish({
          eventId: `evt_boot_failed_${Math.random().toString(36).substr(2, 9)}`,
          eventType: 'Bootstrap.Failed',
          timestamp: new Date().toISOString(),
          correlationId,
          payload: { error: errorMessage },
        }).catch(() => {});
      }

      throw err;
    }
  }

  private dbProvider: TenantDatabaseProvider | null = null;
  private tenantResolver: TenantResolver | null = null;

  public setDatabaseProvider(dbProvider: TenantDatabaseProvider): void {
    this.dbProvider = dbProvider;
    if (this.logger && this.eventBus) {
      this.tenantResolver = new TenantResolver({
        dbProvider,
        eventBus: this.eventBus,
        logger: this.logger,
        environment: ConfigurationManager.getInstance().get().environment,
      });
    }
  }

  public getTenantResolver(): TenantResolver {
    if (!this.tenantResolver) {
      throw new Error('TenantResolver is not initialized. Call setDatabaseProvider first.');
    }
    return this.tenantResolver;
  }

  public async handleRequest(req: { headers: Record<string, string>; url?: string }, res: any): Promise<void> {
    const startTime = Date.now();
    const correlationId = req.headers['x-correlation-id'] || req.headers['X-Correlation-Id'] || `req_${Date.now()}`;
    res.setHeader('X-Correlation-Id', correlationId);

    try {
      if (!this.tenantResolver) {
        throw new Error('TenantResolver is not configured. Set DatabaseProvider first.');
      }

      // Step 1: Detect cross-tenant attempt
      let tokenTenantId: string | null = null;
      const authHeader = req.headers['authorization'] || req.headers['Authorization'];
      if (authHeader && authHeader.toLowerCase().startsWith('bearer ')) {
        const token = authHeader.substring(7);
        tokenTenantId = this.extractTenantIdFromJwt(token);
      }

      const host = req.headers['host'] || req.headers['Host'];
      let hostTenant: TenantContext | null = null;
      if (host && this.dbProvider) {
        const cleanHost = host.split(':')[0].toLowerCase();
        if (cleanHost.endsWith('.webfactor.com') || cleanHost.endsWith('.webfactor.io')) {
          const parts = cleanHost.split('.');
          if (parts.length > 2) {
            hostTenant = await this.dbProvider.findBySlug(parts[0]);
          }
        } else {
          hostTenant = await this.dbProvider.findByDomain(cleanHost);
        }
      }

      // If we got a token and we have a host, verify they match
      if (tokenTenantId && hostTenant && tokenTenantId !== hostTenant.tenantId) {
        res.statusCode = 403;
        res.setHeader('X-Tenant-Id', hostTenant.tenantId);
        res.end('Forbidden: Cross-tenant access attempt');
        return;
      }

      // Step 2: Proceed with standard resolution pipeline
      const tenantContext = await this.tenantResolver.resolve(req);

      res.statusCode = 200;
      res.setHeader('X-Tenant-Id', tenantContext.tenantId);
      res.setHeader('Cache-Control', `public, max-age=${tenantContext.metadata.ttlSeconds || 300}`);

      const executionTime = Date.now() - startTime;
      res.setHeader('X-Execution-Time-Ms', String(executionTime));
      res.end(JSON.stringify({ status: 'success', tenantId: tenantContext.tenantId }));
    } catch (err: any) {
      const executionTime = Date.now() - startTime;
      res.setHeader('X-Execution-Time-Ms', String(executionTime));

      if (err instanceof TenantResolutionError) {
        if (err.code === 'TENANT_NOT_FOUND') {
          res.statusCode = 404;
          res.end(JSON.stringify({ error: 'Tenant not found' }));
          return;
        }
        if (err.code === 'TENANT_SUSPENDED') {
          res.statusCode = 403;
          res.end(JSON.stringify({ error: 'Tenant suspended' }));
          return;
        }
      }

      res.statusCode = 500;
      res.end(JSON.stringify({ error: 'Internal Server Error', message: err.message }));
    }
  }

  private extractTenantIdFromJwt(token: string): string | null {
    try {
      const parts = token.split('.');
      if (parts.length !== 3) {
        return null;
      }
      const payloadBase64 = parts[1].replace(/-/g, '+').replace(/_/g, '/');
      const decodedPayload = typeof atob === 'function' 
        ? atob(payloadBase64) 
        : Buffer.from(payloadBase64, 'base64').toString('utf8');
      const payload = JSON.parse(decodedPayload);
      return payload.tenantId || null;
    } catch {
      return null;
    }
  }
}

import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';
import { Platform } from './RuntimeBootstrap';
import { ConfigurationManager } from '../config/PlatformConfig';
import { PlatformEvent } from '../events/PlatformEvent';
import { PlatformEventBusImpl } from '../events/PlatformEventBus';

describe('Platform Runtime Bootstrap', () => {
  let originalEnv: string | undefined;

  beforeEach(() => {
    originalEnv = process.env.NODE_ENV;
    (process.env as any).NODE_ENV = 'development';
    ConfigurationManager.resetInstanceForTesting();
  });

  afterEach(() => {
    (process.env as any).NODE_ENV = originalEnv;
    ConfigurationManager.resetInstanceForTesting();
    vi.restoreAllMocks();
  });

  it('Should successfully boot all core modules and enter READY state within performance budget', async () => {
    const platform = new Platform();

    expect(platform.getState()).toBe('CREATED');

    const context = await platform.bootstrap();

    expect(context.healthStatus).toBe('READY');
    expect(context.initializedModules).toContain('Configuration');
    expect(context.initializedModules).toContain('Logger');
    expect(context.initializedModules).toContain('EventBus');
    expect(context.initializedModules).toContain('Diagnostics');
    expect(context.bootstrapTimeMs).toBeGreaterThanOrEqual(0);
    expect(context.bootstrapTimeMs).toBeLessThanOrEqual(50); // SLA budget check
    expect(context.errors).toHaveLength(0);

    expect(platform.getState()).toBe('READY');
  });

  it('Should transition to FAILED state if configuration validation fails', async () => {
    (process.env as any).NODE_ENV = 'invalid_env'; // Invalid enum value for Zod schema

    // Prevent console.error clutter in test output
    vi.spyOn(console, 'error').mockImplementation(() => {});

    const platform = new Platform();

    await expect(platform.bootstrap()).rejects.toThrow();
    expect(platform.getState()).toBe('FAILED');
  });

  it('Should transition to DEGRADED state if a non-critical check is DEGRADED', async () => {
    const platform = new Platform();

    // Register degraded check before boot
    platform.getDiagnostics().register({
      name: 'NonCriticalTelemetry',
      check: async () => ({
        status: 'DEGRADED',
        message: 'High response latency',
        timestamp: new Date().toISOString(),
      }),
    });

    const context = await platform.bootstrap();

    expect(context.healthStatus).toBe('DEGRADED');
    expect(platform.getState()).toBe('DEGRADED');
  });

  it('Should transition to FAILED state if a check is FAILED', async () => {
    const platform = new Platform();

    // Register failed check before boot
    platform.getDiagnostics().register({
      name: 'CriticalDatabaseClient',
      check: async () => ({
        status: 'FAILED',
        message: 'Database connection failed',
        timestamp: new Date().toISOString(),
      }),
    });

    await expect(platform.bootstrap()).rejects.toThrow();
    expect(platform.getState()).toBe('FAILED');
  });

  it('Should emit all bootstrap lifecycle events in correct sequence', async () => {
    // Intercept all events published during bootstrap
    const publishedEvents: PlatformEvent[] = [];
    const originalPublish = PlatformEventBusImpl.prototype.publish;

    vi.spyOn(PlatformEventBusImpl.prototype, 'publish').mockImplementation(async function(this: any, event: PlatformEvent) {
      publishedEvents.push(event);
      return originalPublish.call(this, event);
    });

    const platform = new Platform();
    await platform.bootstrap();

    // Filter out log events since logger writes to EventBus on execution completion
    const lifecycleEvents = publishedEvents.filter(e => e.eventType !== 'System.LogCreated');

    // Verify events were emitted
    expect(lifecycleEvents.length).toBeGreaterThanOrEqual(5);

    // First event should be Bootstrap.Started
    expect(lifecycleEvents[0].eventType).toBe('Bootstrap.Started');

    // Middle events should be ModuleInitialized for Configuration, Logger, EventBus
    const initializedModules = lifecycleEvents
      .filter(e => e.eventType === 'Bootstrap.ModuleInitialized')
      .map(e => e.payload.moduleName);

    expect(initializedModules).toContain('Configuration');
    expect(initializedModules).toContain('Logger');
    expect(initializedModules).toContain('EventBus');
    expect(initializedModules).toContain('Diagnostics');

    // Final event should be Bootstrap.Ready
    const lastEvent = lifecycleEvents[lifecycleEvents.length - 1];
    expect(lastEvent.eventType).toBe('Bootstrap.Ready');
    expect(lastEvent.payload.bootstrapTimeMs).toBeGreaterThanOrEqual(0);
  });
});

import { z } from 'zod';

/**
 * Zod schema for platform-wide configurations.
 * Enforces runtime types, presence, and formats of crucial settings.
 */
export const PlatformConfigSchema = z.object({
  environment: z.enum(['development', 'staging', 'production']),
  version: z.string().regex(/^\d+\.\d+\.\d+$/),
  buildId: z.string().min(1),
  features: z.object({
    enableImpersonationAudit: z.boolean().default(true),
    enableMultiRegionTelemetry: z.boolean().default(false),
  }),
  limits: z.object({
    maxRequestExecutionMs: z.number().int().positive().default(5000),
    defaultCacheTtlSeconds: z.number().int().nonnegative().default(300),
  }),
});

export type PlatformConfig = z.infer<typeof PlatformConfigSchema>;

/**
 * ConfigurationManager loads environment variables, validates them against PlatformConfigSchema,
 * and exposes an immutable PlatformConfig snapshot.
 */
export class ConfigurationManager {
  private static instance: ConfigurationManager;
  private readonly config: PlatformConfig;

  private constructor() {
    const rawConfig = {
      environment: process.env.NODE_ENV || 'development',
      version: process.env.NEXT_PUBLIC_APP_VERSION || '1.0.0',
      buildId: process.env.NEXT_PUBLIC_BUILD_ID || 'dev-build',
      features: {
        enableImpersonationAudit: process.env.ENABLE_IMPERSONATION_AUDIT === 'true',
        enableMultiRegionTelemetry: process.env.ENABLE_MULTI_REGION_TELEMETRY === 'true',
      },
      limits: {
        maxRequestExecutionMs: process.env.MAX_REQUEST_EXECUTION_MS 
          ? parseInt(process.env.MAX_REQUEST_EXECUTION_MS, 10) 
          : 5000,
        defaultCacheTtlSeconds: process.env.DEFAULT_CACHE_TTL_SECONDS 
          ? parseInt(process.env.DEFAULT_CACHE_TTL_SECONDS, 10) 
          : 300,
      },
    };

    const parsed = PlatformConfigSchema.safeParse(rawConfig);
    if (!parsed.success) {
      console.error('❌ Krytyczny błąd walidacji konfiguracji platformy:', parsed.error.format());
      throw new Error('Platform configuration validation failed.');
    }

    // Freeze the object recursively to prevent runtime modifications (Architecture Core DNA Rule)
    this.config = this.deepFreeze(parsed.data);
  }

  /**
   * Returns the singleton instance of ConfigurationManager.
   */
  public static getInstance(): ConfigurationManager {
    if (!ConfigurationManager.instance) {
      ConfigurationManager.instance = new ConfigurationManager();
    }
    return ConfigurationManager.instance;
  }

  /**
   * Resets the singleton instance for testing purposes.
   */
  public static resetInstanceForTesting(): void {
    ConfigurationManager.instance = undefined as any;
  }

  /**
   * Retrieves the immutable platform configuration object.
   */
  public get(): PlatformConfig {
    return this.config;
  }

  /**
   * Recursively freezes an object to ensure complete immutability.
   */
  private deepFreeze<T extends Record<string, any>>(obj: T): T {
    Object.freeze(obj);
    Object.getOwnPropertyNames(obj).forEach((prop) => {
      if (
        obj.hasOwnProperty(prop) &&
        obj[prop] !== null &&
        (typeof obj[prop] === 'object' || typeof obj[prop] === 'function') &&
        !Object.isFrozen(obj[prop])
      ) {
        this.deepFreeze(obj[prop]);
      }
    });
    return obj;
  }
}

import { HealthCheck, HealthResult, HealthStatus, AggregatedHealthResult } from '../types';

/**
 * DiagnosticsRegistry is responsible for managing diagnostic checks of critical
 * system modules and aggregates their status into a single platform health profile.
 */
export class DiagnosticsRegistry {
  private readonly checks = new Map<string, HealthCheck>();

  /**
   * Registers a component health check.
   */
  public register(check: HealthCheck): void {
    if (this.checks.has(check.name)) {
      throw new Error(`Health check with name "${check.name}" is already registered.`);
    }
    this.checks.set(check.name, check);
  }

  /**
   * Returns all registered health checks.
   */
  public getChecks(): HealthCheck[] {
    return Array.from(this.checks.values());
  }

  /**
   * Evaluates status for all components and aggregates them into a final health score.
   * Enforces a Diagnostic Timeout Policy (default 1000ms) to prevent hanging checks.
   */
  public async evaluate(timeoutMs = 1000): Promise<AggregatedHealthResult> {
    const components: Record<string, HealthResult> = {};
    let overallStatus: HealthStatus = 'READY';

    for (const [name, check] of this.checks.entries()) {
      try {
        const result = await this.checkWithTimeout(check, timeoutMs);
        components[name] = result;

        if (result.status === 'FAILED') {
          overallStatus = 'FAILED';
        } else if (result.status === 'DEGRADED' && overallStatus !== 'FAILED') {
          overallStatus = 'DEGRADED';
        }
      } catch (err: any) {
        // Exception safety: convert thrown error or timeout into a FAILED check
        const failedResult: HealthResult = {
          status: 'FAILED',
          message: err instanceof Error ? err.message : String(err),
          timestamp: new Date().toISOString(),
        };
        components[name] = failedResult;
        overallStatus = 'FAILED';
      }
    }

    return {
      status: overallStatus,
      timestamp: new Date().toISOString(),
      components,
    };
  }

  private checkWithTimeout(check: HealthCheck, timeoutMs: number): Promise<HealthResult> {
    let timerId: any;
    const timeoutPromise = new Promise<HealthResult>((_, reject) => {
      timerId = setTimeout(() => {
        reject(new Error(`Health check timed out after ${timeoutMs}ms`));
      }, timeoutMs);
    });

    const executionPromise = Promise.resolve(check.check()).then((result) => {
      clearTimeout(timerId);
      return result;
    });

    return Promise.race([executionPromise, timeoutPromise]);
  }
}

import { describe, it, expect, vi, beforeEach } from 'vitest';
import { DiagnosticsRegistry } from './DiagnosticsRegistry';
import { HealthCheck, HealthResult } from '../types';

describe('DiagnosticsRegistry', () => {
  let registry: DiagnosticsRegistry;

  beforeEach(() => {
    registry = new DiagnosticsRegistry();
  });

  it('Should successfully register health checks and prevent duplicate registration names', () => {
    const check1: HealthCheck = {
      name: 'Logger',
      check: async () => ({ status: 'READY', timestamp: new Date().toISOString() }),
    };

    registry.register(check1);
    expect(registry.getChecks().length).toBe(1);

    expect(() => {
      registry.register(check1);
    }).toThrow('already registered');
  });

  it('Should aggregate to READY when all components are healthy', async () => {
    registry.register({
      name: 'Logger',
      check: async () => ({ status: 'READY', timestamp: new Date().toISOString() }),
    });

    registry.register({
      name: 'EventBus',
      check: async () => ({ status: 'READY', timestamp: new Date().toISOString() }),
    });

    const report = await registry.evaluate();
    expect(report.status).toBe('READY');
    expect(report.components['Logger'].status).toBe('READY');
    expect(report.components['EventBus'].status).toBe('READY');
  });

  it('Should aggregate to DEGRADED when at least one component is degraded and none is failed', async () => {
    registry.register({
      name: 'Database',
      check: async () => ({
        status: 'DEGRADED',
        message: 'High latency detected',
        timestamp: new Date().toISOString(),
      }),
    });

    registry.register({
      name: 'EventBus',
      check: async () => ({ status: 'READY', timestamp: new Date().toISOString() }),
    });

    const report = await registry.evaluate();
    expect(report.status).toBe('DEGRADED');
    expect(report.components['Database'].status).toBe('DEGRADED');
    expect(report.components['EventBus'].status).toBe('READY');
  });

  it('Should aggregate to FAILED when at least one component is failed', async () => {
    registry.register({
      name: 'Database',
      check: async () => ({
        status: 'FAILED',
        message: 'Database unreachable',
        timestamp: new Date().toISOString(),
      }),
    });

    registry.register({
      name: 'Logger',
      check: async () => ({ status: 'READY', timestamp: new Date().toISOString() }),
    });

    registry.register({
      name: 'TenantResolver',
      check: async () => ({ status: 'DEGRADED', timestamp: new Date().toISOString() }),
    });

    const report = await registry.evaluate();
    expect(report.status).toBe('FAILED');
    expect(report.components['Database'].status).toBe('FAILED');
    expect(report.components['Logger'].status).toBe('READY');
    expect(report.components['TenantResolver'].status).toBe('DEGRADED');
  });

  it('Should safely catch exceptions within check functions and mark as FAILED', async () => {
    registry.register({
      name: 'CrashComponent',
      check: async () => {
        throw new Error('Connection timeout');
      },
    });

    registry.register({
      name: 'Logger',
      check: async () => ({ status: 'READY', timestamp: new Date().toISOString() }),
    });

    const report = await registry.evaluate();
    expect(report.status).toBe('FAILED');
    expect(report.components['CrashComponent'].status).toBe('FAILED');
    expect(report.components['CrashComponent'].message).toBe('Connection timeout');
  });

  it('Should trigger timeout policy and mark check as FAILED if execution is too slow', async () => {
    registry.register({
      name: 'SlowDatabaseCheck',
      check: () => new Promise<HealthResult>((resolve) => {
        // Slow resolve exceeding evaluation timeout (10ms)
        setTimeout(() => {
          resolve({ status: 'READY', timestamp: new Date().toISOString() });
        }, 100);
      }),
    });

    // Run evaluation with a strict 10ms timeout
    const report = await registry.evaluate(10);

    expect(report.status).toBe('FAILED');
    expect(report.components['SlowDatabaseCheck'].status).toBe('FAILED');
    expect(report.components['SlowDatabaseCheck'].message).toContain('timed out');
  });
});

import { PlatformErrorOptions, ErrorSeverity } from '../types';

/**
 * Base error class for all platform and domain specific errors.
 * Extends JS Error to carry telemetry, severity levels, and execution contexts.
 */
export class PlatformError extends Error {
  public readonly code: string;
  public readonly severity: ErrorSeverity;
  public readonly module: string;
  public readonly correlationId?: string;
  public readonly causationId?: string;
  public readonly tenantId?: string;
  public readonly metadata?: Record<string, any>;

  constructor(options: PlatformErrorOptions) {
    super(options.message);

    this.name = this.constructor.name;
    this.code = options.code;
    this.severity = options.severity;
    this.module = options.module;
    this.correlationId = options.correlationId;
    this.causationId = options.causationId;
    this.tenantId = options.tenantId;

    if (options.metadata) {
      this.metadata = this.deepFreeze({ ...options.metadata });
    }

    if (Error.captureStackTrace) {
      Error.captureStackTrace(this, this.constructor);
    }
  }

  /**
   * Serializes the error to a clean JSON telemetry payload.
   */
  public toJSON(): Record<string, any> {
    return {
      name: this.name,
      message: this.message,
      code: this.code,
      severity: this.severity,
      module: this.module,
      correlationId: this.correlationId,
      causationId: this.causationId,
      tenantId: this.tenantId,
      metadata: this.metadata,
      stack: this.stack,
    };
  }

  private deepFreeze<T extends Record<string, any>>(obj: T): T {
    Object.freeze(obj);
    Object.getOwnPropertyNames(obj).forEach((prop) => {
      if (
        obj.hasOwnProperty(prop) &&
        obj[prop] !== null &&
        (typeof obj[prop] === 'object' || typeof obj[prop] === 'function') &&
        !Object.isFrozen(obj[prop])
      ) {
        this.deepFreeze(obj[prop]);
      }
    });
    return obj;
  }
}

/**
 * Thrown when configuration variables fail parsing or are missing.
 */
export class ConfigurationError extends PlatformError {
  constructor(message: string, correlationId?: string, metadata?: Record<string, any>) {
    super({
      message,
      code: 'CONFIG_VALIDATION_FAILED',
      severity: 'FATAL',
      module: 'CONFIGURATION',
      correlationId,
      metadata,
    });
  }
}

/**
 * Thrown for runtime execution failures within composition and rendering engines.
 */
export class RuntimeError extends PlatformError {
  constructor(message: string, correlationId?: string, metadata?: Record<string, any>) {
    super({
      message,
      code: 'RUNTIME_EXECUTION_FAILED',
      severity: 'HIGH',
      module: 'RUNTIME',
      correlationId,
      metadata,
    });
  }
}

/**
 * Thrown when tenant lookup fails (not found or status is suspended/maintenance).
 */
export class TenantResolutionError extends PlatformError {
  constructor(message: string, code: 'TENANT_NOT_FOUND' | 'TENANT_SUSPENDED', correlationId?: string, metadata?: Record<string, any>) {
    super({
      message,
      code,
      severity: code === 'TENANT_SUSPENDED' ? 'HIGH' : 'MEDIUM',
      module: 'TENANT_RESOLVER',
      correlationId,
      metadata,
    });
  }
}

/**
 * Thrown when store provisioning fails during dynamic sandbox setup.
 */
export class ProvisioningError extends PlatformError {
  constructor(message: string, correlationId?: string, metadata?: Record<string, any>) {
    super({
      message,
      code: 'PROVISIONING_STEP_FAILED',
      severity: 'HIGH',
      module: 'PROVISIONING_ENGINE',
      correlationId,
      metadata,
    });
  }
}

/**
 * Thrown when plugins or packages mismatch versions or fail to load.
 */
export class PackageError extends PlatformError {
  constructor(message: string, correlationId?: string, metadata?: Record<string, any>) {
    super({
      message,
      code: 'DEPENDENCY_RESOLVE_FAILED',
      severity: 'HIGH',
      module: 'PACKAGE_RUNTIME',
      correlationId,
      metadata,
    });
  }
}

/**
 * Thrown on security rule violations, token forgery, or cross-tenant access attempts.
 */
export class SecurityError extends PlatformError {
  constructor(message: string, correlationId?: string, metadata?: Record<string, any>) {
    // Sanitize metadata to avoid leaking raw secret keys / tokens in telemetry logs
    const sanitizedMetadata = metadata ? { ...metadata } : {};
    if (sanitizedMetadata.token) delete sanitizedMetadata.token;
    if (sanitizedMetadata.secret) delete sanitizedMetadata.secret;
    if (sanitizedMetadata.password) delete sanitizedMetadata.password;

    super({
      message,
      code: 'ACCESS_DENIED',
      severity: 'FATAL',
      module: 'SECURITY',
      correlationId,
      metadata: sanitizedMetadata,
    });
  }
}

import { z } from 'zod';

export interface PlatformEvent<T = any> {
  readonly eventId: string;         // UUID / unique ID of the event
  readonly eventType: string;       // Unique event type name (e.g. "Tenant.Resolved")
  readonly timestamp: string;       // ISO 8601 string
  readonly correlationId: string;   // Trace request identifier
  readonly causationId?: string;    // Direct trigger event identifier
  readonly tenantId?: string;       // Tenant context isolation identifier
  readonly payload: T;              // Immutable structured data payload
}

export const PlatformEventSchema = z.object({
  eventId: z.string().min(1),
  eventType: z.string().min(1),
  timestamp: z.string(),
  correlationId: z.string().min(1),
  causationId: z.string().optional(),
  tenantId: z.string().optional(),
  payload: z.any(),
});

import { PlatformEvent, PlatformEventSchema } from './PlatformEvent';
import { EventRegistry } from './EventRegistry';
import { PlatformLogger } from '../types';

export type EventHandler<T = any> = (event: PlatformEvent<T>) => Promise<void> | void;

export interface SubscriptionToken {
  readonly id: string;
  readonly eventType: string;
}

interface Subscription {
  readonly id: string;
  readonly handler: EventHandler;
  readonly tenantId?: string; // If defined, isolates handler to this specific tenant
}

export interface PlatformEventBus {
  publish(event: PlatformEvent): Promise<void>;
  subscribe<T>(eventType: string, handler: EventHandler<T>, tenantId?: string): SubscriptionToken;
  unsubscribe(token: SubscriptionToken): void;
}

export class PlatformEventBusImpl implements PlatformEventBus {
  private readonly subscriptions = new Map<string, Set<Subscription>>();
  private readonly logger?: PlatformLogger;

  constructor(logger?: PlatformLogger) {
    this.logger = logger;
  }

  public async publish(event: PlatformEvent): Promise<void> {
    // 1. Zod runtime validation
    const parsed = PlatformEventSchema.safeParse(event);
    if (!parsed.success) {
      const errMsg = `Event validation failed: ${JSON.stringify(parsed.error.format())}`;
      this.logger?.error({
        message: errMsg,
        correlationId: event.correlationId,
        tenantId: event.tenantId,
      });
      throw new Error(errMsg);
    }

    // 2. EventRegistry verification
    if (!EventRegistry.isRegistered(event.eventType)) {
      this.logger?.warn({
        message: `Unregistered event type published: ${event.eventType}`,
        correlationId: event.correlationId,
        tenantId: event.tenantId,
      });
    }

    // 3. Resolve Handlers
    const eventSubscriptions = this.subscriptions.get(event.eventType) || new Set<Subscription>();
    const wildCardSubscriptions = this.subscriptions.get('*') || new Set<Subscription>();
    const subscriptionsToRun = [...eventSubscriptions, ...wildCardSubscriptions];

    if (subscriptionsToRun.length === 0) {
      return;
    }

    // 4. Asynchronous dispatching using Promise.allSettled to isolate execution
    const promises = subscriptionsToRun.map(async (sub) => {
      // Security Check: Tenant Isolation Boundary
      if (sub.tenantId && event.tenantId && sub.tenantId !== event.tenantId) {
        // Ignorowanie/blokowanie dostępu (cicha izolacja na poziomie dystrybutora)
        return;
      }

      await sub.handler(event);
    });

    const results = await Promise.allSettled(promises);

    // 5. Collect failures and emit System.ErrorOccurred event
    const failures = results.filter((res) => res.status === 'rejected') as PromiseRejectedResult[];

    if (failures.length > 0) {
      for (const fail of failures) {
        const errorMsg = fail.reason instanceof Error ? fail.reason.message : String(fail.reason);
        const stack = fail.reason instanceof Error ? fail.reason.stack : undefined;

        this.logger?.error({
          message: `Event handler failed for eventType: ${event.eventType}`,
          correlationId: event.correlationId,
          tenantId: event.tenantId,
          error: fail.reason instanceof Error ? fail.reason : new Error(errorMsg),
        });

        // Publish System.ErrorOccurred event (if we are not already handling System.ErrorOccurred)
        if (event.eventType !== 'System.ErrorOccurred') {
          this.publish({
            eventId: `evt_err_${Math.random().toString(36).substr(2, 9)}`,
            eventType: 'System.ErrorOccurred',
            timestamp: new Date().toISOString(),
            correlationId: event.correlationId,
            tenantId: event.tenantId,
            payload: {
              failedEventType: event.eventType,
              error: errorMsg,
              stack,
            },
          }).catch((err) => {
            // Safe fallback write to avoid recursive loops crashing publish
            console.error('❌ Failed to publish System.ErrorOccurred event recursively:', err);
          });
        }
      }
    }
  }

  public subscribe<T>(eventType: string, handler: EventHandler<T>, tenantId?: string): SubscriptionToken {
    const id = `sub_${Math.random().toString(36).substr(2, 9)}`;
    const subscription: Subscription = { id, handler, tenantId };

    if (!this.subscriptions.has(eventType)) {
      this.subscriptions.set(eventType, new Set<Subscription>());
    }

    this.subscriptions.get(eventType)!.add(subscription);

    return { id, eventType };
  }

  public unsubscribe(token: SubscriptionToken): void {
    const subs = this.subscriptions.get(token.eventType);
    if (!subs) return;

    for (const sub of subs) {
      if (sub.id === token.id) {
        subs.delete(sub);
        break;
      }
    }

    if (subs.size === 0) {
      this.subscriptions.delete(token.eventType);
    }
  }
}

import { describe, it, expect, vi, beforeEach } from 'vitest';
import { PlatformEventBusImpl } from './PlatformEventBus';
import { PlatformEvent } from './PlatformEvent';
import { EventRegistry } from './EventRegistry';

describe('PlatformEventBus', () => {
  let eventBus: PlatformEventBusImpl;
  let mockLogger: any;

  beforeEach(() => {
    mockLogger = {
      info: vi.fn(),
      warn: vi.fn(),
      error: vi.fn(),
      fatal: vi.fn(),
    };
    eventBus = new PlatformEventBusImpl(mockLogger);
  });

  it('Should successfully publish and subscribe to events (Pub-Sub Flow)', async () => {
    const handler = vi.fn().mockResolvedValue(undefined);

    eventBus.subscribe('Test.Created', handler);

    const event: PlatformEvent = {
      eventId: 'evt_111',
      eventType: 'Test.Created',
      timestamp: new Date().toISOString(),
      correlationId: 'req_111',
      payload: { key: 'value' },
    };

    await eventBus.publish(event);

    expect(handler).toHaveBeenCalledTimes(1);
    expect(handler).toHaveBeenCalledWith(event);
  });

  it('Should correctly unsubscribe and stop receiving events', async () => {
    const handler = vi.fn().mockResolvedValue(undefined);

    const token = eventBus.subscribe('Test.Created', handler);
    eventBus.unsubscribe(token);

    const event: PlatformEvent = {
      eventId: 'evt_222',
      eventType: 'Test.Created',
      timestamp: new Date().toISOString(),
      correlationId: 'req_222',
      payload: {},
    };

    await eventBus.publish(event);

    expect(handler).not.toHaveBeenCalled();
  });

  it('Should propagate correlationId across chained events', async () => {
    const nextEventSpy = vi.fn().mockResolvedValue(undefined);
    eventBus.subscribe('Test.Created', async (event) => {
      // Simulate chained event emission in subscriber
      await eventBus.publish({
        eventId: 'evt_chained_1',
        eventType: 'Tenant.Resolved',
        timestamp: new Date().toISOString(),
        correlationId: event.correlationId, // Propagating the Correlation ID
        causationId: event.eventId,
        payload: { tenant: 'store_abc' },
      });
    });

    eventBus.subscribe('Tenant.Resolved', nextEventSpy);

    const initialEvent: PlatformEvent = {
      eventId: 'evt_root_1',
      eventType: 'Test.Created',
      timestamp: new Date().toISOString(),
      correlationId: 'req_origin_correlation_123',
      payload: {},
    };

    await eventBus.publish(initialEvent);

    expect(nextEventSpy).toHaveBeenCalledTimes(1);
    const chainedEvent = nextEventSpy.mock.calls[0][0];
    expect(chainedEvent.correlationId).toBe('req_origin_correlation_123');
    expect(chainedEvent.causationId).toBe('evt_root_1');
  });

  it('Should isolate tenant handlers and not dispatch events across tenant boundaries', async () => {
    const tenantAHandler = vi.fn().mockResolvedValue(undefined);
    const tenantBHandler = vi.fn().mockResolvedValue(undefined);

    // Subscribe A and B to same event under different tenant limits
    eventBus.subscribe('Test.Created', tenantAHandler, 'tenant_A');
    eventBus.subscribe('Test.Created', tenantBHandler, 'tenant_B');

    const eventForA: PlatformEvent = {
      eventId: 'evt_tenant_a',
      eventType: 'Test.Created',
      timestamp: new Date().toISOString(),
      correlationId: 'req_a',
      tenantId: 'tenant_A',
      payload: {},
    };

    await eventBus.publish(eventForA);

    expect(tenantAHandler).toHaveBeenCalledTimes(1);
    expect(tenantBHandler).not.toHaveBeenCalled();
  });

  it('Should isolate handler failures and prevent crashing other handlers (Fault Isolation)', async () => {
    const goodHandler1 = vi.fn().mockResolvedValue(undefined);
    const badHandler = vi.fn().mockRejectedValue(new Error('Handler crashed'));
    const goodHandler2 = vi.fn().mockResolvedValue(undefined);

    eventBus.subscribe('Test.Created', goodHandler1);
    eventBus.subscribe('Test.Created', badHandler);
    eventBus.subscribe('Test.Created', goodHandler2);

    const event: PlatformEvent = {
      eventId: 'evt_fault_test',
      eventType: 'Test.Created',
      timestamp: new Date().toISOString(),
      correlationId: 'req_fault',
      payload: {},
    };

    await expect(eventBus.publish(event)).resolves.not.toThrow();

    expect(goodHandler1).toHaveBeenCalledTimes(1);
    expect(badHandler).toHaveBeenCalledTimes(1);
    expect(goodHandler2).toHaveBeenCalledTimes(1);

    // Check if failure triggered System.ErrorOccurred event dispatching
    expect(mockLogger.error).toHaveBeenCalled();
  });

  it('Should guarantee sequential local correlation execution order', async () => {
    const executedEvents: string[] = [];
    eventBus.subscribe('Test.Created', async (event) => {
      executedEvents.push(event.eventId);
    });

    const event1: PlatformEvent = {
      eventId: 'evt_seq_1',
      eventType: 'Test.Created',
      timestamp: new Date().toISOString(),
      correlationId: 'req_seq',
      payload: {},
    };

    const event2: PlatformEvent = {
      eventId: 'evt_seq_2',
      eventType: 'Test.Created',
      timestamp: new Date().toISOString(),
      correlationId: 'req_seq',
      payload: {},
    };

    // Publish sequentially and await execution completion
    await eventBus.publish(event1);
    await eventBus.publish(event2);

    expect(executedEvents).toEqual(['evt_seq_1', 'evt_seq_2']);
  });
});

import { PlatformLogger, LoggerPayload } from '../types';

/**
 * Concrete implementation of the PlatformLogger interface.
 * Logs structured JSON to stdout/stderr and integrates lazily with PlatformEventBus.
 */
export class ConsolePlatformLogger implements PlatformLogger {
  private eventBus: any | null = null;
  private isPublishing = false; // Guard to prevent infinite logging recursion loops

  /**
   * Inject EventBus instance lazily after both modules are initialized.
   */
  public setEventBus(eventBus: any): void {
    this.eventBus = eventBus;
  }

  public info(payload: LoggerPayload): void {
    const formatted = this.formatLog('INFO', payload);
    console.log(formatted);
    this.emitLogEvent('INFO', payload);
  }

  public warn(payload: LoggerPayload): void {
    const formatted = this.formatLog('WARN', payload);
    console.warn(formatted);
    this.emitLogEvent('WARN', payload);
  }

  public error(payload: LoggerPayload & { readonly error?: Error }): void {
    const formatted = this.formatLog('ERROR', payload, payload.error);
    console.error(formatted);
    this.emitLogEvent('ERROR', payload, payload.error);
  }

  public fatal(payload: LoggerPayload & { readonly error?: Error }): void {
    const formatted = this.formatLog('FATAL', payload, payload.error);
    console.error(formatted);
    this.emitLogEvent('FATAL', payload, payload.error);
  }

  /**
   * Formats the log payload into a standardized JSON structure.
   */
  private formatLog(
    level: 'INFO' | 'WARN' | 'ERROR' | 'FATAL',
    payload: LoggerPayload,
    error?: Error
  ): string {
    return JSON.stringify({
      timestamp: new Date().toISOString(),
      level,
      message: payload.message,
      correlationId: payload.correlationId,
      causationId: payload.causationId,
      tenantId: payload.tenantId,
      module: payload.module,
      eventType: payload.eventType,
      metadata: payload.metadata || {},
      ...(error && {
        error: {
          name: error.name,
          message: error.message,
          stack: error.stack,
        },
      }),
    });
  }

  /**
   * Publishes the telemetry event to the platform EventBus.
   */
  private emitLogEvent(
    level: 'INFO' | 'WARN' | 'ERROR' | 'FATAL',
    payload: LoggerPayload,
    error?: Error
  ): void {
    if (!this.eventBus || this.isPublishing) {
      return;
    }

    // Do not emit log events for telemetry events themselves to prevent infinite cycles
    if (payload.eventType === 'System.LogCreated') {
      return;
    }

    this.isPublishing = true;

    try {
      this.eventBus.publish({
        eventId: `evt_log_${Math.random().toString(36).substr(2, 9)}`,
        eventType: 'System.LogCreated',
        timestamp: new Date().toISOString(),
        correlationId: payload.correlationId,
        causationId: payload.causationId,
        tenantId: payload.tenantId,
        payload: {
          level,
          message: payload.message,
          module: payload.module,
          metadata: payload.metadata,
          errorName: error?.name,
          errorMessage: error?.message,
        },
      }).catch((err: any) => {
        // Safe fallback write to stderr to avoid crashing the logging pipeline
        console.error(
          JSON.stringify({
            timestamp: new Date().toISOString(),
            level: 'ERROR',
            message: 'Failed to publish System.LogCreated event',
            module: 'LOGGER',
            error: {
              message: err instanceof Error ? err.message : String(err),
            },
          })
        );
      });
    } catch (err: any) {
      // Catch synchronous errors during publish
      console.error(
        JSON.stringify({
          timestamp: new Date().toISOString(),
          level: 'ERROR',
          message: 'Synchronous error occurred during event publishing',
          module: 'LOGGER',
          error: {
            message: err instanceof Error ? err.message : String(err),
          },
        })
      );
    } finally {
      this.isPublishing = false;
    }
  }
}

import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { ConsolePlatformLogger } from './Logger';

describe('ConsolePlatformLogger', () => {
  let logger: ConsolePlatformLogger;
  let logSpy: any;
  let warnSpy: any;
  let errorSpy: any;

  beforeEach(() => {
    logger = new ConsolePlatformLogger();
    logSpy = vi.spyOn(console, 'log').mockImplementation(() => {});
    warnSpy = vi.spyOn(console, 'warn').mockImplementation(() => {});
    errorSpy = vi.spyOn(console, 'error').mockImplementation(() => {});
  });

  afterEach(() => {
    vi.restoreAllMocks();
  });

  it('Should correctly format and print INFO logs to console.log', () => {
    logger.info({
      message: 'Store resolved',
      correlationId: 'req_123',
      tenantId: 'tenant_abc',
