    });

    expect(logSpy).toHaveBeenCalledTimes(1);
    const printed = JSON.parse(logSpy.mock.calls[0][0]);

    expect(printed.level).toBe('INFO');
    expect(printed.message).toBe('Store resolved');
    expect(printed.correlationId).toBe('req_123');
    expect(printed.tenantId).toBe('tenant_abc');
    expect(printed.module).toBe('RESOLVER');
    expect(printed.timestamp).toBeDefined();
  });

  it('Should correctly print WARN logs to console.warn', () => {
    logger.warn({
      message: 'Cache miss',
      correlationId: 'req_456',
      tenantId: 'tenant_xyz',
    });

    expect(warnSpy).toHaveBeenCalledTimes(1);
    const printed = JSON.parse(warnSpy.mock.calls[0][0]);

    expect(printed.level).toBe('WARN');
    expect(printed.message).toBe('Cache miss');
    expect(printed.correlationId).toBe('req_456');
    expect(printed.tenantId).toBe('tenant_xyz');
  });

  it('Should correctly print ERROR logs and include serializable error stack', () => {
    const errorObj = new Error('Database disconnected');
    logger.error({
      message: 'Failed database call',
      correlationId: 'req_789',
      tenantId: 'tenant_err',
      error: errorObj,
    });

    expect(errorSpy).toHaveBeenCalledTimes(1);
    const printed = JSON.parse(errorSpy.mock.calls[0][0]);

    expect(printed.level).toBe('ERROR');
    expect(printed.message).toBe('Failed database call');
    expect(printed.correlationId).toBe('req_789');
    expect(printed.tenantId).toBe('tenant_err');
    expect(printed.error.name).toBe('Error');
    expect(printed.error.message).toBe('Database disconnected');
    expect(printed.error.stack).toBeDefined();
  });

  it('Should not leak cross-tenant information and isolate properties', () => {
    logger.info({
      message: 'Data check',
      tenantId: 'tenant_A',
    });

    const printed = JSON.parse(logSpy.mock.calls[0][0]);
    expect(printed.tenantId).toBe('tenant_A');
    expect(printed.tenantId).not.toBe('tenant_B');
  });

  it('Should publish System.LogCreated event if EventBus is configured', async () => {
    const mockEventBus = {
      publish: vi.fn().mockResolvedValue(undefined),
    };

    logger.setEventBus(mockEventBus);

    logger.info({
      message: 'Bootstrap done',
      correlationId: 'req_boot',
      tenantId: 'system',
    });

    expect(mockEventBus.publish).toHaveBeenCalledTimes(1);
    const event = mockEventBus.publish.mock.calls[0][0];
    expect(event.eventType).toBe('System.LogCreated');
    expect(event.correlationId).toBe('req_boot');
    expect(event.tenantId).toBe('system');
    expect(event.payload.message).toBe('Bootstrap done');
  });

  it('Should log to console and not throw if EventBus publish fails (Failure Isolation)', () => {
    const mockEventBus = {
      publish: vi.fn().mockRejectedValue(new Error('EventBus crash')),
    };

    logger.setEventBus(mockEventBus);

    // This should execute completely without throwing an exception
    expect(() => {
      logger.info({
        message: 'Resilient log',
        correlationId: 'req_resilient',
      });
    }).not.toThrow();

    // Verify stdout still has the message
    expect(logSpy).toHaveBeenCalledTimes(1);
    const printed = JSON.parse(logSpy.mock.calls[0][0]);
    expect(printed.message).toBe('Resilient log');
  });
});

import { TenantContext, TenantContextSchema } from './TenantTypes';

/**
 * TenantContextBuilder safely creates, validates, and freezes a TenantContext
 * to prevent runtime mutation and assure data integrity.
 */
export class TenantContextBuilder {
  private rawContext: Partial<TenantContext> = {
    domains: { primary: '' },
    plan: { tier: 'FREE', limits: {} },
    capabilities: [],
    metadata: { cacheKey: '', lastRefresh: '', ttlSeconds: 300 }
  };

  public setTenantId(tenantId: string): this {
    this.rawContext.tenantId = tenantId;
    return this;
  }

  public setSlug(slug: string): this {
    this.rawContext.slug = slug;
    return this;
  }

  public setStatus(status: 'ACTIVE' | 'SUSPENDED' | 'MAINTENANCE'): this {
    this.rawContext.status = status;
    return this;
  }

  public setDomains(domains: { primary: string; custom?: string }): this {
    this.rawContext.domains = domains;
    return this;
  }

  public setPlan(plan: { tier: 'FREE' | 'GROWTH' | 'ENTERPRISE'; limits: Record<string, number> }): this {
    this.rawContext.plan = plan;
    return this;
  }

  public setCapabilities(capabilities: string[]): this {
    this.rawContext.capabilities = capabilities;
    return this;
  }

  public setMetadata(metadata: { cacheKey: string; lastRefresh: string; ttlSeconds: number; locale?: string; currency?: string }): this {
    this.rawContext.metadata = metadata;
    return this;
  }

  /**
   * Validates data against the schema and freezes the object.
   */
  public build(): TenantContext {
    const parsed = TenantContextSchema.safeParse(this.rawContext);
    if (!parsed.success) {
      throw new Error(`Invalid tenant context configuration: ${JSON.stringify(parsed.error.format())}`);
    }

    return this.deepFreeze(parsed.data);
  }

  private deepFreeze<T extends Record<string, any>>(obj: T): T {
    Object.freeze(obj);
    Object.getOwnPropertyNames(obj).forEach((prop) => {
      if (
        obj.hasOwnProperty(prop) &&
        obj[prop] !== null &&
        (typeof obj[prop] === 'object' || typeof obj[prop] === 'function') &&
        !Object.isFrozen(obj[prop])
      ) {
        this.deepFreeze(obj[prop]);
      }
    });
    return obj;
  }
}

import { TenantContext } from './TenantTypes';
import { TenantCache } from './TenantCache';
import { PlatformEventBusImpl } from '../events/PlatformEventBus';
import { ConsolePlatformLogger } from '../logger/Logger';
import { TenantResolutionError, RuntimeError } from '../errors/PlatformError';

export interface TenantDatabaseProvider {
  findByTenantId(tenantId: string): Promise<TenantContext | null>;
  findByDomain(domain: string): Promise<TenantContext | null>;
  findBySlug(slug: string): Promise<TenantContext | null>;
}

export interface TenantL2Cache {
  get(key: string): Promise<{ context: TenantContext; expiresAt: number } | null>;
  set(key: string, context: TenantContext, ttlSeconds: number): Promise<void>;
  delete(key: string): Promise<void>;
}

export class TenantResolver {
  private readonly l1Cache: TenantCache;
  private readonly l2Cache?: TenantL2Cache;
  private readonly dbProvider: TenantDatabaseProvider;
  private readonly eventBus: PlatformEventBusImpl;
  private readonly logger: ConsolePlatformLogger;
  private readonly environment: 'development' | 'staging' | 'production';
  private readonly maxStaleMs: number;

  constructor(options: {
    dbProvider: TenantDatabaseProvider;
    eventBus: PlatformEventBusImpl;
    logger: ConsolePlatformLogger;
    environment?: 'development' | 'staging' | 'production';
    l2Cache?: TenantL2Cache;
    l1CacheTtlSeconds?: number;
    maxStaleSeconds?: number;
  }) {
    this.dbProvider = options.dbProvider;
    this.eventBus = options.eventBus;
    this.logger = options.logger;
    this.environment = options.environment || 'development';
    this.l2Cache = options.l2Cache;
    this.l1Cache = new TenantCache(options.l1CacheTtlSeconds || 300);
    this.maxStaleMs = (options.maxStaleSeconds || 86400) * 1000; // 1 day default max stale
  }

  public getL1Cache(): TenantCache {
    return this.l1Cache;
  }

  /**
   * Resolves a TenantContext from an incoming request using a prioritized pipeline.
   * Priority:
   * 1. Signed API Token
   * 2. Custom Domain
   * 3. Internal Preview URL
   * 4. Development Override (blocked in production/staging)
   */
  public async resolve(req: { headers: Record<string, string>; url?: string }): Promise<TenantContext> {
    const correlationId = req.headers['x-correlation-id'] || req.headers['X-Correlation-Id'] || `req_${Date.now()}`;

    // 1. Signed API Token
    let tokenTenantId: string | null = null;
    const authHeader = req.headers['authorization'] || req.headers['Authorization'];
    if (authHeader && authHeader.toLowerCase().startsWith('bearer ')) {
      const token = authHeader.substring(7);
      tokenTenantId = this.extractTenantIdFromJwt(token);
    }

    if (!tokenTenantId && req.url) {
      try {
        const urlObj = new URL(req.url, 'http://localhost');
        const apiKey = urlObj.searchParams.get('api_key');
        if (apiKey) {
          if (apiKey.includes('.')) {
            tokenTenantId = this.extractTenantIdFromJwt(apiKey);
          } else {
            tokenTenantId = apiKey;
          }
        }
      } catch {}
    }

    if (tokenTenantId) {
      return this.resolveWithCaching(
        `id:${tokenTenantId}`,
        () => this.dbProvider.findByTenantId(tokenTenantId!),
        correlationId
      );
    }

    // 2. Development Override
    const override = req.headers['x-tenant-override'] || req.headers['X-Tenant-Override'];
    if (override) {
      if (this.environment === 'development') {
        this.logger.info({
          message: `Tenant override header detected: ${override}`,
          correlationId,
        });
        return this.resolveWithCaching(
          `id:${override}`,
          () => this.dbProvider.findByTenantId(override),
          correlationId
        );
      } else {
        this.logger.warn({
          message: `Attempted X-Tenant-Override '${override}' in non-development environment '${this.environment}' blocked!`,
          correlationId,
        });
      }
    }

    // 3. Host resolution (Custom Domain or Internal Preview URL)
    const host = req.headers['host'] || req.headers['Host'];
    if (!host) {
      const errorMsg = 'Resolution failed: Missing host header';
      await this.publishFailure(correlationId, 'unknown', errorMsg);
      throw new TenantResolutionError(errorMsg, 'TENANT_NOT_FOUND', correlationId);
    }

    const cleanHost = host.split(':')[0].toLowerCase();

    // Check if preview domain
    if (cleanHost.endsWith('.webfactor.com') || cleanHost.endsWith('.webfactor.io')) {
      const parts = cleanHost.split('.');
      if (parts.length > 2) {
        const slug = parts[0];
        return this.resolveWithCaching(
          `slug:${slug}`,
          () => this.dbProvider.findBySlug(slug),
          correlationId
        );
      }
    }

    // Default to custom domain lookup
    return this.resolveWithCaching(
      `domain:${cleanHost}`,
      () => this.dbProvider.findByDomain(cleanHost),
      correlationId
    );
  }

  /**
   * Helper that orchestrates L1 Cache -> L2 Cache -> DB Lookup.
   * Handles database failure (Failover to L2 stale content vs Fail-Closed).
   */
  private async resolveWithCaching(
    lookupKey: string,
    dbFetcher: () => Promise<TenantContext | null>,
    correlationId: string
  ): Promise<TenantContext> {
    const l1Key = `tenant:${lookupKey}`;

    // A. L1 Cache lookup
    const cachedL1 = this.l1Cache.get(l1Key);
    if (cachedL1) {
      this.verifyStatus(cachedL1, correlationId);
      return cachedL1;
    }

    // B. L2 Cache lookup
    let l2Entry: { context: TenantContext; expiresAt: number } | null = null;
    if (this.l2Cache) {
      try {
        l2Entry = await this.l2Cache.get(l1Key);
        if (l2Entry) {
          const now = Date.now();
          if (now < l2Entry.expiresAt) {
            this.verifyStatus(l2Entry.context, correlationId);
            this.l1Cache.set(l1Key, l2Entry.context);
            return l2Entry.context;
          }
        }
      } catch (err: any) {
        this.logger.error({
          message: `L2 cache fetch error: ${err.message}`,
          correlationId,
        });
      }
    }

    // C. Database lookup
    try {
      const dbContext = await dbFetcher();
      if (!dbContext) {
        throw new TenantResolutionError(
          `Tenant not found for lookup: ${lookupKey}`,
          'TENANT_NOT_FOUND',
          correlationId
        );
      }

      this.verifyStatus(dbContext, correlationId);

      // Save to L1 and L2
      this.l1Cache.set(l1Key, dbContext);
      if (this.l2Cache) {
        const ttlSeconds = dbContext.metadata.ttlSeconds || 300;
        this.l2Cache.set(l1Key, dbContext, ttlSeconds).catch(() => {});
      }

      // Publish event
      this.eventBus.publish({
        eventId: `evt_resolved_${Math.random().toString(36).substr(2, 9)}`,
        eventType: 'Tenant.Resolved',
        timestamp: new Date().toISOString(),
        correlationId,
        tenantId: dbContext.tenantId,
        payload: { lookupKey, slug: dbContext.slug },
      }).catch(() => {});

      return dbContext;
    } catch (dbErr: any) {
      // D. Fallback / Failover L2 Stale logic
      if (l2Entry && !(dbErr instanceof TenantResolutionError)) {
        const now = Date.now();
        // Check if within maxStaleMs threshold
        if (now < l2Entry.expiresAt + this.maxStaleMs) {
          this.logger.warn({
            message: `Database offline. Serving stale configuration for key ${l1Key} (SWR fallback)`,
            correlationId,
          });
          this.verifyStatus(l2Entry.context, correlationId);
          this.l1Cache.set(l1Key, l2Entry.context);
          return l2Entry.context;
        }
      }

      // E. Fail-Closed
      const finalError = dbErr instanceof TenantResolutionError 
        ? dbErr 
        : new RuntimeError(`Database unavailable during tenant resolution: ${dbErr.message}`, correlationId);

      await this.publishFailure(correlationId, lookupKey, finalError.message);
      throw finalError;
    }
  }

  private verifyStatus(context: TenantContext, correlationId: string): void {
    if (context.status === 'SUSPENDED') {
      throw new TenantResolutionError(
        `Tenant ${context.tenantId} is SUSPENDED`,
        'TENANT_SUSPENDED',
        correlationId
      );
    }
    // Note: MAINTENANCE stores can still be resolved, but rendering pipeline handles standard splash block.
  }

  private async publishFailure(correlationId: string, lookupKey: string, reason: string): Promise<void> {
    this.logger.error({
      message: `Tenant resolution failed for '${lookupKey}': ${reason}`,
      correlationId,
    });

    this.eventBus.publish({
      eventId: `evt_res_fail_${Math.random().toString(36).substr(2, 9)}`,
      eventType: 'Tenant.ResolutionFailed',
      timestamp: new Date().toISOString(),
      correlationId,
      payload: { lookupKey, reason },
    }).catch(() => {});
  }

  private extractTenantIdFromJwt(token: string): string | null {
    try {
      const parts = token.split('.');
      if (parts.length !== 3) {
        return null;
      }
      const payloadBase64 = parts[1].replace(/-/g, '+').replace(/_/g, '/');
      const decodedPayload = this.base64Decode(payloadBase64);
      const payload = JSON.parse(decodedPayload);
      return payload.tenantId || null;
    } catch {
      return null;
    }
  }

  private base64Decode(str: string): string {
    if (typeof atob === 'function') {
      return atob(str);
    }
    return Buffer.from(str, 'base64').toString('utf8');
  }
}

import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { Platform } from '../bootstrap/RuntimeBootstrap';
import { PlatformEventBusImpl } from '../events/PlatformEventBus';
import { createMockRequest, createMockResponse } from '../mocks/http';
import { TenantDatabaseProvider } from './TenantResolver';
import { TenantContext } from './TenantTypes';
import { TenantContextBuilder } from './TenantContextBuilder';
import { ConfigurationManager } from '../config/PlatformConfig';

describe('Runtime Request Integration Flow', () => {
  let platform: Platform;
  let eventBus: PlatformEventBusImpl;
  let dbProvider: TenantDatabaseProvider;
  let mockTenants: Record<string, TenantContext>;
  let originalEnv: string | undefined;

  function createFakeJwt(payload: Record<string, any>): string {
    const header = Buffer.from(JSON.stringify({ alg: 'HS256', typ: 'JWT' })).toString('base64');
    const payloadStr = Buffer.from(JSON.stringify(payload)).toString('base64');
    return `${header}.${payloadStr}.fake_signature`;
  }

  beforeEach(async () => {
    originalEnv = process.env.NODE_ENV;
    (process.env as any).NODE_ENV = 'development';
    ConfigurationManager.resetInstanceForTesting();
    const tenantA = new TenantContextBuilder()
      .setTenantId('store_fashion_001')
      .setSlug('fashion')
      .setStatus('ACTIVE')
      .setDomains({ primary: 'fashion.localhost' })
      .setPlan({ tier: 'GROWTH', limits: {} })
      .setCapabilities(['cart', 'seo'])
      .setMetadata({ cacheKey: 'etag-a', lastRefresh: new Date().toISOString(), ttlSeconds: 300 })
      .build();

    const tenantB = new TenantContextBuilder()
      .setTenantId('store_b')
      .setSlug('books')
      .setStatus('ACTIVE')
      .setDomains({ primary: 'books.localhost' })
      .setPlan({ tier: 'FREE', limits: {} })
      .setCapabilities([])
      .setMetadata({ cacheKey: 'etag-b', lastRefresh: new Date().toISOString(), ttlSeconds: 300 })
      .build();

    mockTenants = {
      'store_fashion_001': tenantA,
      'store_b': tenantB,
    };

    dbProvider = {
      findByTenantId: async (id) => mockTenants[id] || null,
      findByDomain: async (domain) => {
        return Object.values(mockTenants).find(
          t => t.domains.primary === domain || t.domains.custom === domain
        ) || null;
      },
      findBySlug: async (slug) => {
        return Object.values(mockTenants).find(t => t.slug === slug) || null;
      },
    };

    platform = new Platform();
    platform.setDatabaseProvider(dbProvider);
    const context = await platform.bootstrap();
    expect(context.healthStatus).toBe('READY');
  });

  afterEach(() => {
    (process.env as any).NODE_ENV = originalEnv;
    ConfigurationManager.resetInstanceForTesting();
    vi.restoreAllMocks();
  });

  it('Should successfully process request, resolve tenant, emit event and inject tracing headers', async () => {
    const tenantResolvedSpy = vi.fn();
    eventBus = platform.getEventBus();
    eventBus.subscribe('Tenant.Resolved', tenantResolvedSpy);

    const req = createMockRequest({
      url: 'http://fashion.localhost/api/test-context',
      headers: {
        'Host': 'fashion.localhost',
        'X-Correlation-Id': 'req_test_flow_999'
      }
    });
    const res = createMockResponse();

    await platform.handleRequest(req, res);

    expect(res.statusCode).toBe(200);
    expect(res.getHeader('X-Correlation-Id')).toBe('req_test_flow_999');
    expect(res.getHeader('X-Tenant-Id')).toBe('store_fashion_001');
    expect(Number(res.getHeader('X-Execution-Time-Ms'))).toBeLessThan(100);

    expect(tenantResolvedSpy).toHaveBeenCalledTimes(1);
    const event = tenantResolvedSpy.mock.calls[0][0];
    expect(event.correlationId).toBe('req_test_flow_999');
    expect(event.tenantId).toBe('store_fashion_001');
    expect(event.payload.slug).toBe('fashion');
  });

  it('Should return 404 and emit Tenant.ResolutionFailed when host is unknown', async () => {
    const resolutionFailedSpy = vi.fn();
    eventBus = platform.getEventBus();
    eventBus.subscribe('Tenant.ResolutionFailed', resolutionFailedSpy);

    const req = createMockRequest({
      url: 'http://unknown-host.com/api/test-context',
      headers: {
        'Host': 'unknown-host.com',
        'X-Correlation-Id': 'req_failed_flow_111'
      }
    });
    const res = createMockResponse();

    await platform.handleRequest(req, res);

    expect(res.statusCode).toBe(404);
    expect(res.getHeader('X-Correlation-Id')).toBe('req_failed_flow_111');
    expect(res.getHeader('X-Tenant-Id')).toBeUndefined();

    expect(resolutionFailedSpy).toHaveBeenCalledTimes(1);
    const event = resolutionFailedSpy.mock.calls[0][0];
    expect(event.correlationId).toBe('req_failed_flow_111');
    expect(event.payload.lookupKey).toBe('domain:unknown-host.com');
  });

  it('Should reject request with 403 Forbidden when trying to access host of Tenant A with credentials of Tenant B (Cross Tenant Attempt)', async () => {
    const jwt = createFakeJwt({ tenantId: 'store_b' });

    const req = createMockRequest({
      url: 'http://fashion.localhost/api/secure-action',
      headers: {
        'Host': 'fashion.localhost',
        'X-Correlation-Id': 'req_cross_attempt_403',
        'Authorization': `Bearer ${jwt}`
      }
    });
    const res = createMockResponse();

    await platform.handleRequest(req, res);

    expect(res.statusCode).toBe(403);
  });
});

import { describe, it, expect, beforeEach, vi } from 'vitest';
import { TenantResolver, TenantDatabaseProvider, TenantL2Cache } from './TenantResolver';
import { TenantContext } from './TenantTypes';
import { TenantContextBuilder } from './TenantContextBuilder';
import { PlatformEventBusImpl } from '../events/PlatformEventBus';
import { ConsolePlatformLogger } from '../logger/Logger';
import { TenantResolutionError, RuntimeError } from '../errors/PlatformError';

describe('Tenant Resolver Engine', () => {
  let eventBus: PlatformEventBusImpl;
  let logger: ConsolePlatformLogger;
  let dbProvider: TenantDatabaseProvider;
  let mockTenants: Record<string, TenantContext>;

  // Helper to create valid JWT tokens
  function createFakeJwt(payload: Record<string, any>): string {
    const header = Buffer.from(JSON.stringify({ alg: 'HS256', typ: 'JWT' })).toString('base64');
    const payloadStr = Buffer.from(JSON.stringify(payload)).toString('base64');
    return `${header}.${payloadStr}.fake_signature`;
  }

  beforeEach(() => {
    logger = new ConsolePlatformLogger();
    eventBus = new PlatformEventBusImpl(logger);
    logger.setEventBus(eventBus);

    // Prepare mock tenants
    const tenantA = new TenantContextBuilder()
      .setTenantId('tenant-a')
      .setSlug('store-a')
      .setStatus('ACTIVE')
      .setDomains({ primary: 'store-a.webfactor.io', custom: 'fashion-store-a.com' })
      .setPlan({ tier: 'GROWTH', limits: { products: 100 } })
      .setCapabilities(['cart', 'seo'])
      .setMetadata({ cacheKey: 'etag-a', lastRefresh: new Date().toISOString(), ttlSeconds: 10 })
      .build();

    const tenantSuspended = new TenantContextBuilder()
      .setTenantId('tenant-suspended')
      .setSlug('suspended-store')
      .setStatus('SUSPENDED')
      .setDomains({ primary: 'suspended.webfactor.io' })
      .setPlan({ tier: 'FREE', limits: { products: 10 } })
      .setCapabilities([])
      .setMetadata({ cacheKey: 'etag-suspended', lastRefresh: new Date().toISOString(), ttlSeconds: 10 })
      .build();

    mockTenants = {
      'tenant-a': tenantA,
      'tenant-suspended': tenantSuspended,
    };

    dbProvider = {
      findByTenantId: async (id) => mockTenants[id] || null,
      findByDomain: async (domain) => {
        return Object.values(mockTenants).find(
          t => t.domains.primary === domain || t.domains.custom === domain
        ) || null;
      },
      findBySlug: async (slug) => {
        return Object.values(mockTenants).find(t => t.slug === slug) || null;
      },
    };
  });

  it('Should resolve tenant by custom domain and return correct context', async () => {
    const resolver = new TenantResolver({ dbProvider, eventBus, logger });
    const context = await resolver.resolve({
      headers: { host: 'fashion-store-a.com' },
    });

    expect(context.tenantId).toBe('tenant-a');
    expect(context.slug).toBe('store-a');
    expect(context.status).toBe('ACTIVE');
    expect(context.capabilities).toContain('cart');
  });

  it('Should resolve tenant by internal preview URL', async () => {
    const resolver = new TenantResolver({ dbProvider, eventBus, logger });
    const context = await resolver.resolve({
      headers: { host: 'store-a.webfactor.io' },
    });

    expect(context.tenantId).toBe('tenant-a');
    expect(context.slug).toBe('store-a');
  });

  it('Should resolve tenant by Signed API Token in Authorization header', async () => {
    const resolver = new TenantResolver({ dbProvider, eventBus, logger });
    const jwt = createFakeJwt({ tenantId: 'tenant-a' });

    const context = await resolver.resolve({
      headers: { authorization: `Bearer ${jwt}` },
    });

    expect(context.tenantId).toBe('tenant-a');
  });

  it('Should resolve tenant by Signed API Token in query params', async () => {
    const resolver = new TenantResolver({ dbProvider, eventBus, logger });
    const jwt = createFakeJwt({ tenantId: 'tenant-a' });

    const context = await resolver.resolve({
      headers: {},
      url: `http://localhost/api/products?api_key=${jwt}`,
    });

    expect(context.tenantId).toBe('tenant-a');
  });

  it('Should resolve tenant by Development Override if environment is development', async () => {
    const resolver = new TenantResolver({
      dbProvider,
      eventBus,
      logger,
      environment: 'development',
    });

    const context = await resolver.resolve({
      headers: { 'x-tenant-override': 'tenant-a' },
    });

    expect(context.tenantId).toBe('tenant-a');
  });

  it('Should ignore Development Override and fall back if environment is production', async () => {
    // Suppress warn messages from polluting test output
    vi.spyOn(logger, 'warn').mockImplementation(() => {});

    const resolver = new TenantResolver({
      dbProvider,
      eventBus,
      logger,
      environment: 'production',
    });

    // Should ignore override and fallback to host header
    const context = await resolver.resolve({
      headers: {
        'x-tenant-override': 'tenant-suspended',
        host: 'store-a.webfactor.io',
      },
    });

    expect(context.tenantId).toBe('tenant-a'); // Resolved from host 'store-a.webfactor.io'
  });

  it('Should leverage L1 cache on second hit (cache hit)', async () => {
    const findSpy = vi.spyOn(dbProvider, 'findByDomain');
    const resolver = new TenantResolver({ dbProvider, eventBus, logger });

    // First lookup (cache miss)
    const context1 = await resolver.resolve({ headers: { host: 'fashion-store-a.com' } });
    expect(findSpy).toHaveBeenCalledTimes(1);

    // Second lookup (cache hit)
    const context2 = await resolver.resolve({ headers: { host: 'fashion-store-a.com' } });
    expect(findSpy).toHaveBeenCalledTimes(1); // Still 1

    expect(context1).toBe(context2);
  });

  it('Should cache miss and query database when cache is invalidated', async () => {
    const findSpy = vi.spyOn(dbProvider, 'findByDomain');
    const resolver = new TenantResolver({ dbProvider, eventBus, logger });

    await resolver.resolve({ headers: { host: 'fashion-store-a.com' } });
    expect(findSpy).toHaveBeenCalledTimes(1);

    // Invalidate cache
    resolver.getL1Cache().invalidate('tenant:domain:fashion-store-a.com');

    // Second lookup
    await resolver.resolve({ headers: { host: 'fashion-store-a.com' } });
    expect(findSpy).toHaveBeenCalledTimes(2);
  });

  it('Should throw TenantResolutionError for suspended tenant', async () => {
    const resolver = new TenantResolver({ dbProvider, eventBus, logger });

    await expect(
      resolver.resolve({ headers: { host: 'suspended.webfactor.io' } })
    ).rejects.toThrowError(TenantResolutionError);
  });

  it('Should throw TenantResolutionError with TENANT_NOT_FOUND code for unknown tenant', async () => {
    const resolver = new TenantResolver({ dbProvider, eventBus, logger });

    await expect(
      resolver.resolve({ headers: { host: 'unknown-shop.com' } })
    ).rejects.toThrow();
  });

  it('Should prevent cross-tenant data access (Tenant Isolation)', async () => {
    const resolver = new TenantResolver({ dbProvider, eventBus, logger });

    const contextA = await resolver.resolve({ headers: { host: 'store-a.webfactor.io' } });

    // Attempting to resolve an unknown or isolated domain should not leak data from A
    await expect(
      resolver.resolve({ headers: { host: 'unknown-shop.com' } })
    ).rejects.toThrow();

    expect(contextA.tenantId).toBe('tenant-a');
  });

  it('Should fallback to L2 Cache when database is unreachable (Circuit Breaker)', async () => {
    const l2Store = new Map<string, { context: TenantContext; expiresAt: number }>();
    const l2Cache: TenantL2Cache = {
      get: async (key) => l2Store.get(key) || null,
      set: async (key, context, ttlSeconds) => {
        l2Store.set(key, { context, expiresAt: Date.now() + (ttlSeconds * 1000) });
      },
      delete: async (key) => {
        l2Store.delete(key);
      },
    };

    // 1. Populate L2 Cache
    const resolverSetup = new TenantResolver({ dbProvider, eventBus, logger, l2Cache });
    await resolverSetup.resolve({ headers: { host: 'fashion-store-a.com' } });

    // 2. Break the DB provider
    const brokenDbProvider: TenantDatabaseProvider = {
      findByTenantId: async () => { throw new Error('Database is offline'); },
      findByDomain: async () => { throw new Error('Database is offline'); },
      findBySlug: async () => { throw new Error('Database is offline'); },
    };

    // 3. Resolve using broken DB provider with L2 Cache fallback
    const resolverFallback = new TenantResolver({
      dbProvider: brokenDbProvider,
      eventBus,
      logger,
      l2Cache,
    });

    const context = await resolverFallback.resolve({ headers: { host: 'fashion-store-a.com' } });
    expect(context.tenantId).toBe('tenant-a'); // Resolved from stale/cached L2 KV
  });

  it('Should fail closed if database is unreachable and L2 cache is completely expired', async () => {
    const l2Store = new Map<string, { context: TenantContext; expiresAt: number }>();
    const l2Cache: TenantL2Cache = {
      get: async (key) => l2Store.get(key) || null,
      set: async (key, context, ttlSeconds) => {
        l2Store.set(key, { context, expiresAt: Date.now() + (ttlSeconds * 1000) });
      },
      delete: async (key) => {
        l2Store.delete(key);
      },
    };

    // 1. Populate L2 Cache
    const resolverSetup = new TenantResolver({ dbProvider, eventBus, logger, l2Cache });
    await resolverSetup.resolve({ headers: { host: 'fashion-store-a.com' } });

    // 2. Artificially age the L2 cache entry beyond max stale limit (e.g. 10 days ago)
    const key = 'tenant:domain:fashion-store-a.com';
    const entry = l2Store.get(key)!;
    l2Store.set(key, {
      context: entry.context,
      expiresAt: Date.now() - (10 * 24 * 60 * 60 * 1000), // 10 days ago
    });

    // 3. Break DB Provider
    const brokenDbProvider: TenantDatabaseProvider = {
      findByTenantId: async () => { throw new Error('Database is offline'); },
      findByDomain: async () => { throw new Error('Database is offline'); },
      findBySlug: async () => { throw new Error('Database is offline'); },
    };

    const resolverFailClosed = new TenantResolver({
      dbProvider: brokenDbProvider,
      eventBus,
      logger,
      l2Cache,
      maxStaleSeconds: 3600, // 1 hour max stale
    });

    // Expect fail closed (reject resolution)
    await expect(
      resolverFailClosed.resolve({ headers: { host: 'fashion-store-a.com' } })
    ).rejects.toThrowError(RuntimeError);
  });
});

