import { ProvisionEngine, ProvisionEngineEvent } from './ProvisionEngine';
import { ProvisionRequest } from './ProvisionRequest';
import { ProvisionResult, createProvisionResult } from './ProvisionResult';
import { ProvisionPipeline } from './ProvisionPipeline';
import { createProvisionContext, extendProvisionContext } from './ProvisionContext';
import { PublishEngine } from '../../publish-engine/src/PublishEngine';
import { createPublishRequest } from '../../publish-core/src/PublishRequest';
import { StoreConfig } from '../../runtime-core/src/RuntimeContext';

export class DefaultProvisionEngine implements ProvisionEngine {
  private readonly pipeline: ProvisionPipeline;
  private readonly publishEngine: PublishEngine;
  private readonly provisionedConfigs = new Map<string, StoreConfig>();
  private readonly onEvent?: (event: ProvisionEngineEvent) => void;

  constructor(params: {
    pipeline: ProvisionPipeline;
    publishEngine: PublishEngine;
    onEvent?: (event: ProvisionEngineEvent) => void;
  }) {
    this.pipeline = params.pipeline;
    this.publishEngine = params.publishEngine;
    this.onEvent = params.onEvent;
  }

  /**
   * Allows external components (like the PublishEngine's loadStoreConfig dependency)
   * to resolve store configurations currently in-flight during the provisioning process.
   */
  getProvisionedConfig(storeId: string): StoreConfig | undefined {
    return this.provisionedConfigs.get(storeId);
  }

  async provision(request: ProvisionRequest): Promise<ProvisionResult> {
    const startOverall = Date.now();

    this.onEvent?.({
      type: 'ProvisionStarted',
      tenantId: request.tenantId,
      correlationId: request.correlationId,
      timestamp: new Date().toISOString()
    });

    const result = await this.pipeline.execute(request);

    if (!result.success || !result.storeConfig) {
      // Loop through stage results to find the failure
      const failedStage = result.stageResults.find(r => !r.success);

      this.onEvent?.({
        type: 'ProvisionFailed',
        tenantId: request.tenantId,
        correlationId: request.correlationId,
        timestamp: new Date().toISOString(),
        durationMs: Date.now() - startOverall,
        stage: failedStage?.stageName || 'pipeline',
        error: result.errors.join(', ')
      });

      return result;
    }

    // Emit success events for pipeline stages
    for (const stageRes of result.stageResults) {
      if (stageRes.success) {
        const eventTypeMap: Record<string, ProvisionEngineEvent['type']> = {
          tenant: 'TenantCreated',
          template: 'TemplateInstalled',
          packages: 'PackagesInstalled',
          'store-config': 'StoreConfigGenerated'
        };
        const type = eventTypeMap[stageRes.stageName];
        if (type) {
          this.onEvent?.({
            type,
            tenantId: request.tenantId,
            correlationId: request.correlationId,
            timestamp: new Date().toISOString(),
            durationMs: stageRes.durationMs
          });
        }
      }
    }

    // Temporarily cache the storeConfig so that PublishEngine's loadStoreConfig call can resolve it
    this.provisionedConfigs.set(request.storeId, result.storeConfig);

    try {
      this.onEvent?.({
        type: 'PublishStarted',
        tenantId: request.tenantId,
        correlationId: request.correlationId,
        timestamp: new Date().toISOString()
      });

      const publishRequest = createPublishRequest({
        tenantId: request.tenantId,
        storeId: request.storeId,
        mode: request.mode === 'LIVE' ? 'LIVE' : 'PREVIEW',
        correlationId: request.correlationId,
        metadata: {
          ...request.metadata,
          storeConfig: result.storeConfig
        }
      });

      const publishResult = await this.publishEngine.publish(publishRequest);

      if (!publishResult.success) {
        // Rollback all executed stages in reverse LIFO order
        let currentContext = createProvisionContext(request);
        currentContext = extendProvisionContext(currentContext, {
          storeConfig: result.storeConfig,
          installedPackages: request.initialPackages,
          metadata: result.metadata || {}
        });

        for (let i = this.pipeline.stages.length - 1; i >= 0; i--) {
          const stage = this.pipeline.stages[i];
          if (stage.rollback) {
            try {
              currentContext = await stage.rollback(currentContext);
            } catch (rollbackErr) {
              // Non-blocking rollback error tracking
            }
          }
        }

        const publishErrors = publishResult.errors || ['Publishing failed during provisioning'];

        this.onEvent?.({
          type: 'ProvisionFailed',
          tenantId: request.tenantId,
          correlationId: request.correlationId,
          timestamp: new Date().toISOString(),
          durationMs: Date.now() - startOverall,
          stage: 'publish',
          error: publishErrors.join(', ')
        });

        return createProvisionResult(
          false,
          request.correlationId,
          [
            ...result.stageResults,
            {
              stageName: 'publish-integration',
              success: false,
              durationMs: 0,
              errors: publishErrors
            }
          ],
          undefined,
          undefined,
          result.durationMs,
          result.metadata
        );
      }

      // Successful publish events
      this.onEvent?.({
        type: 'AssetsBuilt',
        tenantId: request.tenantId,
        correlationId: request.correlationId,
        timestamp: new Date().toISOString()
      });

      this.onEvent?.({
        type: 'DeploymentCompleted',
        tenantId: request.tenantId,
        correlationId: request.correlationId,
        timestamp: new Date().toISOString()
      });

      const overallDuration = Date.now() - startOverall;
      this.onEvent?.({
        type: 'ProvisionCompleted',
        tenantId: request.tenantId,
        correlationId: request.correlationId,
        timestamp: new Date().toISOString(),
        durationMs: overallDuration
      });

      // Successful Provision & Publish Flow
      return createProvisionResult(
        true,
        request.correlationId,
        result.stageResults,
        result.storeConfig,
        publishResult.deploymentUrl,
        result.durationMs,
        {
          ...result.metadata,
          publishReport: publishResult.metadata?.publishReport
        }
      );
    } catch (err) {
      const errMsg = err instanceof Error ? err.message : String(err);

      this.onEvent?.({
        type: 'ProvisionFailed',
        tenantId: request.tenantId,
        correlationId: request.correlationId,
        timestamp: new Date().toISOString(),
        durationMs: Date.now() - startOverall,
        stage: 'publish',
        error: errMsg
      });

      throw err;
    } finally {
      // Clean up cache
      this.provisionedConfigs.delete(request.storeId);
    }
  }
}

import { ProvisionPipeline, ProvisionPipelineBuilder } from './ProvisionPipeline';
import { ProvisionRequest } from './ProvisionRequest';
import { ProvisionResult, createProvisionResult } from './ProvisionResult';
import { ProvisionStage, StageResult } from './ProvisionStage';
import { ProvisionContext, createProvisionContext, extendProvisionContext } from './ProvisionContext';

export class DefaultProvisionPipeline implements ProvisionPipeline {
  readonly name: string;
  readonly stages: ReadonlyArray<ProvisionStage>;

  constructor(name = 'default-provision-pipeline', stages: ProvisionStage[] = []) {
    this.name = name;
    this.stages = stages;
  }

  async execute(request: ProvisionRequest): Promise<ProvisionResult> {
    let currentContext = createProvisionContext(request);
    const executedStages: ProvisionStage[] = [];
    const stageResults: StageResult[] = [];
    let success = true;
    const startOverall = Date.now();

    for (const stage of this.stages) {
      if (stage.canExecute && !stage.canExecute(currentContext)) {
        stageResults.push({
          stageName: stage.name,
          success: true,
          durationMs: 0,
          errors: [],
          data: { skipped: true }
        });
        continue;
      }

      const start = Date.now();
      executedStages.push(stage);

      try {
        currentContext = await stage.execute(currentContext);
        stageResults.push({
          stageName: stage.name,
          success: true,
          durationMs: Date.now() - start
        });
      } catch (err) {
        success = false;
        const durationMs = Date.now() - start;
        const errMsg = err instanceof Error ? err.message : String(err);

        stageResults.push({
          stageName: stage.name,
          success: false,
          durationMs,
          errors: [errMsg]
        });

        // Rollback executed stages in reverse order
        for (let i = executedStages.length - 1; i >= 0; i--) {
          const rollbackStage = executedStages[i];
          if (rollbackStage.rollback) {
            try {
              currentContext = await rollbackStage.rollback(currentContext);
            } catch (rollbackErr) {
              const rollbackErrMsg = rollbackErr instanceof Error ? rollbackErr.message : String(rollbackErr);
              currentContext = extendProvisionContext(currentContext, {
                metadata: {
                  ...currentContext.metadata,
                  [`rollback_error_${rollbackStage.name}`]: rollbackErrMsg
                }
              });
            }
          }
        }
        break; // Stop execution
      }
    }

    const durationMs = Date.now() - startOverall;

    return createProvisionResult(
      success,
      request.correlationId,
      stageResults,
      success ? currentContext.storeConfig : undefined,
      success ? currentContext.deploymentUrl : undefined,
      durationMs,
      currentContext.metadata
    );
  }

  addStage(stage: ProvisionStage): ProvisionPipeline {
    return new DefaultProvisionPipeline(this.name, [...this.stages, stage]);
  }

  removeStage(stageName: string): ProvisionPipeline {
    return new DefaultProvisionPipeline(this.name, this.stages.filter(s => s.name !== stageName));
  }

  getStage(stageName: string): ProvisionStage | undefined {
    return this.stages.find(s => s.name === stageName);
  }
}

export class DefaultProvisionPipelineBuilder implements ProvisionPipelineBuilder {
  private stages: ProvisionStage[] = [];
  private pipelineName = 'default-provision-pipeline';

  withStage(stage: ProvisionStage): ProvisionPipelineBuilder {
    this.stages.push(stage);
    return this;
  }

  withName(name: string): ProvisionPipelineBuilder {
    this.pipelineName = name;
    return this;
  }

  build(): ProvisionPipeline {
    return new DefaultProvisionPipeline(this.pipelineName, this.stages);
  }
}

export function createProvisionPipelineBuilder(): ProvisionPipelineBuilder {
  return new DefaultProvisionPipelineBuilder();
}

import { ProvisionStage } from '../ProvisionStage';
import { ProvisionContext, extendProvisionContext } from '../ProvisionContext';
import { MarketplaceInstaller } from '../../../package-registry/src';

export class PackageStage implements ProvisionStage {
  readonly name = 'packages';
  private readonly installer?: MarketplaceInstaller;

  constructor(installer?: MarketplaceInstaller) {
    this.installer = installer;
  }

  async execute(context: ProvisionContext): Promise<ProvisionContext> {
    const requestedPackages = context.request.initialPackages;

    if (this.installer) {
      const coreVersion = (context.request.metadata?.coreVersion as string) || '1.0.0';
      const plan = await this.installer.createInstallationPlan(requestedPackages, coreVersion);
      await this.installer.install(plan, context.request.tenantId, context.request.storeId);

      const installed = plan.steps.map(s => s.packageId);

      return extendProvisionContext(context, {
        installedPackages: installed,
        metadata: {
          ...context.metadata,
          capabilities: plan.capabilities,
          installationPlan: plan
        }
      });
    }

    const capabilitiesMap: Record<string, string> = {
      stripe: 'payments',
      paypal: 'payments',
      posthog: 'analytics',
      ga4: 'analytics',
      fedex: 'shipping',
      dhl: 'shipping',
      yoast: 'seo',
      hubspot: 'crm'
    };

    const resolvedCapabilities = new Set<string>();
    const installed: string[] = [];

    for (const pkg of requestedPackages) {
      installed.push(pkg);
      const cap = capabilitiesMap[pkg.toLowerCase()];
      if (cap) {
        resolvedCapabilities.add(cap);
      }
    }

    return extendProvisionContext(context, {
      installedPackages: installed,
      metadata: {
        ...context.metadata,
        capabilities: Array.from(resolvedCapabilities)
      }
    });
  }

  async rollback(context: ProvisionContext): Promise<ProvisionContext> {
    if (this.installer && context.metadata?.installationPlan) {
      await this.installer.rollback(
        context.metadata.installationPlan as any,
        context.request.tenantId,
        context.request.storeId
      );
    }

    return extendProvisionContext(context, {
      installedPackages: [],
      metadata: {
        ...context.metadata,
        capabilities: undefined,
        installationPlan: undefined
      }
    });
  }
}

import { ProvisionStage } from '../ProvisionStage';
import { ProvisionContext, extendProvisionContext } from '../ProvisionContext';
