export function makeConfig(storeId: string, sections: RuntimeSection[]): StoreConfig {
  return {
    storeId,
    storeName: 'Test Store',
    publicationStatus: 'PUBLISHED',
    branding: { primaryColor: '#7c3aed', secondaryColor: '#ec4899', font: 'Inter' },
