export interface InstallationStep {
  type: 'theme' | 'components' | 'assets' | 'pages' | 'commerce' | 'configuration';
  id: string;
  name: string;
  payload: unknown;
  order: number;
}

export interface InstallationPlan {
  templateId: string;
  templateVersion: string;
  tenantId: string;
  steps: InstallationStep[];
  dependencies: string[];
  validation: InstallationValidation;
  metadata: InstallationMetadata;
}

export interface InstallationValidation {
  compatibility: boolean;
  missingDependencies: string[];
  conflicts: string[];
  minPlatformVersion: string;
  issues: string[];
}

export interface InstallationMetadata {
  templateName: string;
  templateAuthor: string;
  templateDescription: string;
  estimatedTimeMs: number;
  requiredComponents: string[];
  requiredThemes: string[];
  requiredAssets: string[];
}

export class InstallationPlanBuilder {
  private templateId: string = '';
  private templateVersion: string = '';
  private tenantId: string = '';
  private template: MarketplaceTemplate | null = null;
  private packageData: TemplateManifestData | null = null;
  private steps: InstallationStep[] = [];

  withTemplate(template: MarketplaceTemplate): InstallationPlanBuilder {
    this.template = template;
    this.templateId = template.id;
    this.templateVersion = template.versions[0]?.version || '0.0.0';
    return this;
  }

  withPackageData(data: TemplateManifestData): InstallationPlanBuilder {
    this.packageData = data;
    return this;
  }

  withTenant(tenantId: string): InstallationPlanBuilder {
    this.tenantId = tenantId;
    return this;
  }

  build(): InstallationPlan {
    if (!this.template) {
      throw new Error('Template is required to build installation plan');
    }

    const steps = this.buildSteps();
    const validation = this.buildValidation();
    const metadata = this.buildMetadata();

    return {
      templateId: this.templateId,
      templateVersion: this.templateVersion,
      tenantId: this.tenantId,
      steps,
      dependencies: this.template.dependencies,
      validation,
      metadata
    };
  }

  private buildSteps(): InstallationStep[] {
    const steps: InstallationStep[] = [];
    let order = 0;

    if (this.packageData?.themes) {
      steps.push({
        type: 'theme',
        id: 'theme-install',
        name: 'Install Theme',
        payload: this.packageData.themes,
        order: order++
      });
    }

    if (this.packageData?.components) {
      steps.push({
        type: 'components',
        id: 'components-install',
        name: 'Install Components',
        payload: this.packageData.components,
        order: order++
      });
    }

    if (this.packageData?.assets) {
      steps.push({
        type: 'assets',
        id: 'assets-install',
        name: 'Install Assets',
        payload: this.packageData.assets,
        order: order++
      });
    }

    if (this.packageData?.pages) {
      steps.push({
        type: 'pages',
        id: 'pages-install',
        name: 'Install Pages',
        payload: this.packageData.pages,
        order: order++
      });
    }

    if (this.packageData?.commerce) {
      steps.push({
        type: 'commerce',
        id: 'commerce-install',
        name: 'Install Commerce',
        payload: this.packageData.commerce,
        order: order++
      });
    }

    steps.push({
      type: 'configuration',
      id: 'config-apply',
      name: 'Apply Configuration',
      payload: this.packageData?.runtime,
      order: steps.length
    });

    return steps;
  }

  private buildValidation(): InstallationValidation {
    const issues: string[] = [];
    const missingDependencies: string[] = [];
    const conflicts: string[] = [];

    if (!this.template) {
      return {
        compatibility: false,
        missingDependencies: [],
        conflicts: [],
        minPlatformVersion: '3.0.0',
        issues: ['Template is required']
      };
    }

    if (this.template.dependencies && this.template.dependencies.length > 0) {
      issues.push(`Template has ${this.template.dependencies.length} dependencies that need resolution`);
    }

    return {
      compatibility: true,
      missingDependencies,
      conflicts,
      minPlatformVersion: this.template.compatibility?.builder || '>=3.0',
      issues
    };
  }

  private buildMetadata(): InstallationMetadata {
    return {
      templateName: this.template?.name || 'Unknown',
      templateAuthor: this.template?.author?.name || 'Unknown',
      templateDescription: this.template?.description || '',
      estimatedTimeMs: this.steps.length * 500,
      requiredComponents: Object.keys(this.packageData?.components || {}),
      requiredThemes: Object.keys(this.packageData?.themes || {}),
      requiredAssets: Object.keys(this.packageData?.assets || {})
    };
  }
}

import { InstallationPlan, InstallationStep } from './InstallationPlan';
import { InstallationReport } from './InstallationReport';

export enum TransactionStatus {
  STARTED = 'STARTED',
  COMMITTED = 'COMMITTED',
  ROLLED_BACK = 'ROLLED_BACK',
  FAILED = 'FAILED'
}

export interface TransactionContext {
  tenantId: string;
  templateId: string;
  templateVersion: string;
  artifacts: {
    components: string[];
    themes: string[];
    assets: string[];
  };
  metadata: Record<string, unknown>;
}

export interface TransactionEvent {
  type: 'TRANSACTION_STARTED' | 'STEP_STARTED' | 'STEP_COMPLETED' | 'STEP_ROLLED_BACK' | 'TRANSACTION_COMPLETED' | 'TRANSACTION_FAILED';
  stepId?: string;
  stepName?: string;
  timestamp: string;
  metadata?: Record<string, unknown>;
}

export class InstallationTransaction {
  private status: TransactionStatus = TransactionStatus.STARTED;
  private context: TransactionContext | null = null;
  private executedSteps: string[] = [];
  private rolledBackSteps: string[] = [];
  private errors: string[] = [];
  private warnings: string[] = [];
  private startTime: string = new Date().toISOString();
  private endTime?: string;
  private eventListeners: ((event: TransactionEvent) => void)[] = [];

  begin(plan: InstallationPlan): void {
    this.context = {
      tenantId: plan.tenantId,
      templateId: plan.templateId,
      templateVersion: plan.templateVersion,
      artifacts: {
        components: [],
        themes: [],
        assets: []
      },
      metadata: {}
    };
    this.status = TransactionStatus.STARTED;
    this.emit({
      type: 'TRANSACTION_STARTED',
      timestamp: new Date().toISOString(),
      metadata: { templateId: plan.templateId, tenantId: plan.tenantId }
    });
  }

  async executeStep(step: InstallationStep): Promise<boolean> {
    if (!this.context) {
      throw new Error('Transaction not started');
    }

    this.emit({
      type: 'STEP_STARTED',
      stepId: step.id,
      stepName: step.name,
      timestamp: new Date().toISOString()
    });

    try {
      await this.runStep(step);
      this.executedSteps.push(step.id);
      this.emit({
        type: 'STEP_COMPLETED',
        stepId: step.id,
        stepName: step.name,
        timestamp: new Date().toISOString()
      });
      return true;
    } catch (error) {
      this.errors.push(error instanceof Error ? error.message : String(error));
      this.status = TransactionStatus.FAILED;
      this.emit({
        type: 'TRANSACTION_FAILED',
        stepId: step.id,
        timestamp: new Date().toISOString(),
        metadata: { error: error instanceof Error ? error.message : String(error) }
      });
      return false;
    }
  }

  async rollback(): Promise<void> {
    if (!this.context) {
      throw new Error('Transaction not started');
    }

    this.status = TransactionStatus.ROLLED_BACK;
    const reversedSteps = [...this.executedSteps].reverse();

    for (const stepId of reversedSteps) {
      try {
        await this.rollbackStep(stepId);
        this.rolledBackSteps.push(stepId);
        this.emit({
          type: 'STEP_ROLLED_BACK',
          stepId,
          timestamp: new Date().toISOString()
        });
      } catch (error) {
        this.errors.push(`Rollback failed for ${stepId}: ${error instanceof Error ? error.message : String(error)}`);
      }
    }

    this.endTime = new Date().toISOString();
    this.emit({
      type: 'TRANSACTION_COMPLETED',
      timestamp: this.endTime,
      metadata: { status: 'ROLLED_BACK', rolledBackSteps: this.rolledBackSteps.length }
    });
  }

  commit(): void {
    if (this.status !== TransactionStatus.STARTED) {
      throw new Error('Transaction is not in STARTED state');
    }

    this.status = TransactionStatus.COMMITTED;
    this.endTime = new Date().toISOString();
    this.emit({
      type: 'TRANSACTION_COMPLETED',
      timestamp: this.endTime,
      metadata: { status: 'COMMITTED', executedSteps: this.executedSteps.length }
    });
  }

  abort(): void {
    this.status = TransactionStatus.FAILED;
    this.endTime = new Date().toISOString();
    this.emit({
      type: 'TRANSACTION_FAILED',
      timestamp: this.endTime,
      metadata: { status: 'ABORTED' }
    });
  }

  addEventListener(listener: (event: TransactionEvent) => void): void {
    this.eventListeners.push(listener);
  }

  removeEventListener(listener: (event: TransactionEvent) => void): void {
    this.eventListeners = this.eventListeners.filter(l => l !== listener);
  }

  private emit(event: TransactionEvent): void {
    for (const listener of this.eventListeners) {
      listener(event);
    }
  }

  protected async runStep(step: InstallationStep): Promise<void> {
    switch (step.type) {
      case 'theme':
        await this.installTheme(step.payload as Record<string, unknown>);
        break;
      case 'components':
        await this.installComponents(step.payload as Record<string, unknown>);
        break;
      case 'assets':
        await this.installAssets(step.payload as Record<string, unknown>);
        break;
      case 'pages':
        await this.installPages(step.payload as Record<string, unknown>);
        break;
      case 'commerce':
        await this.installCommerce(step.payload as Record<string, unknown>);
        break;
      case 'configuration':
        await this.applyConfiguration(step.payload as Record<string, unknown>);
        break;
    }
  }

  protected async rollbackStep(stepId: string): Promise<void> {
    // Concrete implementations should override this for actual rollback logic
  }

  protected async installTheme(themeData: Record<string, unknown>): Promise<void> {}
  protected async installComponents(componentData: Record<string, unknown>): Promise<void> {}
  protected async installAssets(assetData: Record<string, unknown>): Promise<void> {}
  protected async installPages(pageData: Record<string, unknown>): Promise<void> {}
  protected async installCommerce(commerceData: Record<string, unknown>): Promise<void> {}
  protected async applyConfiguration(configData: Record<string, unknown>): Promise<void> {}

  getReport(): InstallationReport {
    const durationMs = this.endTime 
      ? new Date(this.endTime).getTime() - new Date(this.startTime).getTime()
      : new Date().getTime() - new Date(this.startTime).getTime();

    return {
      id: `tx-${this.context?.tenantId}-${Date.now()}`,
      templateId: this.context?.templateId || '',
      templateVersion: this.context?.templateVersion || '',
      tenantId: this.context?.tenantId || '',
      status: this.mapStatus(),
      startedAt: this.startTime,
      completedAt: this.endTime,
      durationMs,
      stepsCompleted: this.executedSteps,
      stepsFailed: this.errors.length > 0 ? this.executedSteps.slice(-1) : [],
      installedComponents: this.context?.artifacts.components || [],
      installedThemes: this.context?.artifacts.themes || [],
      installedAssets: this.context?.artifacts.assets || [],
      migrations: [],
      warnings: this.warnings,
      errors: this.errors,
      compatibilityIssues: []
    };
  }

  private mapStatus(): 'pending' | 'running' | 'completed' | 'failed' | 'rolled-back' {
    switch (this.status) {
      case TransactionStatus.STARTED: return 'pending';
      case TransactionStatus.COMMITTED: return 'completed';
      case TransactionStatus.ROLLED_BACK: return 'rolled-back';
      case TransactionStatus.FAILED: return 'failed';
      default: return 'pending';
    }
  }
}

import { MarketplaceTemplate, PlatformVersion } from '../../marketplace-core/src';
import { TemplateManifestData } from '../../template-package/src/TemplateManifest';

export interface VerificationResult {
  success: boolean;
  packageIntegrity: PackageIntegrityResult;
  runtimeVerification: RuntimeVerificationResult;
  tenantVerification: TenantVerificationResult;
  warnings: string[];
  errors: string[];
  durationMs: number;
}

export interface PackageIntegrityResult {
  valid: boolean;
  manifestValid: boolean;
  versionValid: boolean;
  checksumValid: boolean;
  dependenciesValid: boolean;
  compatibilityValid: boolean;
  issues: string[];
}

export interface RuntimeVerificationResult {
  themeRuntime: boolean;
  componentRuntime: boolean;
  templateRuntime: boolean;
  assetRuntime: boolean;
  commercePersistence: boolean;
  publishPipelineReady: boolean;
  issues: string[];
}

export interface TenantVerificationResult {
  dataIsolation: boolean;
  correctScope: boolean;
  correctRepositories: boolean;
  assetReferencesValid: boolean;
  themeProviderValid: boolean;
  issues: string[];
}

export class InstallationVerifier {
  async verify(
    template: MarketplaceTemplate,
    packageData: TemplateManifestData,
    tenantId: string,
    platformVersion: PlatformVersion
  ): Promise<VerificationResult> {
    const startTime = Date.now();

    const packageIntegrity = await this.verifyPackageIntegrity(template, packageData);
    const runtimeVerification = await this.verifyRuntime(packageData);
    const tenantVerification = await this.verifyTenant(tenantId, packageData);

    const warnings: string[] = [];
    const errors: string[] = [];

    if (!packageIntegrity.valid) {
      errors.push('Package integrity check failed');
    }
    if (!runtimeVerification.themeRuntime) {
      errors.push('ThemeRuntime verification failed');
    }
    if (!runtimeVerification.componentRuntime) {
      errors.push('ComponentRuntime verification failed');
    }
    if (!tenantVerification.dataIsolation) {
      errors.push('Tenant data isolation check failed');
    }

    return {
      success: errors.length === 0,
      packageIntegrity,
      runtimeVerification,
      tenantVerification,
      warnings,
      errors,
      durationMs: Date.now() - startTime
    };
  }

  private async verifyPackageIntegrity(
    template: MarketplaceTemplate,
    packageData: TemplateManifestData
  ): Promise<PackageIntegrityResult> {
    const issues: string[] = [];

    const manifestValid = this.validateManifest(packageData.manifest);
    const versionValid = this.validateVersion(packageData.manifest.version);
    const checksumValid = true;
    const dependenciesValid = this.validateDependencies(template.dependencies);
    const compatibilityValid = this.validateCompatibility(template.compatibility);

    if (!manifestValid) issues.push('Invalid manifest');
    if (!versionValid) issues.push('Invalid version format');
    if (!dependenciesValid) issues.push('Invalid dependencies');
    if (!compatibilityValid) issues.push('Incompatible platform requirements');

    return {
      valid: issues.length === 0,
      manifestValid,
      versionValid,
      checksumValid,
      dependenciesValid,
      compatibilityValid,
      issues
    };
  }

  private async verifyRuntime(packageData: TemplateManifestData): Promise<RuntimeVerificationResult> {
    const issues: string[] = [];

    const themeRuntime = this.checkThemeRuntime(packageData.themes);
    const componentRuntime = this.checkComponentRuntime(packageData.components);
    const templateRuntime = this.checkTemplateRuntime(packageData.pages);
    const assetRuntime = this.checkAssetRuntime(packageData.assets);
    const commercePersistence = this.checkCommercePersistence(packageData.commerce);
    const publishPipelineReady = true;

    if (!themeRuntime) issues.push('ThemeRuntime not available');
    if (!componentRuntime) issues.push('ComponentRuntime not available');
    if (!templateRuntime) issues.push('TemplateRuntime not available');
    if (!assetRuntime) issues.push('AssetRuntime not available');
    if (!commercePersistence) issues.push('CommercePersistence not available');

    return {
      themeRuntime,
      componentRuntime,
      templateRuntime,
      assetRuntime,
      commercePersistence,
      publishPipelineReady,
      issues
    };
  }

  private async verifyTenant(tenantId: string, packageData: TemplateManifestData): Promise<TenantVerificationResult> {
    const issues: string[] = [];

    const dataIsolation = true;
    const correctScope = tenantId.length > 0;
    const correctRepositories = true;
    const assetReferencesValid = this.validateAssetReferences(packageData.assets);
    const themeProviderValid = this.validateThemeProvider(packageData.themes);

    if (!assetReferencesValid) issues.push('Asset references validation failed');
    if (!themeProviderValid) issues.push('ThemeProvider validation failed');

    return {
      dataIsolation,
      correctScope,
      correctRepositories,
      assetReferencesValid,
      themeProviderValid,
      issues
    };
  }

  private validateManifest(manifest: TemplateManifestData['manifest']): boolean {
    return !!manifest?.id && !!manifest?.version && !!manifest?.type;
  }

  private validateVersion(version: string): boolean {
    const semver = /^\d+\.\d+\.\d+$/;
    return semver.test(version);
  }

  private validateDependencies(dependencies: string[]): boolean {
    return Array.isArray(dependencies);
  }

  private validateCompatibility(compat: MarketplaceTemplate['compatibility']): boolean {
    return !!compat;
  }

  private checkThemeRuntime(themes: Record<string, unknown>): boolean {
    return typeof themes === 'object';
  }

  private checkComponentRuntime(components: Record<string, unknown>): boolean {
    return typeof components === 'object';
  }

  private checkTemplateRuntime(pages: Record<string, unknown>): boolean {
    return typeof pages === 'object';
  }

  private checkAssetRuntime(assets: Record<string, unknown>): boolean {
    return typeof assets === 'object';
  }

  private checkCommercePersistence(commerce: Record<string, unknown>): boolean {
    return typeof commerce === 'object';
  }

  private validateAssetReferences(assets: Record<string, unknown>): boolean {
    return typeof assets === 'object';
  }

  private validateThemeProvider(themes: Record<string, unknown>): boolean {
    return typeof themes === 'object';
  }
}

import { InstallationPlan, InstallationPlanBuilder, InstallationStep } from './InstallationPlan';
import { MarketplaceTemplate, PlatformVersion } from '../../marketplace-core/src/entities';
import { TemplateManifestData } from '../../template-package/src/TemplateManifest';
import { InstallationReport, InstallationReportBuilder } from './InstallationReport';

export interface TemplateInstallerDeps {
  readonly loadTemplate: (id: string) => Promise<MarketplaceTemplate | null>;
  readonly loadPackageData: (id: string, version: string) => Promise<TemplateManifestData | null>;
  readonly resolveDependencies: (dependencies: string[]) => Promise<string[]>;
  readonly checkCompatibility: (template: MarketplaceTemplate, platformVersion: PlatformVersion) => Promise<boolean>;
}

export interface InstallResult {
  success: boolean;
  report: InstallationReport;
}

export class TemplateInstallerEngine {
  constructor(private readonly deps: TemplateInstallerDeps) {}

  async install(templateId: string, tenantId: string, platformVersion?: PlatformVersion): Promise<InstallResult> {
    const reportBuilder = new InstallationReportBuilder()
      .withId(`install-${tenantId}-${Date.now()}`)
      .withTemplate(templateId, '')
      .withTenant(tenantId)
      .setStatus('running');

    const template = await this.deps.loadTemplate(templateId);
    if (!template) {
      const report = reportBuilder
        .markStepFailed('template-load', `Template ${templateId} not found`)
        .fail();
      return { success: false, report };
    }

    const version = template.versions[0]?.version || '0.0.0';
    const packageData = await this.deps.loadPackageData(templateId, version);
    if (!packageData) {
      const report = reportBuilder
        .withTemplate(templateId, version)
        .markStepFailed('package-load', `Package data not found for ${templateId}@${version}`)
        .fail();
      return { success: false, report };
    }

    const plan = new InstallationPlanBuilder()
      .withTemplate(template)
      .withPackageData(packageData)
      .withTenant(tenantId)
      .build();

    const compatibility = await this.deps.checkCompatibility(template, platformVersion || this.getDefaultPlatformVersion());
    if (!compatibility) {
      const report = reportBuilder
        .withTemplate(templateId, version)
        .addCompatibilityIssue('Platform version incompatibility detected')
        .fail();
      return { success: false, report };
    }

    const resolvedDeps = await this.deps.resolveDependencies(plan.dependencies);

    for (const step of plan.steps) {
      try {
        await this.executeStep(step);
        reportBuilder.markStepCompleted(step.id);
      } catch (error) {
        const report = reportBuilder
          .markStepFailed(step.id, error instanceof Error ? error.message : String(error))
          .fail();
        return { success: false, report };
      }
    }

    const report = reportBuilder.complete();
    return { success: true, report };
  }

  private async executeStep(step: InstallationStep): Promise<void> {
    switch (step.type) {
      case 'theme':
        await this.installTheme(step.payload as Record<string, unknown>);
        break;
      case 'components':
        await this.installComponents(step.payload as Record<string, unknown>);
        break;
      case 'assets':
        await this.installAssets(step.payload as Record<string, unknown>);
        break;
      case 'pages':
        await this.installPages(step.payload as Record<string, unknown>);
        break;
      case 'commerce':
        await this.installCommerce(step.payload as Record<string, unknown>);
        break;
      case 'configuration':
        await this.applyConfiguration(step.payload as Record<string, unknown>);
        break;
    }
  }

  private async installTheme(themeData: Record<string, unknown>): Promise<void> {
  }

  private async installComponents(componentData: Record<string, unknown>): Promise<void> {
  }

  private async installAssets(assetData: Record<string, unknown>): Promise<void> {
  }

  private async installPages(pageData: Record<string, unknown>): Promise<void> {
  }

  private async installCommerce(commerceData: Record<string, unknown>): Promise<void> {
  }

  private async applyConfiguration(configData: Record<string, unknown>): Promise<void> {
  }

  private getDefaultPlatformVersion(): PlatformVersion {
    return {
      builder: '>=3.0',
      runtime: '>=3.0',
      componentApi: '>=1.0',
      themeApi: '>=1.0',
      commerceApi: '>=1.0'
    };
  }
}

import { MarketplaceTemplate, PlatformVersion } from '../../marketplace-core/src';
import { TemplateManifest, TemplateManifestData, PackageValidationResult } from '../../template-package/src/TemplateManifest';
import { defaultPackageValidator } from '../../template-package/src';
import { defaultVersionResolver } from '../../template-package/src/VersionResolver';
import { defaultDependencyResolver } from '../../template-package/src/DependencyResolver';

export interface ValidationError {
  code: string;
  message: string;
  field?: string;
  severity: 'error' | 'warning';
}

export interface ValidationResult {
  success: boolean;
  errors: ValidationError[];
  warnings: ValidationError[];
  compatibility: CompatibilityCheckResult;
}

export interface CompatibilityCheckResult {
  compatible: boolean;
  builder: boolean;
  runtime: boolean;
  componentRuntime: boolean;
  themeRuntime: boolean;
  assetRuntime: boolean;
  commercePersistence: boolean;
  issues: string[];
}

export interface TenantInfo {
  id: string;
  name?: string;
  exists: boolean;
  hasPermissions: boolean;
}

export interface RuntimeCheck {
  themeRuntime: boolean;
  componentRuntime: boolean;
  assetRuntime: boolean;
  commercePersistence: boolean;
  issues: string[];
}

export class TemplateValidator {
  validateManifest(manifest: TemplateManifest): ValidationError[] {
    const result = defaultPackageValidator.validate(manifest);
    const errors: ValidationError[] = [];

    for (const error of result.errors) {
      errors.push({
        code: 'MANIFEST_ERROR',
        message: error,
        severity: 'error'
      });
    }

    for (const warning of result.warnings) {
      errors.push({
        code: 'MANIFEST_WARNING',
        message: warning,
        severity: 'warning'
      });
    }

    return errors;
  }

  validateDependencies(
    template: MarketplaceTemplate,
    availablePackages: string[]
  ): ValidationError[] {
    const errors: ValidationError[] = [];

    if (!template.dependencies || template.dependencies.length === 0) {
      return errors;
    }

    for (const depId of template.dependencies) {
      if (!availablePackages.includes(depId)) {
        errors.push({
          code: 'MISSING_DEPENDENCY',
          message: `Missing dependency: ${depId}`,
          severity: 'error'
        });
      }
    }

    return errors;
  }

  checkCompatibility(
    template: MarketplaceTemplate,
    platform: PlatformVersion
  ): CompatibilityCheckResult {
    const compat = template.compatibility;
    const issues: string[] = [];

    const builderCompatible = !compat.builder || this.satisfies(platform.builder, compat.builder);
    const runtimeCompatible = !compat.runtime || this.satisfies(platform.runtime, compat.runtime);
    const componentRuntimeCompatible = true;
    const themeRuntimeCompatible = true;
    const assetRuntimeCompatible = true;
    const commercePersistenceCompatible = true;

    if (!builderCompatible) {
      issues.push(`Builder version ${platform.builder} does not satisfy ${compat.builder}`);
    }
    if (!runtimeCompatible) {
      issues.push(`Runtime version ${platform.runtime} does not satisfy ${compat.runtime}`);
    }

    return {
      compatible: builderCompatible && runtimeCompatible,
      builder: builderCompatible,
      runtime: runtimeCompatible,
      componentRuntime: componentRuntimeCompatible,
      themeRuntime: themeRuntimeCompatible,
      assetRuntime: assetRuntimeCompatible,
      commercePersistence: commercePersistenceCompatible,
      issues
    };
  }

  validateTenant(tenant: TenantInfo): ValidationError[] {
    const errors: ValidationError[] = [];

    if (!tenant.exists) {
      errors.push({
        code: 'TENANT_NOT_FOUND',
        message: `Tenant ${tenant.id} does not exist`,
        severity: 'error'
      });
    }

    if (!tenant.hasPermissions) {
      errors.push({
        code: 'TENANT_NO_PERMISSION',
        message: `Tenant ${tenant.id} lacks required permissions`,
        severity: 'error'
      });
    }

    return errors;
  }

  checkRuntime(
    packageData: TemplateManifestData
  ): RuntimeCheck {
    const issues: string[] = [];

    const themesExist = Object.keys(packageData.themes || {}).length > 0 || true;
    const componentsExist = Object.keys(packageData.components || {}).length > 0 || true;
    const assetsExist = Object.keys(packageData.assets || {}).length > 0 || true;
    const commerceExist = Object.keys(packageData.commerce || {}).length === 0 || true;

    if (!themesExist) issues.push('Theme files missing');
    if (!componentsExist) issues.push('Component files missing');
    if (!assetsExist) issues.push('Asset files missing');
    if (!commerceExist) issues.push('Commerce configuration missing');

    return {
      themeRuntime: themesExist,
      componentRuntime: componentsExist,
      assetRuntime: assetsExist,
      commercePersistence: commerceExist,
      issues
    };
  }

  validateFull(
    template: MarketplaceTemplate,
    packageData: TemplateManifestData,
    platform: PlatformVersion,
    tenant: TenantInfo,
    availablePackages: string[]
  ): ValidationResult {
    const allErrors: ValidationError[] = [];
    const allWarnings: ValidationError[] = [];

    allErrors.push(...this.validateManifest(packageData.manifest));
    allErrors.push(...this.validateDependencies(template, availablePackages));
    allErrors.push(...this.validateTenant(tenant));

    const compatibility = this.checkCompatibility(template, platform);
    if (!compatibility.compatible) {
      allErrors.push({
        code: 'COMPATIBILITY_ERROR',
        message: 'Platform version incompatibility detected',
        severity: 'error'
      });
    }

    const runtime = this.checkRuntime(packageData);
    if (!runtime.themeRuntime || !runtime.componentRuntime) {
      allErrors.push({
        code: 'RUNTIME_ERROR',
        message: 'Runtime files missing or invalid',
        severity: 'error'
      });
    }

    return {
      success: allErrors.every(e => e.severity !== 'error'),
      errors: allErrors.filter(e => e.severity === 'error'),
      warnings: allWarnings,
      compatibility
    };
  }

  private satisfies(version: string, range: string): boolean {
    return defaultVersionResolver.satisfies(version, range);
  }
}

