// TemplateRuntime.ts
// C6.3-D: Template Runtime Engine
// Renders StoreConfig pages/sections into HTML using ThemeRuntime and RendererEngine.

import { StoreConfig } from '../../runtime-core/src/RuntimeContext';
import { RuntimeSection, RuntimePage } from '../../runtime-core/src/RuntimeSection';
import { ThemeRuntime } from './ThemeRuntime';
import { RendererEngine, StorefrontRenderContext } from './RendererEngine';
import { PlatformEventBusImpl } from '../../platform-core/src/events/PlatformEventBus';
import { ConsolePlatformLogger } from '../../platform-core/src/logger/Logger';
import { EventRegistry } from '../../platform-core/src/events/EventRegistry';
import { SimpleAssetResolver } from '../../asset-manager-core/src/AssetResolver';
import { AssetReference } from '../../asset-manager-core/src/AssetReference';

export interface SectionRenderContext {
  tenantId: string;
  themeId: string;
  tokens: StorefrontRenderContext['tokens'];
  locale: string;
  currency: string;
  assets: SimpleAssetResolver;
}

export interface SectionRenderer {
  type: string;
  render(section: RuntimeSection, context: SectionRenderContext): Promise<string>;
}

export class TemplateRuntime {
  private readonly eventBus: PlatformEventBusImpl;
  private readonly logger: ConsolePlatformLogger;
  private readonly themeRuntime: ThemeRuntime;
  private readonly rendererEngine: RendererEngine;
  private readonly sectionRenderers = new Map<string, SectionRenderer>();
  private readonly assets: SimpleAssetResolver;

  constructor(options: {
    eventBus: PlatformEventBusImpl;
    logger: ConsolePlatformLogger;
    themeRuntime: ThemeRuntime;
    rendererEngine: RendererEngine;
    assets: SimpleAssetResolver;
  }) {
    this.eventBus = options.eventBus;
    this.logger = options.logger;
    this.themeRuntime = options.themeRuntime;
    this.rendererEngine = options.rendererEngine;
    this.assets = options.assets;

    const templateEvents = [
      'Template.RenderStarted',
      'Template.SectionRendered',
      'Template.PageRendered',
      'Template.RenderCompleted',
      'Template.RenderFailed',
    ];
    for (const evt of templateEvents) {
      EventRegistry.register(evt);
    }

    this.registerDefaultSectionRenderers();
  }

  private registerDefaultSectionRenderers() {
    this.sectionRenderers.set('Header', {
      type: 'Header',
      render: async (section, context) => {
        const title = (section.props?.title as string) || context.locale;
        return `<header><h1>${title}</h1></header>`;
      },
    });

    this.sectionRenderers.set('Footer', {
      type: 'Footer',
      render: async (section, context) => {
        const copyright = (section.props?.copyright as string) || '';
        return `<footer>${copyright}</footer>`;
      },
    });

    this.sectionRenderers.set('Hero', {
      type: 'Hero',
      render: async (section, context) => {
        const heading = (section.props?.heading as string) || '';
        const text = (section.props?.text as string) || '';
        const imageRef = section.props?.image as { id: string; type: string } | undefined;
        let imageHtml = '';
        if (imageRef) {
          const ref = AssetReference.fromAsset(imageRef as any);
          const url = await context.assets.resolve(ref);
          imageHtml = `<img src="${url}" alt="${heading}" />`;
        }
        return `<section class="hero"><h2>${heading}</h2><p>${text}</p>${imageHtml}</section>`;
      },
    });

    this.sectionRenderers.set('ProductGrid', {
      type: 'ProductGrid',
      render: async (section, context) => {
        const limit = (section.props?.limit as number) || 8;
        return `<section class="product-grid"><p>Products (limit: ${limit})</p></section>`;
      },
    });

    this.sectionRenderers.set('FeatureList', {
      type: 'FeatureList',
      render: async (section, context) => {
        const items = Array.isArray(section.props?.items) ? section.props.items : [];
        const listItems = items.map((item: string) => `<li>${item}</li>`).join('');
        return `<section class="features"><ul>${listItems}</ul></section>`;
      },
    });

    this.sectionRenderers.set('ContactForm', {
      type: 'ContactForm',
      render: async (section, context) => {
        const email = (section.props?.email as string) || '';
        return `<section class="contact"><a href="mailto:${email}">${email}</a></section>`;
      },
    });
  }

  public registerSectionRenderer(renderer: SectionRenderer) {
    this.sectionRenderers.set(renderer.type, renderer);
  }

  public async renderSection(section: RuntimeSection, context: SectionRenderContext): Promise<string> {
    const renderer = this.sectionRenderers.get(section.type);
    if (!renderer) {
      throw new Error(`No section renderer registered for type: ${section.type}`);
    }
    return renderer.render(section, context);
  }

  public async renderPage(
    tenantId: string,
    themeId: string,
    page: RuntimePage,
    layoutTemplate: string,
    correlationId?: string
  ): Promise<string> {
    const cid = correlationId || `tpl_page_${Date.now()}`;
    await this.eventBus.publish({
      eventId: `evt_tpl_start_${Math.random().toString(36).substr(2, 9)}`,
      eventType: 'Template.RenderStarted',
      timestamp: new Date().toISOString(),
      correlationId: cid,
      tenantId,
      payload: { pageId: page.id },
    });

    const tokens = {
      primaryColor: '#8b5cf6',
      secondaryColor: '#d946ef',
      backgroundColor: '#050508',
      fontFamily: 'Inter',
      borderRadius: '4px',
    };

    const context: SectionRenderContext = {
      tenantId,
      themeId,
      tokens,
      locale: 'pl_PL',
      currency: 'PLN',
      assets: this.assets,
    };

    const slots: Record<string, { html: string; componentName: string; props: Record<string, any> }> = {};
    const sortedSections = [...page.sections].sort((a, b) => a.order - b.order);

    for (const section of sortedSections) {
      if (!section.visible) continue;

      const renderer = this.sectionRenderers.get(section.type);
      if (!renderer) {
        this.logger.warn({
          message: `No section renderer registered for type: ${section.type}`,
          correlationId: cid,
          tenantId,
        });
        continue;
      }

      const renderedHtml = await renderer.render(section, context);
      slots[section.id] = {
        html: renderedHtml,
        componentName: section.type,
        props: section.props,
      };

      await this.eventBus.publish({
        eventId: `evt_tpl_sec_${Math.random().toString(36).substr(2, 9)}`,
        eventType: 'Template.SectionRendered',
        timestamp: new Date().toISOString(),
        correlationId: cid,
        tenantId,
        payload: { sectionId: section.id, sectionType: section.type },
      });
    }

    const renderContext: StorefrontRenderContext = {
      tenantId,
      shopName: page.name,
      locale: context.locale,
      currency: context.currency,
      themeId,
      tokens,
      page: {
        title: page.name,
        type: 'home',
        data: {},
      },
    };

    const finalHtml = await this.rendererEngine.renderPage(renderContext, layoutTemplate, slots, cid);

    await this.eventBus.publish({
      eventId: `evt_tpl_done_${Math.random().toString(36).substr(2, 9)}`,
      eventType: 'Template.PageRendered',
      timestamp: new Date().toISOString(),
      correlationId: cid,
      tenantId,
      payload: { pageId: page.id },
    });

    return finalHtml;
  }
}

// ThemeProvider.ts
// Implements TenantCompositionDetailsProvider for theme management
// This is the bridge between tenant data and the theme runtime system

import { TenantCompositionDetailsProvider } from '../../runtime-composition/src/RuntimeCompositionEngine';
import { ThemeResolver } from '../../theme-runtime/src/ThemeResolver';
import { ThemeManifest } from '../../theme-runtime/src/ThemeManifest';

/**
 * Default theme configuration for tenants without custom themes
 */
const DEFAULT_THEME: ThemeManifest = {
  id: 'default',
  name: 'WEB FACTOR Default',
  version: '1.0.0',
  author: 'WEB FACTOR',
  tokens: {
    primaryColor: '#8b5cf6',
    secondaryColor: '#d946ef',
    backgroundColor: '#050508',
    fontFamily: 'Inter',
    borderRadius: '4px',
  },
  layouts: ['default'],
  components: {
    header: { name: 'Header', type: 'layout' },
    footer: { name: 'Footer', type: 'layout' },
    main: { name: 'MainContent', type: 'layout' },
  },
};

/**
 * Theme configuration per tenant (in production, this would come from database)
 * For now, we maintain an in-memory registry that can be extended
 */
const TENANT_THEME_REGISTRY: Map<string, { id: string; settings?: Record<string, any> }> = new Map();

/**
 * ThemeProvider implements TenantCompositionDetailsProvider
 * It provides theme data for runtime composition based on tenant configuration
 */
export class ThemeProvider implements TenantCompositionDetailsProvider {
  private readonly themeResolver: ThemeResolver;
  private readonly packageRegistry: Map<string, string[]>;
  private readonly configRegistry: Map<string, Record<string, any>>;

  constructor(themeResolver: ThemeResolver) {
    this.themeResolver = themeResolver;
    this.packageRegistry = new Map();
    this.configRegistry = new Map();

    // Register default theme
    this.themeResolver.registerTheme(DEFAULT_THEME);
  }

  /**
   * Get packages configured for a tenant
   * In production, this would query the database
   */
  async getPackagesForTenant(tenantId: string): Promise<string[]> {
    // Default packages for all tenants
    const defaultPackages = ['commerce', 'theme'];

    // Check for tenant-specific packages
    const tenantPackages = this.packageRegistry.get(tenantId);
    if (tenantPackages) {
      return [...defaultPackages, ...tenantPackages];
    }

    return defaultPackages;
  }

  /**
   * Get theme configuration for a tenant
   * This is the core method that enables theme runtime engine
   */
  async getThemeForTenant(tenantId: string): Promise<{ id: string; settings?: Record<string, any> }> {
    // Check if tenant has a custom theme configured
    const tenantTheme = TENANT_THEME_REGISTRY.get(tenantId);
    if (tenantTheme) {
      return tenantTheme;
    }

    // Return default theme for tenants without custom configuration
    return {
      id: DEFAULT_THEME.id,
      settings: {
        primaryColor: DEFAULT_THEME.tokens.primaryColor,
        secondaryColor: DEFAULT_THEME.tokens.secondaryColor,
      },
    };
  }

  /**
   * Get configuration for a tenant
   * Merges global defaults with tenant-specific overrides
   */
  async getConfigurationForTenant(tenantId: string): Promise<Record<string, any>> {
    const tenantConfig = this.configRegistry.get(tenantId) || {};

    return {
      siteName: `${tenantId}-store`,
      locale: 'pl_PL',
      currency: 'PLN',
      ...tenantConfig,
    };
  }

  /**
   * Register a custom theme for a tenant
   * This enables tenant-specific theme customization
   */
  public registerTenantTheme(tenantId: string, themeId: string, settings?: Record<string, any>): void {
    TENANT_THEME_REGISTRY.set(tenantId, { id: themeId, settings });
  }

  /**
   * Register additional packages for a tenant
   */
  public registerTenantPackages(tenantId: string, packages: string[]): void {
    const existing = this.packageRegistry.get(tenantId) || [];
    this.packageRegistry.set(tenantId, [...existing, ...packages]);
  }

  /**
   * Register custom configuration for a tenant
   */
  public registerTenantConfig(tenantId: string, config: Record<string, any>): void {
    const existing = this.configRegistry.get(tenantId) || {};
    this.configRegistry.set(tenantId, { ...existing, ...config });
  }

  /**
   * Clear all tenant-specific configurations
   * Useful for testing
   */
  public clearAll(): void {
    TENANT_THEME_REGISTRY.clear();
    this.packageRegistry.clear();
    this.configRegistry.clear();
  }
}

/**
 * Singleton instance for the application
 * Prevents multiple initializations
 */
let themeProviderInstance: ThemeProvider | null = null;

/**
 * Get or create the ThemeProvider singleton
 */
export function getThemeProvider(themeResolver: ThemeResolver): ThemeProvider {
  if (!themeProviderInstance) {
    themeProviderInstance = new ThemeProvider(themeResolver);
  }
  return themeProviderInstance;
}

/**
 * Reset the singleton instance (for testing)
 */
export function resetThemeProvider(): void {
  themeProviderInstance = null;
}

import { PlatformEventBusImpl } from '../../platform-core/src/events/PlatformEventBus';
import { ConsolePlatformLogger } from '../../platform-core/src/logger/Logger';
import { EventRegistry } from '../../platform-core/src/events/EventRegistry';
import { ThemeManifest } from './ThemeManifest';
import { ComponentRegistry, ThemeComponent } from './ComponentRegistry';
import { TenantSecurityException } from '../../commerce-engine/src/CommerceEngine';

export class ThemeRuntime {
  private readonly eventBus: PlatformEventBusImpl;
  private readonly logger: ConsolePlatformLogger;

  // Tenant-isolated registries and active themes
  private readonly activeThemes = new Map<string, ThemeManifest>();
  private readonly registries = new Map<string, ComponentRegistry>();

  constructor(options: {
    eventBus: PlatformEventBusImpl;
    logger: ConsolePlatformLogger;
  }) {
    this.eventBus = options.eventBus;
    this.logger = options.logger;

    // Register all theme events
    const themeEvents = [
      'Theme.Loaded',
      'Theme.ComponentResolved',
      'Theme.RenderStarted',
      'Theme.RenderCompleted',
      'Theme.Failed',
    ];
    for (const evt of themeEvents) {
      EventRegistry.register(evt);
    }
  }

  /**
   * Loads and initializes a theme for a tenant
   */
  public async loadTheme(tenantId: string, manifest: ThemeManifest, correlationId?: string): Promise<void> {
    const cid = correlationId || `theme_load_${Date.now()}`;

    // Store active theme
    this.activeThemes.set(tenantId, manifest);

    // Initialize clean registry for this tenant
    const registry = new ComponentRegistry();
    this.registries.set(tenantId, registry);

    await this.eventBus.publish({
      eventId: `evt_thm_load_${Math.random().toString(36).substr(2, 9)}`,
      eventType: 'Theme.Loaded',
      timestamp: new Date().toISOString(),
      correlationId: cid,
      tenantId,
      payload: { themeId: manifest.id },
    });
  }

  /**
   * Get active theme manifest for a tenant
   */
  public async getThemeManifest(tenantId: string): Promise<ThemeManifest> {
    const manifest = this.activeThemes.get(tenantId);
    if (!manifest) {
      throw new Error(`No active theme loaded for tenant: '${tenantId}'`);
    }
    return manifest;
  }

  /**
   * Register a theme component for a tenant
   */
  public registerComponent(tenantId: string, componentName: string, component: ThemeComponent): void {
    const registry = this.registries.get(tenantId);
    if (!registry) {
      throw new Error(`No active theme loaded for tenant '${tenantId}'. Load theme before registering components.`);
    }
    registry.register(componentName, component);
  }

  /**
   * Renders a component using the tenant's registry
   */
  public async renderComponent(
    tenantId: string,
    componentName: string,
    props: Record<string, any>,
    correlationId?: string
  ): Promise<string> {
    const cid = correlationId || `theme_rnd_${Date.now()}`;

    await this.eventBus.publish({
      eventId: `evt_thm_rnd_start_${Math.random().toString(36).substr(2, 9)}`,
      eventType: 'Theme.RenderStarted',
      timestamp: new Date().toISOString(),
      correlationId: cid,
      tenantId,
      payload: { componentName },
    });

    try {
      const manifest = this.activeThemes.get(tenantId);
      if (!manifest) {
        throw new Error(`No theme loaded for tenant: '${tenantId}'`);
      }

      const registry = this.registries.get(tenantId);
      if (!registry) {
        throw new Error(`No component registry found for tenant: '${tenantId}'`);
      }

      const component = registry.resolve(componentName);

      await this.eventBus.publish({
        eventId: `evt_thm_comp_res_${Math.random().toString(36).substr(2, 9)}`,
        eventType: 'Theme.ComponentResolved',
        timestamp: new Date().toISOString(),
        correlationId: cid,
        tenantId,
        payload: { componentName, type: component.type },
      });

      const html = component.render(props);

      await this.eventBus.publish({
        eventId: `evt_thm_rnd_comp_${Math.random().toString(36).substr(2, 9)}`,
        eventType: 'Theme.RenderCompleted',
        timestamp: new Date().toISOString(),
        correlationId: cid,
        tenantId,
        payload: { componentName },
      });

      return html;
    } catch (err: any) {
      await this.eventBus.publish({
        eventId: `evt_thm_rnd_fail_${Math.random().toString(36).substr(2, 9)}`,
        eventType: 'Theme.Failed',
        timestamp: new Date().toISOString(),
        correlationId: cid,
        tenantId,
        payload: { componentName, error: err.message },
      });
      throw err;
    }
  }
}

