  const mockDbInst = {
    stores: [] as any[]
  };
  return {
    mockDb: mockDbInst,
    clearMockDb: () => {
      mockDbInst.stores = [];
    },
    getServiceSupabase: () => {
      let pendingUpdates: any = null;
      const queryChain = {
        eq: () => queryChain,
        order: () => queryChain,
        select: () => queryChain,
        maybeSingle: () => Promise.resolve({ data: mockDbInst.stores[0] || null, error: null }),
        single: () => {
          if (pendingUpdates) {
            const store = mockDbInst.stores[0];
            if (store) {
              Object.assign(store, pendingUpdates);
            }
          }
          return Promise.resolve({ data: mockDbInst.stores[0] || null, error: null });
        }
      };
      return {
        from: (table: string) => ({
          select: () => queryChain,
          insert: (row: any) => ({
            select: () => ({
              single: () => {
                mockDbInst.stores.push(row);
                return Promise.resolve({ data: row, error: null });
              }
            })
          }),
          update: (updates: any) => {
            pendingUpdates = updates;
            return queryChain;
          }
        })
      };
    }
  };
});

