function makeRequest(body: object, correlationId = 'corr-onb-test') {
  return new Request('http://localhost', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', 'x-correlation-id': correlationId },
    body: JSON.stringify(body),
  }) as any;
}

