// ---------------------------------------------------------------------------
// BuilderApp — public entry point (creates BuilderProvider)
// ---------------------------------------------------------------------------

export interface BuilderAppProps {
  storeId: string
  /** Initial BuilderDocument loaded from API */
  initialDocument?: BuilderDocument
  onSave?: (doc: BuilderDocument) => Promise<void>
}

/**
 * Default document factory — used when no server document is available
 * (e.g. new store, or API not yet connected)
 */
function createDefaultDocument(storeId: string): BuilderDocument {
  const metadata: BuilderMetadata = {
    storeName: 'Mój Sklep',
    storeSlug: storeId,
    locale: 'pl',
    currency: 'PLN',
  }
  const theme: Partial<BuilderTheme> = {
    primaryColor: '#7c3aed',
    secondaryColor: '#d946ef',
    font: 'Inter',
  }
  return createBuilderDocument({ id: storeId, tenantId: 'local', metadata, theme })
}

export function BuilderApp({ storeId, initialDocument, onSave }: BuilderAppProps) {
  const [saving, setSaving] = useState(false)
  const [savedDoc, setSavedDoc] = useState<BuilderDocument | null>(null)

  const doc = savedDoc ?? initialDocument ?? createDefaultDocument(storeId)

  const handleSave = async (currentDoc: BuilderDocument) => {
    if (saving) return
    setSaving(true)
    try {
      await onSave?.(currentDoc)
      setSavedDoc(currentDoc)
    } catch (err) {
      console.error('Builder save error:', err)
    } finally {
      setSaving(false)
    }
  }

  return (
    <BuilderProvider document={doc}>
      <BuilderShellWithSave storeId={storeId} onSave={handleSave} saving={saving} />
    </BuilderProvider>
  )
}

// Inner wrapper to access useBuilder() for save
function BuilderShellWithSave({
  storeId, onSave, saving,
}: {
  storeId: string
  onSave: (doc: BuilderDocument) => Promise<void>
  saving: boolean
}) {
  const { document } = useBuilder()
  return (
    <BuilderShell
      storeId={storeId}
      onSave={() => onSave(document)}
      saving={saving}
    />
  )
}

'use client'

/**
 * BuilderCanvas — C6.2-C
 *
 * The central preview area of the Visual Builder.
 *
 * ARCHITECTURAL PRINCIPLE (as specified in C6.2):
 *   Canvas does NOT render its own components.
 *   It renders an HTML iframe that displays what the Runtime would show.
 *
 *   EDIT MODE flow:
 *     BuilderDocument → compile() → SectionRenderers (existing preview HTML)
 *
 *   The iframe receives document updates via the PreviewChannel (MemoryChannel).
 *   In this C6.2 implementation we use a lightweight in-canvas preview
 *   (section wireframes with selection overlay) since the full iframe
 *   Runtime integration is wired in C6.2-C proper.
 *
 * What this component does:
 *   - Renders each SectionNode as a selectable "preview block"
 *   - Shows selection ring around the selected section
 *   - Shows hover overlay with section type + quick actions
 *   - Simulates viewport width (desktop/tablet/mobile)
 *   - Clicking a section → dispatch(CANVAS SELECT_SECTION)
 */

import { useCallback, useState } from 'react'
import { motion } from 'framer-motion'
import {
  ArrowUp, ArrowDown, Trash2, Copy, Plus,
  Layers, Package, Star, FileText, LayoutDashboard, Grid,
} from 'lucide-react'
import { useBuilder } from '../state/BuilderProvider'
import { SectionNode } from '../../../../packages/builder-core/src/BuilderDocument'
import { VIEWPORT_PRESETS, DEFAULT_GRID_CONFIG } from '../../../../packages/builder-core/src/CanvasState'
import { GridSystem } from '../../../../packages/builder-core/src/GridSystem'

// ---------------------------------------------------------------------------
// Section type → icon mapping (used for wireframe preview)
// ---------------------------------------------------------------------------

const SECTION_ICONS: Record<string, React.ReactNode> = {
  hero:               <LayoutDashboard className="w-8 h-8 text-violet-400" />,
  navbar:             <LayoutDashboard className="w-8 h-8 text-slate-400" />,
  footer:             <LayoutDashboard className="w-8 h-8 text-slate-400" />,
  'product-grid':     <Package className="w-8 h-8 text-amber-400" />,
  'featured-products':<Package className="w-8 h-8 text-amber-400" />,
  'category-grid':    <Grid className="w-8 h-8 text-emerald-400" />,
  gallery:            <Grid className="w-8 h-8 text-blue-400" />,
  testimonials:       <Star className="w-8 h-8 text-yellow-400" />,
  newsletter:         <FileText className="w-8 h-8 text-pink-400" />,
  content:            <FileText className="w-8 h-8 text-slate-400" />,
  container:          <Layers className="w-8 h-8 text-violet-300" />,
}

function sectionIcon(type: string) {
  return SECTION_ICONS[type] ?? <Layers className="w-8 h-8 text-slate-500" />
}

// ---------------------------------------------------------------------------
// Section heights for wireframe preview (approximate)
// ---------------------------------------------------------------------------

const SECTION_HEIGHTS: Record<string, number> = {
  navbar: 64,
  hero: 320,
  'product-grid': 380,
  'featured-products': 300,
  'category-grid': 240,
  gallery: 280,
  testimonials: 320,
  newsletter: 180,
  footer: 200,
  content: 200,
  container: 160,
}

function sectionHeight(type: string): number {
  return SECTION_HEIGHTS[type] ?? 160
}

// ---------------------------------------------------------------------------
// Grid Overlay
// ---------------------------------------------------------------------------

const gridSystem = new GridSystem(DEFAULT_GRID_CONFIG)

function findParent(sections: SectionNode[], childId: string): string | null {
  for (const section of sections) {
    if (section.children.some(child => child.id === childId)) {
      return section.id
    }
    const found = findParent(section.children, childId)
    if (found) return found
  }
  return null
}

function GridOverlay({ width }: { width: number }) {
  const config = gridSystem.getConfig()
  if (!config.showGuides) return null

  const columnWidth = (width - config.margin * 2 - config.gutter * (config.columns - 1)) / config.columns

  const lines = []
  for (let i = 0; i < config.columns; i++) {
    const x = config.margin + i * (columnWidth + config.gutter)
    lines.push(
      <div
        key={i}
        className="absolute top-0 bottom-0 w-px bg-violet-500/10"
        style={{ left: x }}
      />
    )
    if (i < config.columns - 1) {
      const gutterX = x + columnWidth
      lines.push(
        <div
          key={`gutter-${i}`}
          className="absolute top-0 bottom-0 w-px bg-violet-500/5"
          style={{ left: gutterX }}
        />
      )
    }
  }

  return <>{lines}</>
}

// ---------------------------------------------------------------------------
// Section wireframe block
// ---------------------------------------------------------------------------

interface SectionBlockProps {
  node: SectionNode
  pageId: string
  index: number
  total: number
  isSelected: boolean
  isHovered: boolean
  onSelect: () => void
  onHover: (id: string | null) => void
}

const RESIZE_HANDLES = [
  { id: 'nw', cursor: 'nwse-resize', className: '-top-1.5 -left-1.5' },
  { id: 'n',  cursor: 'ns-resize',   className: '-top-1.5 left-1/2 -translate-x-1/2' },
  { id: 'ne', cursor: 'nesw-resize', className: '-top-1.5 -right-1.5' },
  { id: 'e',  cursor: 'ew-resize',   className: '-right-1.5 top-1/2 -translate-y-1/2' },
  { id: 'se', cursor: 'nwse-resize', className: '-bottom-1.5 -right-1.5' },
  { id: 's',  cursor: 'ns-resize',   className: '-bottom-1.5 left-1/2 -translate-x-1/2' },
  { id: 'sw', cursor: 'nesw-resize', className: '-bottom-1.5 -left-1.5' },
  { id: 'w',  cursor: 'ew-resize',   className: '-left-1.5 top-1/2 -translate-y-1/2' },
]

function SectionBlock({
  node, pageId, index, total, isSelected, isHovered, onSelect, onHover,
}: SectionBlockProps) {
  const { dispatch } = useBuilder()

  const handleMoveUp = (e: React.MouseEvent) => {
    e.stopPropagation()
    if (index === 0) return
    dispatch({ type: 'MOVE_SECTION', pageId, fromIndex: index, toIndex: index - 1 })
  }

  const handleMoveDown = (e: React.MouseEvent) => {
    e.stopPropagation()
    if (index === total - 1) return
    dispatch({ type: 'MOVE_SECTION', pageId, fromIndex: index, toIndex: index + 1 })
  }

  const handleDelete = (e: React.MouseEvent) => {
    e.stopPropagation()
    dispatch({ type: 'REMOVE_SECTION', pageId, sectionId: node.id })
  }

  const handleDuplicate = (e: React.MouseEvent) => {
    e.stopPropagation()
    dispatch({ type: 'DUPLICATE_SECTION', pageId, sectionId: node.id })
  }

  const height = sectionHeight(node.type)
  const showOverlay = isSelected || isHovered

  return (
    <div
      onClick={onSelect}
      onMouseEnter={() => onHover(node.id)}
      onMouseLeave={() => onHover(null)}
      style={{ minHeight: height }}
      className={`relative group cursor-pointer transition-all duration-150 select-none
        ${!node.visible ? 'opacity-30' : ''}
        ${isSelected
          ? 'ring-2 ring-violet-500 ring-inset'
          : isHovered
            ? 'ring-1 ring-violet-500/40 ring-inset'
            : ''
        }
      `}
    >
      {/* Wireframe content */}
      <div className={`w-full h-full flex flex-col items-center justify-center gap-3 px-8 py-6
        bg-white/[0.02] border-b border-white/5`}
        style={{ minHeight: height }}
      >
        <div className={`p-3 rounded-2xl ${isSelected ? 'bg-violet-500/20' : 'bg-white/5'} transition-colors`}>
          {sectionIcon(node.type)}
        </div>
        <div className="text-center">
          <div className="font-semibold text-white text-sm">{node.label}</div>
          <div className="text-[11px] text-slate-600 font-mono mt-0.5">{node.type}</div>
          {node.locked && (
            <div className="text-[11px] text-amber-400 mt-1 flex items-center justify-center gap-1">
              🔒 zablokowana
            </div>
          )}
          {!node.visible && (
            <div className="text-[11px] text-slate-500 mt-1 flex items-center justify-center gap-1">
              👁 ukryta
            </div>
          )}
        </div>

        {/* Children indicator for containers */}
        {node.children.length > 0 && (
          <div className="text-[11px] text-slate-500 flex items-center gap-1">
            <Layers className="w-3 h-3" />
            {node.children.length} komponent{node.children.length > 1 ? 'y' : ''}
          </div>
        )}
      </div>

      {/* Hover / selected toolbar */}
      {showOverlay && (
        <div className="absolute top-2 left-0 right-0 flex items-center justify-between px-3 z-10 pointer-events-none">
          {/* Section label chip */}
          <div className="flex items-center gap-1 bg-violet-600 text-white text-[11px] font-bold
                          px-2.5 py-1 rounded-full pointer-events-auto shadow-lg">
            {node.label}
            <span className="ml-1 text-violet-200 font-normal">#{index + 1}</span>
          </div>

          {/* Action toolbar */}
          <div className="flex items-center gap-1 bg-[#080a14]/90 backdrop-blur rounded-xl p-1
                          border border-white/10 shadow-xl pointer-events-auto">
            <button
              onClick={handleMoveUp}
              disabled={index === 0}
              className="p-1.5 rounded-lg hover:bg-white/10 text-slate-400 hover:text-white
                         disabled:opacity-30 disabled:cursor-not-allowed transition-all"
              title="Przesuń w górę"
            >
              <ArrowUp className="w-3.5 h-3.5" />
            </button>
            <button
              onClick={handleMoveDown}
              disabled={index === total - 1}
              className="p-1.5 rounded-lg hover:bg-white/10 text-slate-400 hover:text-white
                         disabled:opacity-30 disabled:cursor-not-allowed transition-all"
              title="Przesuń w dół"
            >
              <ArrowDown className="w-3.5 h-3.5" />
            </button>
            <div className="w-px h-4 bg-white/10 mx-0.5" />
            <button
              onClick={handleDuplicate}
              className="p-1.5 rounded-lg hover:bg-violet-500/20 text-slate-400 hover:text-violet-300 transition-all"
              title="Duplikuj"
            >
              <Copy className="w-3.5 h-3.5" />
            </button>
            <button
              onClick={handleDelete}
              className="p-1.5 rounded-lg hover:bg-red-500/20 text-slate-400 hover:text-red-400 transition-all"
              title="Usuń"
            >
              <Trash2 className="w-3.5 h-3.5" />
            </button>
          </div>
        </div>
      )}

      {/* Parent breadcrumb */}
      {isSelected && node.children.length > 0 && (
        <div className="absolute -bottom-6 left-0 right-0 flex items-center gap-1 text-[10px] text-slate-500">
          <Layers className="w-3 h-3" />
          <span>Container</span>
          <span className="text-slate-600">•</span>
          <span>{node.children.length} dzieci</span>
        </div>
      )}

      {/* Resize Handles */}
      {isSelected && (
        <div className="absolute inset-0 pointer-events-none">
          {RESIZE_HANDLES.map(handle => (
            <div
              key={handle.id}
              className={`absolute w-3 h-3 bg-violet-500 border-2 border-white rounded-full pointer-events-auto cursor-${handle.cursor}`}
              style={{
                top: handle.className.includes('-top') ? '-6px' : handle.className.includes('-bottom') ? 'auto' : '50%',
                bottom: handle.className.includes('-bottom') ? '-6px' : handle.className.includes('-top') ? 'auto' : '50%',
                left: handle.className.includes('-left') ? '-6px' : handle.className.includes('-right') ? 'auto' : '50%',
                right: handle.className.includes('-right') ? '-6px' : handle.className.includes('-left') ? 'auto' : '50%',
              }}
            />
          ))}
        </div>
      )}
    </div>
  )
}

// ---------------------------------------------------------------------------
// BuilderCanvas root
// ---------------------------------------------------------------------------

interface BuilderCanvasProps {
  onAddSection?: () => void
}

export function BuilderCanvas({ onAddSection }: BuilderCanvasProps) {
  const { document, canvas, dispatch } = useBuilder()
  const [marquee, setMarquee] = useState<{ startX: number; startY: number; currentX: number; currentY: number } | null>(null)

  const activePage = document.pages.find(p =>
    canvas.selectedPageId ? p.id === canvas.selectedPageId : p.isHome
  ) ?? document.pages[0]

  const sections = activePage?.sections ?? []
  const isDragging = canvas.dragState?.isDragging ?? false

  const handleSelectSection = useCallback((sectionId: string, pageId: string) => {
    const parentId = findParent(sections, sectionId)
    const targetId = parentId || sectionId
    dispatch({
      type: 'CANVAS',
      action: { type: 'SELECT_SECTION', sectionId: targetId, pageId },
    })
  }, [dispatch, sections])

  const handleParentSelect = useCallback((sectionId: string, pageId: string) => {
    dispatch({
      type: 'CANVAS',
      action: { type: 'SELECT_SECTION', sectionId: null, pageId },
    })
  }, [dispatch])

  const handleHoverSection = useCallback((sectionId: string | null) => {
    dispatch({
      type: 'CANVAS',
      action: { type: 'HOVER_SECTION', sectionId },
    })
  }, [dispatch])

  const handleCanvasClick = useCallback(() => {
    if (canvas.selectedSectionId) {
      dispatch({ type: 'CANVAS', action: { type: 'SELECT_SECTION', sectionId: null } })
    }
  }, [dispatch, canvas.selectedSectionId])

  const handleMouseDown = useCallback((e: React.MouseEvent) => {
    if (e.button !== 0) return
    const rect = e.currentTarget.getBoundingClientRect()
    setMarquee({
      startX: e.clientX - rect.left,
      startY: e.clientY - rect.top,
      currentX: e.clientX - rect.left,
      currentY: e.clientY - rect.top,
    })
  }, [])

  const handleMouseMove = useCallback((e: React.MouseEvent) => {
    if (!marquee) return
    const rect = e.currentTarget.getBoundingClientRect()
    setMarquee({
      ...marquee,
      currentX: e.clientX - rect.left,
      currentY: e.clientY - rect.top,
    })
  }, [marquee])

  const handleMouseUp = useCallback(() => {
    if (marquee) {
      setMarquee(null)
    }
  }, [marquee])

  const viewportWidth = VIEWPORT_PRESETS[canvas.viewport.label].width

  return (
    <div
      className="flex-1 flex flex-col items-center justify-start overflow-auto bg-[#030305] p-8"
      onClick={handleCanvasClick}
    >
      {/* Canvas frame */}
      <motion.div
        key={canvas.viewport.label}
        initial={{ opacity: 0, scale: 0.98 }}
        animate={{ opacity: 1, scale: 1 }}
        transition={{ duration: 0.2 }}
        style={{ width: viewportWidth, maxWidth: '100%' }}
        className="relative bg-[#08080f] rounded-2xl shadow-2xl border border-white/10 overflow-hidden min-h-[600px]"
        onClick={e => e.stopPropagation()}
        onMouseDown={handleMouseDown}
        onMouseMove={handleMouseMove}
        onMouseUp={handleMouseUp}
      >
        {/* Grid Overlay */}
        <GridOverlay width={viewportWidth} />

        {/* Drop Indicators */}
        {isDragging && sections.map((node, index) => (
          <div
            key={`drop-${node.id}`}
            className="absolute left-0 right-0 h-0.5 bg-violet-500/50 z-20 pointer-events-none"
            style={{
              top: 0,
              transform: `translateY(${index === 0 ? 0 : '100%'})`,
            }}
          />
        ))}

        {/* Alignment Guides */}
        {isDragging && (
          <div className="absolute inset-0 pointer-events-none z-20">
            <div
              className="absolute left-0 right-0 h-px bg-violet-400/40"
              style={{ top: '0' }}
            />
            <div
              className="absolute top-0 bottom-0 w-px bg-violet-400/40"
              style={{ left: '0' }}
            />
          </div>
        )}

        {/* Locked/Hidden element guides */}
        {canvas.selection.lockedIds.length > 0 && (
          <div className="absolute inset-0 pointer-events-none z-10">
            {sections.map(node => {
              if (!canvas.selection.lockedIds.includes(node.id)) return null
              return (
                <div
                  key={`guide-${node.id}`}
                  className="absolute left-0 right-0 h-0.5 bg-amber-500/30"
                  style={{ top: '0' }}
                />
              )
            })}
          </div>
        )}

        {/* Marquee Selection */}
        {marquee && (
          <div
            className="absolute bg-violet-500/10 border border-violet-500/30 pointer-events-none z-30"
            style={{
              left: Math.min(marquee.startX, marquee.currentX),
              top: Math.min(marquee.startY, marquee.currentY),
              width: Math.abs(marquee.currentX - marquee.startX),
              height: Math.abs(marquee.currentY - marquee.startY),
            }}
          />
        )}
        {sections.length === 0 && (
          <div className="flex flex-col items-center justify-center h-full min-h-[500px] text-center p-12">
            <div className="w-20 h-20 rounded-3xl bg-violet-500/10 border border-violet-500/20
                            flex items-center justify-center mb-6">
              <Layers className="w-10 h-10 text-violet-400" />
            </div>
            <h3 className="text-lg font-bold text-white mb-2">Pusta strona</h3>
            <p className="text-slate-500 text-sm mb-8 max-w-xs">
              Dodaj pierwszą sekcję z panelu komponentów po lewej stronie
            </p>
            {onAddSection && (
              <button
                onClick={onAddSection}
                className="inline-flex items-center gap-2 px-6 py-3 rounded-xl
                           bg-gradient-to-r from-violet-600 to-fuchsia-600
                           text-white font-bold text-sm hover:shadow-lg hover:shadow-violet-500/30
                           transition-all hover:scale-105 active:scale-95"
              >
                <Plus className="w-4 h-4" />
                Dodaj sekcję
              </button>
            )}
          </div>
        )}

        {/* Sections */}
        {sections.map((node, index) => {
          const isDragSource = isDragging && canvas.dragState?.sectionId === node.id
          return (
            <div
              key={node.id}
              style={{ 
                minHeight: sectionHeight(node.type),
                opacity: isDragSource ? 0.3 : 1,
              }}
              className={`relative group cursor-pointer transition-all duration-150 select-none
                ${!node.visible ? 'opacity-30' : ''}
                ${canvas.selectedSectionId === node.id
                  ? 'ring-2 ring-violet-500 ring-inset'
                  : canvas.hoveredSectionId === node.id && canvas.selectedSectionId !== node.id
                    ? 'ring-1 ring-violet-500/40 ring-inset'
                    : ''
                }
              `}
            >
              <SectionBlock
                node={node}
                pageId={activePage!.id}
                index={index}
                total={sections.length}
                isSelected={canvas.selectedSectionId === node.id}
                isHovered={canvas.hoveredSectionId === node.id && canvas.selectedSectionId !== node.id}
                onSelect={() => handleSelectSection(node.id, activePage!.id)}
                onHover={handleHoverSection}
              />
            </div>
          )
        })}

        {/* Add section button at bottom */}
        {sections.length > 0 && onAddSection && (
          <button
            onClick={e => { e.stopPropagation(); onAddSection?.() }}
            className="w-full py-4 flex items-center justify-center gap-2 text-slate-600
                       hover:text-violet-400 hover:bg-violet-500/5 transition-all border-t border-white/5"
          >
            <Plus className="w-4 h-4" />
            <span className="text-sm font-medium">Dodaj sekcję</span>
          </button>
        )}
      </motion.div>
    </div>
  )
}

'use client'

/**
 * LayerTree — C6.2-D
 *
 * Left-panel section hierarchy viewer.
 * Renders the recursive SectionNode tree for the active page.
 *
 * Operations:
 *   - click to select
 *   - rename (double-click label)
 *   - toggle visibility
 *   - delete
 *   - move up/down (buttons)
 *   - duplicate
 *   - expand/collapse containers
 */

import { useState, useCallback } from 'react'
import {
  Eye, EyeOff, Trash2, Copy, ChevronRight, ChevronDown,
  GripVertical, Lock, Unlock, Filter,
} from 'lucide-react'
import { useBuilder } from '../state/BuilderProvider'
import { SectionNode } from '../../../../packages/builder-core/src/BuilderDocument'

// ---------------------------------------------------------------------------
// Layer row
// ---------------------------------------------------------------------------

interface LayerRowProps {
  node: SectionNode
  depth: number
  pageId: string
  isSelected: boolean
  onSelect: (id: string) => void
}

function LayerRow({ node, depth, pageId, isSelected, onSelect }: LayerRowProps) {
  const { dispatch } = useBuilder()
  const [expanded, setExpanded] = useState(true)
  const hasChildren = node.children.length > 0

  const handleToggleVisibility = useCallback((e: React.MouseEvent) => {
    e.stopPropagation()
    dispatch({ type: 'TOGGLE_VISIBILITY', pageId, sectionId: node.id })
  }, [dispatch, pageId, node.id])

  const handleDelete = useCallback((e: React.MouseEvent) => {
    e.stopPropagation()
    dispatch({ type: 'REMOVE_SECTION', pageId, sectionId: node.id })
  }, [dispatch, pageId, node.id])

  const handleDuplicate = useCallback((e: React.MouseEvent) => {
    e.stopPropagation()
    dispatch({ type: 'DUPLICATE_SECTION', pageId, sectionId: node.id })
  }, [dispatch, pageId, node.id])

  const handleToggleLock = useCallback((e: React.MouseEvent) => {
    e.stopPropagation()
    dispatch({ type: 'TOGGLE_LOCK', pageId, sectionId: node.id })
  }, [dispatch, pageId, node.id])

  const typeIcon = hasChildren ? '⬡' : '▣'

  return (
    <div>
      <div
        onClick={() => onSelect(node.id)}
        className={`group flex items-center gap-1.5 px-2 py-1.5 rounded-lg cursor-pointer transition-all text-sm select-none
          ${isSelected
            ? 'bg-violet-500/20 border border-violet-500/30 text-white'
            : 'hover:bg-white/5 text-slate-300 hover:text-white border border-transparent'
          }
          ${!node.visible ? 'opacity-40' : ''}
        `}
        style={{ paddingLeft: `${8 + depth * 16}px` }}
      >
        {/* Expand/collapse for containers */}
        {hasChildren ? (
          <button
            onClick={e => { e.stopPropagation(); setExpanded(v => !v) }}
            className="text-slate-500 hover:text-white transition-colors flex-shrink-0"
          >
            {expanded
              ? <ChevronDown className="w-3.5 h-3.5" />
              : <ChevronRight className="w-3.5 h-3.5" />
            }
          </button>
        ) : (
          <span className="w-3.5 h-3.5 flex-shrink-0 text-slate-600 text-xs flex items-center justify-center">
            {typeIcon}
          </span>
        )}

        {/* Drag handle */}
        <GripVertical className="w-3.5 h-3.5 text-slate-600 group-hover:text-slate-400 transition-colors flex-shrink-0" />

        {/* Label */}
        <span className={`flex-1 text-xs font-medium truncate ${node.locked ? 'text-amber-400/70' : ''}`}>
          {node.label}
        </span>

        {/* Type badge */}
        <span className="text-[10px] text-slate-600 font-mono hidden group-hover:block flex-shrink-0">
          {node.type}
        </span>

        {/* Action buttons — show on hover or selection */}
        <div className={`flex items-center gap-0.5 flex-shrink-0 ${isSelected ? 'flex' : 'hidden group-hover:flex'}`}>
          <button
            onClick={handleToggleLock}
            className="p-0.5 rounded hover:bg-white/10 text-slate-500 hover:text-amber-400 transition-colors"
            title={node.locked ? 'Odblokuj' : 'Zablokuj'}
          >
            {node.locked
              ? <Lock className="w-3 h-3" />
              : <Unlock className="w-3 h-3" />
            }
          </button>
          <button
            onClick={handleToggleVisibility}
            className="p-0.5 rounded hover:bg-white/10 text-slate-500 hover:text-white transition-colors"
            title={node.visible ? 'Ukryj' : 'Pokaż'}
          >
            {node.visible
              ? <Eye className="w-3 h-3" />
              : <EyeOff className="w-3 h-3" />
            }
          </button>
          <button
            onClick={handleDuplicate}
            className="p-0.5 rounded hover:bg-white/10 text-slate-500 hover:text-violet-400 transition-colors"
            title="Duplikuj"
          >
            <Copy className="w-3 h-3" />
          </button>
          <button
            onClick={handleDelete}
            className="p-0.5 rounded hover:bg-red-500/10 text-slate-500 hover:text-red-400 transition-colors"
            title="Usuń"
          >
            <Trash2 className="w-3 h-3" />
          </button>
        </div>
      </div>

      {/* Children */}
      {hasChildren && expanded && (
        <div>
          {node.children.map(child => (
            <LayerRow
              key={child.id}
              node={child}
              depth={depth + 1}
              pageId={pageId}
              isSelected={isSelected && false /* children have own selection */}
              onSelect={onSelect}
            />
          ))}
        </div>
      )}
    </div>
  )
}

// ---------------------------------------------------------------------------
// LayerTree root
// ---------------------------------------------------------------------------

export function LayerTree() {
  const { document, canvas, dispatch } = useBuilder()
  const [showVisibleOnly, setShowVisibleOnly] = useState(false)
  const [showUnlockedOnly, setShowUnlockedOnly] = useState(false)

  const activePage = document.pages.find(p =>
    canvas.selectedPageId ? p.id === canvas.selectedPageId : p.isHome
  ) ?? document.pages[0]

  const handleSelect = useCallback((sectionId: string) => {
    const parentId = findParent(activePage.sections, sectionId)
    const targetId = parentId || sectionId
    dispatch({
      type: 'CANVAS',
      action: { type: 'SELECT_SECTION', sectionId: targetId, pageId: activePage?.id ?? null },
    })
  }, [dispatch, activePage])

  function findParent(sections: SectionNode[], childId: string): string | null {
    for (const section of sections) {
      if (section.children.some(child => child.id === childId)) {
        return section.id
      }
      const found = findParent(section.children, childId)
      if (found) return found
    }
    return null
  }

  if (!activePage) {
    return (
      <div className="flex flex-col items-center justify-center h-32 text-slate-500 text-sm">
        Brak stron
      </div>
    )
  }

  const sections = activePage.sections.filter(node => {
    if (showVisibleOnly && !node.visible) return false
    if (showUnlockedOnly && node.locked) return false
    return true
  })

  return (
    <div className="flex flex-col gap-0.5 p-2">
      {/* Filters */}
      <div className="flex items-center gap-1 px-2 py-1.5">
        <Filter className="w-3.5 h-3.5 text-slate-500" />
        <button
          onClick={() => setShowVisibleOnly(v => !v)}
          className={`text-[11px] px-2 py-1 rounded transition-all ${
            showVisibleOnly ? 'bg-violet-500/20 text-violet-300' : 'text-slate-500 hover:text-white'
          }`}
        >
          Widoczne
        </button>
        <button
          onClick={() => setShowUnlockedOnly(v => !v)}
          className={`text-[11px] px-2 py-1 rounded transition-all ${
            showUnlockedOnly ? 'bg-violet-500/20 text-violet-300' : 'text-slate-500 hover:text-white'
          }`}
        >
          Odblokowane
        </button>
      </div>

      {sections.length === 0 ? (
        <div className="flex flex-col items-center justify-center py-8 text-slate-600 text-xs text-center">
          <span className="text-2xl mb-2">⬡</span>
          Brak sekcji na tej stronie.
          <br />
          Dodaj pierwszą sekcję z palety.
        </div>
      ) : (
        sections.map(node => (
          <LayerRow
            key={node.id}
            node={node}
            depth={0}
            pageId={activePage.id}
            isSelected={canvas.selectedSectionId === node.id}
            onSelect={handleSelect}
          />
        ))
      )}
    </div>
  )
}

'use client'

/**
 * PropsPanel — C6.2-E
 *
 * Dynamic props editor — auto-generated from ComponentRegistry schema.
 *
 * Architecture:
 *   ComponentRegistry.get(section.type).schema
 *       ↓
 *   PropSchema[] (type: string | color | image | select | number | boolean | text | array)
 *       ↓
 *   Field renderer per type
 *       ↓
 *   dispatch({ type: 'UPDATE_PROPS', ... })
 *
 * No per-component editor files needed. The schema drives everything.
 */

import { useCallback, useMemo, useState } from 'react'
import { Image } from 'lucide-react'
import { X, Lock, Eye, EyeOff, Trash2, Copy } from 'lucide-react'
import { useBuilder, useSelectedSection } from '../state/BuilderProvider'
import { PropSchema } from '../../../../packages/builder-core/src/ComponentRegistry'
import { VIEWPORT_PRESETS, ViewportLabel } from '../../../../packages/builder-core/src/CanvasState'
import { Monitor, Tablet, Smartphone } from 'lucide-react'
import { ResponsiveEngine, ResponsiveValue } from '../../../../packages/builder-core/src/ResponsiveEngine'
import { AssetPicker } from '../../media/AssetPicker'
import { MediaDocument } from '../../../../packages/asset-manager-core/src/AssetTypes'

// ---------------------------------------------------------------------------
// Individual field renderers
// ---------------------------------------------------------------------------

interface FieldProps {
  schema: PropSchema
  value: unknown
  onChange: (key: string, value: unknown) => void
}

function StringField({ schema, value, onChange }: FieldProps) {
  return (
    <div>
      <label className="block text-[11px] font-semibold text-slate-500 uppercase tracking-wider mb-1.5">
        {schema.label}
        {schema.required && <span className="text-red-400 ml-1">*</span>}
      </label>
      <input
        type="text"
        value={typeof value === 'string' ? value : ''}
        onChange={e => onChange(schema.key, e.target.value)}
        placeholder={(schema as { placeholder?: string }).placeholder ?? schema.label}
        className="w-full bg-white/5 border border-white/10 rounded-lg px-3 py-2 text-sm text-white placeholder-slate-600
                   focus:outline-none focus:border-violet-500/50 focus:ring-1 focus:ring-violet-500/30 transition-all"
      />
      {schema.description && (
        <p className="text-[11px] text-slate-600 mt-1">{schema.description}</p>
      )}
    </div>
  )
}

function TextField({ schema, value, onChange }: FieldProps) {
  return (
    <div>
      <label className="block text-[11px] font-semibold text-slate-500 uppercase tracking-wider mb-1.5">
        {schema.label}
      </label>
      <textarea
        value={typeof value === 'string' ? value : ''}
        onChange={e => onChange(schema.key, e.target.value)}
        rows={3}
        className="w-full bg-white/5 border border-white/10 rounded-lg px-3 py-2 text-sm text-white
                   focus:outline-none focus:border-violet-500/50 focus:ring-1 focus:ring-violet-500/30 transition-all resize-none"
      />
    </div>
  )
}

function NumberField({ schema, value, onChange }: FieldProps) {
  const s = schema as { min?: number; max?: number; step?: number; unit?: string }
  return (
    <div>
      <label className="block text-[11px] font-semibold text-slate-500 uppercase tracking-wider mb-1.5">
        {schema.label} {s.unit && <span className="text-slate-600 normal-case font-normal">({s.unit})</span>}
      </label>
      <input
        type="number"
        value={typeof value === 'number' ? value : ''}
        min={s.min}
        max={s.max}
        step={s.step ?? 1}
        onChange={e => onChange(schema.key, parseFloat(e.target.value))}
        className="w-full bg-white/5 border border-white/10 rounded-lg px-3 py-2 text-sm text-white
                   focus:outline-none focus:border-violet-500/50 focus:ring-1 focus:ring-violet-500/30 transition-all"
      />
    </div>
  )
}

function BooleanField({ schema, value, onChange }: FieldProps) {
  return (
    <div className="flex items-center justify-between">
      <label className="text-[11px] font-semibold text-slate-500 uppercase tracking-wider">
        {schema.label}
      </label>
      <button
        onClick={() => onChange(schema.key, !value)}
        className={`relative w-10 h-5 rounded-full transition-all duration-200 flex-shrink-0
          ${value ? 'bg-violet-500' : 'bg-white/10'}`}
      >
        <span className={`absolute top-0.5 w-4 h-4 bg-white rounded-full shadow transition-transform duration-200
          ${value ? 'translate-x-5' : 'translate-x-0.5'}`} />
      </button>
    </div>
  )
}

function ColorField({ schema, value, onChange }: FieldProps) {
  const colorVal = typeof value === 'string' ? value : '#6366f1'
  return (
    <div>
      <label className="block text-[11px] font-semibold text-slate-500 uppercase tracking-wider mb-1.5">
        {schema.label}
      </label>
      <div className="flex items-center gap-2">
        <input
          type="color"
          value={colorVal}
          onChange={e => onChange(schema.key, e.target.value)}
          className="w-9 h-9 rounded-lg border border-white/10 cursor-pointer bg-transparent flex-shrink-0"
        />
        <input
          type="text"
          value={colorVal}
          onChange={e => onChange(schema.key, e.target.value)}
          className="flex-1 bg-white/5 border border-white/10 rounded-lg px-3 py-2 text-sm text-white font-mono
                     focus:outline-none focus:border-violet-500/50 focus:ring-1 focus:ring-violet-500/30 transition-all"
        />
      </div>
    </div>
  )
}

function ImageField({ schema, value, onChange }: FieldProps) {
  const [showPicker, setShowPicker] = useState(false)
  const assetRef = typeof value === 'object' && value !== null && 'id' in value ? value as { id: string; type: string } : null
  const displayUrl = assetRef ? `asset://${assetRef.id}` : (typeof value === 'string' ? value : '')

  return (
    <div>
      <label className="block text-[11px] font-semibold text-slate-500 uppercase tracking-wider mb-1.5">
        {schema.label}
      </label>
      {assetRef && (
        <div className="mb-2 relative rounded-lg overflow-hidden bg-white/5 border border-white/10 aspect-video flex items-center justify-center">
          <div className="text-4xl opacity-60">🖼️</div>
          <div className="absolute bottom-2 left-2 right-2">
            <p className="text-[10px] text-slate-400 font-mono truncate">asset://{assetRef.id}</p>
          </div>
        </div>
      )}
      {!assetRef && displayUrl && (
        <div className="mb-2 relative rounded-lg overflow-hidden bg-white/5 border border-white/10 aspect-video">
          {/* eslint-disable-next-line @next/next/no-img-element */}
          <img src={displayUrl} alt={schema.label} className="w-full h-full object-cover" />
        </div>
      )}
      <div className="flex items-center gap-2">
        <input
          type="text"
          value={displayUrl}
          readOnly
          placeholder="Brak wybranego assetu"
          className="flex-1 bg-white/5 border border-white/10 rounded-lg px-3 py-2 text-sm text-white font-mono text-xs focus:outline-none"
        />
        <button
          onClick={() => setShowPicker(true)}
          className="p-2 rounded-lg bg-violet-600 text-white hover:bg-violet-500 transition-colors"
          title="Wybierz z biblioteki"
        >
          <Image className="w-4 h-4" />
        </button>
      </div>
      <AssetPicker
        isOpen={showPicker}
        onClose={() => setShowPicker(false)}
        onSelect={(asset) => {
          const ref = { id: asset.id, type: asset.type }
          onChange(schema.key, ref)
          setShowPicker(false)
        }}
        document={{} as MediaDocument}
      />
    </div>
  )
}

function SelectField({ schema, value, onChange }: FieldProps) {
  const s = schema as { options?: Array<{ label: string; value: unknown }> }
  const options = s.options ?? []
  return (
    <div>
      <label className="block text-[11px] font-semibold text-slate-500 uppercase tracking-wider mb-1.5">
        {schema.label}
      </label>
      <select
        value={String(value ?? '')}
        onChange={e => {
          const opt = options.find(o => String(o.value) === e.target.value)
          onChange(schema.key, opt?.value ?? e.target.value)
        }}
        className="w-full bg-[#0a0a14] border border-white/10 rounded-lg px-3 py-2 text-sm text-white
                   focus:outline-none focus:border-violet-500/50 transition-all"
      >
        {options.map(opt => (
          <option key={String(opt.value)} value={String(opt.value)}>
            {opt.label}
          </option>
        ))}
      </select>
    </div>
  )
}

// ---------------------------------------------------------------------------
// Field dispatcher
// ---------------------------------------------------------------------------

function PropField({ schema, value, onChange }: FieldProps) {
  if (schema.hidden) return null

  switch (schema.type) {
    case 'string':  return <StringField  schema={schema} value={value} onChange={onChange} />
    case 'text':    return <TextField    schema={schema} value={value} onChange={onChange} />
    case 'number':  return <NumberField  schema={schema} value={value} onChange={onChange} />
    case 'boolean': return <BooleanField schema={schema} value={value} onChange={onChange} />
    case 'color':   return <ColorField   schema={schema} value={value} onChange={onChange} />
    case 'image':
    case 'asset':   return <ImageField   schema={schema} value={value} onChange={onChange} />
    case 'select':
    case 'multiselect': return <SelectField schema={schema} value={value} onChange={onChange} />
    case 'array':
    case 'object':
    default:
      return (
        <div className="text-xs text-slate-600 italic p-2 bg-white/5 rounded-lg">
          {schema.label}: <span className="font-mono">{schema.type}</span> — panel C6.3
        </div>
      )
  }
}

// ---------------------------------------------------------------------------
// PropsPanel root
// ---------------------------------------------------------------------------

export function PropsPanel() {
  const { dispatch, canvas, document, ctx } = useBuilder()
  const selectedNode = useSelectedSection()
  const responsiveEngine = useMemo(() => new ResponsiveEngine(), [])
  const [responsiveProps, setResponsiveProps] = useState<Record<string, Record<string, any>>>({})

  const handleClose = useCallback(() => {
    dispatch({ type: 'CANVAS', action: { type: 'SELECT_SECTION', sectionId: null } })
  }, [dispatch])

  const handlePropChange = useCallback((key: string, value: unknown) => {
    if (!canvas.selectedSectionId || !canvas.selectedPageId) return
    const breakpoint = canvas.selection.activeBreakpoint
    const sectionResponsive = responsiveProps[canvas.selectedSectionId] ?? {}
    const updated = {
      ...sectionResponsive,
      [breakpoint.toLowerCase()]: value,
    }
    setResponsiveProps(prev => ({
      ...prev,
      [canvas.selectedSectionId!]: updated,
    }))
    dispatch({
      type: 'UPDATE_PROPS',
      pageId: canvas.selectedPageId,
      sectionId: canvas.selectedSectionId,
      props: { [key]: value },
    })
  }, [dispatch, canvas.selectedSectionId, canvas.selectedPageId, canvas.selection.activeBreakpoint, responsiveProps])

  const handleDelete = useCallback(() => {
    if (!canvas.selectedSectionId || !canvas.selectedPageId) return
    dispatch({ type: 'REMOVE_SECTION', pageId: canvas.selectedPageId, sectionId: canvas.selectedSectionId })
  }, [dispatch, canvas.selectedSectionId, canvas.selectedPageId])

  const handleDuplicate = useCallback(() => {
    if (!canvas.selectedSectionId || !canvas.selectedPageId) return
    dispatch({ type: 'DUPLICATE_SECTION', pageId: canvas.selectedPageId, sectionId: canvas.selectedSectionId })
  }, [dispatch, canvas.selectedSectionId, canvas.selectedPageId])

  const handleToggleVisibility = useCallback(() => {
    if (!canvas.selectedSectionId || !canvas.selectedPageId) return
    dispatch({ type: 'TOGGLE_VISIBILITY', pageId: canvas.selectedPageId, sectionId: canvas.selectedSectionId })
  }, [dispatch, canvas.selectedSectionId, canvas.selectedPageId])

  // Empty state
  if (!selectedNode) {
    // Show page-level SEO and branding when no section is selected
    const activePage = document.pages.find(p =>
      canvas.selectedPageId ? p.id === canvas.selectedPageId : p.isHome
    ) ?? document.pages[0]

    return (
      <div className="flex flex-col h-full">
        <div className="p-4 border-b border-white/10 flex items-center justify-between">
          <h2 className="text-xs font-bold text-white uppercase tracking-wider">Właściwości</h2>
        </div>
        <div className="flex-1 overflow-y-auto p-4 space-y-4">
          {activePage && (
            <>
              <div className="text-[11px] font-semibold text-slate-500 uppercase tracking-wider mb-2">
                Strona: {activePage.name}
              </div>
              <div>
                <label className="block text-[11px] font-semibold text-slate-500 uppercase tracking-wider mb-1.5">
                  Meta title
                </label>
                <input
                  type="text"
                  value={activePage.seo.title ?? ''}
                  onChange={e => dispatch({
                    type: 'UPDATE_PAGE_SEO',
                    pageId: activePage.id,
                    seo: { title: e.target.value }
                  })}
                  className="w-full bg-white/5 border border-white/10 rounded-lg px-3 py-2 text-sm text-white
                             focus:outline-none focus:border-violet-500/50 transition-all"
                />
              </div>
              <div>
                <label className="block text-[11px] font-semibold text-slate-500 uppercase tracking-wider mb-1.5">
                  Meta description
                </label>
                <textarea
                  value={activePage.seo.description ?? ''}
                  onChange={e => dispatch({
                    type: 'UPDATE_PAGE_SEO',
                    pageId: activePage.id,
                    seo: { description: e.target.value }
                  })}
                  rows={3}
                  className="w-full bg-white/5 border border-white/10 rounded-lg px-3 py-2 text-sm text-white
                             focus:outline-none focus:border-violet-500/50 transition-all resize-none"
                />
              </div>
            </>
          )}
          <div className="flex flex-col items-center justify-center py-8 text-slate-600 text-xs text-center">
            <span className="text-2xl mb-2">▣</span>
            Kliknij sekcję, aby edytować jej właściwości
          </div>
        </div>
      </div>
    )
  }

  // Get schema from registry
  const descriptor = ctx.registry.get(selectedNode.type)
  const schema = descriptor?.schema ?? []
  const props = selectedNode.props

  // Group props by group
  const groups = new Map<string, PropSchema[]>()
  const ungrouped: PropSchema[] = []
  for (const field of schema) {
    if (field.group) {
      const existing = groups.get(field.group) ?? []
      existing.push(field)
      groups.set(field.group, existing)
    } else {
      ungrouped.push(field)
    }
  }

  return (
    <div className="flex flex-col h-full">
      {/* Header */}
      <div className="p-4 border-b border-white/10 flex items-center gap-2">
        <div className="flex-1 min-w-0">
          <h2 className="text-xs font-bold text-white uppercase tracking-wider truncate">
            {selectedNode.label}
          </h2>
          <p className="text-[11px] text-slate-600 font-mono">{selectedNode.type}</p>
        </div>

        {/* Breakpoint Switcher */}
        <div className="flex items-center gap-0.5 bg-white/5 rounded-lg p-0.5">
          {(Object.keys(VIEWPORT_PRESETS) as ViewportLabel[]).map(label => (
            <button
              key={label}
              onClick={() => dispatch({ type: 'CANVAS', action: { type: 'SET_BREAKPOINT', breakpoint: label } })}
              className={`p-1 rounded transition-all ${
                canvas.selection.activeBreakpoint === label
                  ? 'bg-violet-500/20 text-violet-400'
                  : 'text-slate-500 hover:text-white'
              }`}
              title={label}
            >
              {label === 'DESKTOP' && <Monitor className="w-3.5 h-3.5" />}
              {label === 'TABLET' && <Tablet className="w-3.5 h-3.5" />}
              {label === 'MOBILE' && <Smartphone className="w-3.5 h-3.5" />}
            </button>
          ))}
        </div>

        <div className="flex items-center gap-1 flex-shrink-0">
          <button
            onClick={handleToggleVisibility}
            className={`p-1.5 rounded-lg hover:bg-white/10 transition-colors
              ${selectedNode.visible ? 'text-slate-400 hover:text-white' : 'text-violet-400'}`}
            title={selectedNode.visible ? 'Ukryj' : 'Pokaż'}
          >
            {selectedNode.visible ? <Eye className="w-4 h-4" /> : <EyeOff className="w-4 h-4" />}
          </button>
          <button
            onClick={handleDuplicate}
            className="p-1.5 rounded-lg hover:bg-white/10 text-slate-400 hover:text-violet-400 transition-colors"
            title="Duplikuj"
          >
            <Copy className="w-4 h-4" />
          </button>
          <button
            onClick={handleDelete}
            className="p-1.5 rounded-lg hover:bg-red-500/10 text-slate-400 hover:text-red-400 transition-colors"
            title="Usuń sekcję"
          >
            <Trash2 className="w-4 h-4" />
          </button>
          <button
            onClick={handleClose}
            className="p-1.5 rounded-lg hover:bg-white/10 text-slate-400 hover:text-white transition-colors"
            title="Zamknij"
          >
            <X className="w-4 h-4" />
          </button>
        </div>
      </div>

      {/* Locked notice */}
      {selectedNode.locked && (
        <div className="mx-4 mt-3 px-3 py-2 rounded-lg bg-amber-500/10 border border-amber-500/20 text-amber-400 text-xs flex items-center gap-2">
          <Lock className="w-3.5 h-3.5 flex-shrink-0" />
          Sekcja jest zablokowana — edycja wyłączona
        </div>
      )}

      {/* Props */}
      <div className={`flex-1 overflow-y-auto p-4 space-y-4 ${selectedNode.locked ? 'pointer-events-none opacity-60' : ''}`}>
        {schema.length === 0 ? (
          <div className="text-xs text-slate-600 italic text-center py-8">
            Brak konfigurowalnych właściwości dla tego komponentu.
            <br />
            Zarejestruj schemat w ComponentRegistry.
          </div>
        ) : (
          <>
            {/* Ungrouped fields */}
            {ungrouped.map(field => (
              <PropField
                key={field.key}
                schema={field}
                value={props[field.key]}
                onChange={handlePropChange}
              />
            ))}
            {/* Grouped fields */}
            {Array.from(groups.entries()).map(([groupName, fields]) => (
              <div key={groupName}>
                <div className="text-[11px] font-semibold text-slate-600 uppercase tracking-wider mb-2 pt-2 border-t border-white/5">
                  {groupName}
                </div>
                <div className="space-y-3">
                  {fields.map(field => (
                    <PropField
                      key={field.key}
                      schema={field}
                      value={props[field.key]}
                      onChange={handlePropChange}
                    />
                  ))}
                </div>
              </div>
            ))}
          </>
        )}
      </div>
    </div>
  )
}

'use client'

/**
 * BuilderProvider — C6.2-B
 *
 * React adapter over BuilderContext (builder-core).
 *
 * Responsibilities:
 *   - Creates a BuilderContext on mount from the provided BuilderDocument
 *   - Stores context in React state (immutable update pattern → re-render on change)
 *   - Provides dispatch() to children via hook
 *   - Manages keyboard shortcuts (Ctrl+Z / Ctrl+Shift+Z)
 *   - Wires the MemoryChannel for preview sync
 *
 * ARCH NOTE: This file is the ONLY place in builder-ui that imports from builder-core.
 * All child components consume via useBuilder() hook.
 */

import {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useMemo,
  useRef,
  useState,
} from 'react'
import {
  BuilderContext,
  BuilderCommand,
  BuilderDocument,
  BuilderComponentRegistry,
  CanvasState,
  HistoryStack,
  createBuilderContext,
  createBuilderComponentRegistry,
  createMemoryChannel,
  MemoryChannelPair,
} from '../../../../packages/builder-core/src/index'

// ---------------------------------------------------------------------------
// Context shape exposed to children
// ---------------------------------------------------------------------------

export interface BuilderContextValue {
  /** Current builder context (immutable snapshot) */
  ctx: BuilderContext
  /** Dispatch a command — triggers re-render with new ctx */
  dispatch: (command: BuilderCommand) => void
  /** Derived convenience: the current document */
  document: BuilderDocument
  /** Derived convenience: canvas state */
  canvas: CanvasState
  /** Derived convenience: history stack */
  history: HistoryStack<BuilderDocument>
  /** The preview channel pair (for wiring preview iframe) */
  previewChannel: MemoryChannelPair
  /** Whether the document has unsaved (unpublished) changes */
  isDirty: boolean
}

const BuilderCtx = createContext<BuilderContextValue | null>(null)

// ---------------------------------------------------------------------------
// Provider
// ---------------------------------------------------------------------------

interface BuilderProviderProps {
  document: BuilderDocument
  registry?: BuilderComponentRegistry
  children: React.ReactNode
}

export function BuilderProvider({
  document: initialDocument,
  registry: providedRegistry,
  children,
}: BuilderProviderProps) {
  // Create the memory channel once (stable reference)
  const previewChannelRef = useRef<MemoryChannelPair>(createMemoryChannel())
  const previewChannel = previewChannelRef.current

  // Registry — use provided or create default
  const registry = useMemo(
    () => providedRegistry ?? createBuilderComponentRegistry(),
    [providedRegistry]
  )

  // BuilderContext stored in React state (immutable update → re-render)
  const [ctx, setCtx] = useState<BuilderContext>(() =>
    createBuilderContext({
      document: initialDocument,
      registry,
      preview: previewChannel.builderChannel,
    })
  )

  // dispatch — the single mutation gateway
  const dispatch = useCallback((command: BuilderCommand) => {
    setCtx(prev => prev.dispatch(command))
  }, [])

  // Keyboard shortcuts
  useEffect(() => {
    const handler = (e: KeyboardEvent) => {
      const isMac = navigator.platform.toLowerCase().includes('mac')
      const ctrlKey = isMac ? e.metaKey : e.ctrlKey

      if (ctrlKey && !e.shiftKey && e.key === 'z') {
        e.preventDefault()
        dispatch({ type: 'UNDO' })
      }
      if (ctrlKey && e.shiftKey && (e.key === 'z' || e.key === 'Z')) {
        e.preventDefault()
        dispatch({ type: 'REDO' })
      }
    }
    window.addEventListener('keydown', handler)
    return () => window.removeEventListener('keydown', handler)
  }, [dispatch])

  // Cleanup preview channel on unmount
  useEffect(() => {
    return () => {
      previewChannel.builderChannel.destroy()
    }
  }, [previewChannel])

  const value = useMemo<BuilderContextValue>(
    () => ({
      ctx,
      dispatch,
      document: ctx.document,
      canvas: ctx.canvas,
      history: ctx.history,
      previewChannel,
      isDirty: ctx.document.isDirty,
    }),
    [ctx, dispatch, previewChannel]
  )

  return <BuilderCtx.Provider value={value}>{children}</BuilderCtx.Provider>
}

// ---------------------------------------------------------------------------
// Hooks
// ---------------------------------------------------------------------------

export function useBuilder(): BuilderContextValue {
  const ctx = useContext(BuilderCtx)
  if (!ctx) {
    throw new Error('useBuilder() must be used within <BuilderProvider>')
  }
  return ctx
}

export function useBuilderDocument(): BuilderDocument {
  return useBuilder().document
}

export function useBuilderCanvas(): CanvasState {
  return useBuilder().canvas
}

export function useBuilderHistory(): {
  canUndo: boolean
  canRedo: boolean
  undo: () => void
  redo: () => void
} {
  const { history, dispatch } = useBuilder()
  return {
    canUndo: history.canUndo,
    canRedo: history.canRedo,
    undo: () => dispatch({ type: 'UNDO' }),
    redo: () => dispatch({ type: 'REDO' }),
  }
}

export function useSelectedSection() {
  const { canvas, document } = useBuilder()
  if (!canvas.selectedSectionId || !canvas.selectedPageId) return null

  const page = document.pages.find(p => p.id === canvas.selectedPageId)
  if (!page) return null

  const pageSections = page.sections
  const targetId = canvas.selectedSectionId

  // Search recursively
  type SectionArray = typeof pageSections
  function find(nodes: SectionArray): SectionArray[0] | null {
    for (const node of nodes) {
      if (node.id === targetId) return node
      if (node.children.length > 0) {
        const found = find(node.children)
        if (found) return found
      }
    }
    return null
  }

  return find(pageSections)
}

