import { TemplateRegistry } from './TemplateRegistry'
import { StoreService } from '@/lib/store/StoreService'
import { ProductService } from '@/lib/product/ProductService'
import type { TemplateDefinition } from './TemplateTypes'

export class TemplateInstaller {
  private readonly registry: TemplateRegistry
  private readonly storeService: StoreService
  private readonly productService: ProductService

  constructor() {
    this.registry = new TemplateRegistry()
    this.storeService = new StoreService()
    this.productService = new ProductService()
  }

  async install(tenantId: string, storeId: string, templateSlug: string) {
    const template = this.registry.getBySlug(templateSlug)
    if (!template) {
      throw new Error(`Template not found: ${templateSlug}`)
    }

    const branding = {
      primaryColor: template.theme.primaryColor,
      secondaryColor: template.theme.secondaryColor,
      font: template.theme.font,
      description: template.theme.description || template.description,
    }

    await this.storeService.updateBranding(tenantId, storeId, branding)

    for (const productSeed of template.products) {
      await this.productService.createProduct(tenantId, {
        name: productSeed.name,
        description: productSeed.description,
        price: productSeed.price,
        currency: productSeed.currency || template.currency,
        images: productSeed.images || [],
        storeId,
        status: 'DRAFT',
      })
    }

    await this.storeService.updateStore(tenantId, storeId, {
      config: {
        branding,
        template: templateSlug,
        pages: template.pages,
      },
    })

    await this.storeService.markStoreReady(tenantId, storeId)

    return { template: template.slug, storeId }
  }
}

import { PlatformEventBusImpl } from '@/../packages/platform-core/src/events/PlatformEventBus';
import { EventRegistry } from '@/../packages/platform-core/src/events/EventRegistry';
import { ConsolePlatformLogger } from '@/../packages/platform-core/src/logger/Logger';
import { TenantRepository } from './TenantRepository';
import type { Tenant, TenantStatus, StoreInstance, StoreStatus } from './TenantStatus';

export class TenantProvisioningEngine {
  private readonly eventBus: PlatformEventBusImpl;
  private readonly tenantRepo: TenantRepository;
  private readonly logger: ConsolePlatformLogger;

  constructor(options: {
    eventBus: PlatformEventBusImpl;
    tenantRepo: TenantRepository;
    logger: ConsolePlatformLogger;
  }) {
    this.eventBus = options.eventBus;
    this.tenantRepo = options.tenantRepo;
    this.logger = options.logger;

    // Register provisioning events
    const provisioningEvents = [
      'Tenant.Created',
      'Store.Provisioned',
      'Tenant.Ready',
    ];
    for (const evt of provisioningEvents) {
      EventRegistry.register(evt);
    }

    // Subscribe to Order.PaymentConfirmed event
    this.eventBus.subscribe<{ orderId: string; paymentIntentId: string }>(
      'Order.PaymentConfirmed',
      async (event) => {
        const { orderId, paymentIntentId } = event.payload;
        const tenantId = event.tenantId;
        if (tenantId) {
          try {
            await this.provisionTenant(tenantId, event.correlationId);
          } catch (err: any) {
            this.logger.error({
              message: `Provisioning failed for tenant ${tenantId} on order ${orderId}: ${err.message}`,
              correlationId: event.correlationId,
              tenantId,
            });
          }
        }
      }
    );
  }

  async createTenant(tenantId: string, ownerEmail: string, packageId: string, correlationId?: string): Promise<Tenant> {
    const cid = correlationId || `tn_create_${Date.now()}`;

    // Create tenant in CREATED status
    const tenant = await this.tenantRepo.createTenant({
      id: tenantId,
      ownerEmail,
      packageId,
      status: 'CREATED',
    });

    // Publish Tenant.Created event
    await this.eventBus.publish({
      eventId: `evt_tn_created_${Math.random().toString(36).substr(2, 9)}`,
      eventType: 'Tenant.Created',
      timestamp: new Date().toISOString(),
      correlationId: cid,
      tenantId,
      payload: { tenantId, ownerEmail, packageId },
    });

    this.logger.info({
      message: `Tenant registered: ${tenantId}`,
      correlationId: cid,
      tenantId,
    });

    return tenant;
  }

  async provisionTenant(tenantId: string, correlationId?: string): Promise<void> {
    const cid = correlationId || `tn_prov_${Date.now()}`;

    const tenant = await this.tenantRepo.getTenant(tenantId);
    if (!tenant) {
      throw new Error(`Tenant not found: ${tenantId}`);
    }

    // Update status to PROVISIONING
    await this.tenantRepo.updateTenantStatus(tenantId, 'PROVISIONING');

    const storeName = `${tenantId} Store`;
    const store = await this.tenantRepo.createStore({
      id: `store_${Math.random().toString(36).substr(2, 9)}`,
      tenantId,
      name: storeName,
      slug: storeName.toLowerCase().replace(/\s+/g, '-'),
      status: 'READY',
    });

    // Update status to ACTIVE
    await this.tenantRepo.updateTenantStatus(tenantId, 'ACTIVE');

    // Publish Store.Provisioned
    await this.eventBus.publish({
      eventId: `evt_store_prov_${Math.random().toString(36).substr(2, 9)}`,
      eventType: 'Store.Provisioned',
      timestamp: new Date().toISOString(),
      correlationId: cid,
      tenantId,
      payload: { tenantId, storeId: store.id, status: 'READY' },
    });

    // Publish Tenant.Ready
    await this.eventBus.publish({
      eventId: `evt_tn_ready_${Math.random().toString(36).substr(2, 9)}`,
      eventType: 'Tenant.Ready',
      timestamp: new Date().toISOString(),
      correlationId: cid,
      tenantId,
      payload: { tenantId, status: 'ACTIVE' },
    });

    this.logger.info({
      message: `Store provisioned and tenant activated: ${tenantId}`,
      correlationId: cid,
      tenantId,
    });
  }
}

import { getServiceSupabase } from '@/lib/supabase';
import type { Tenant, TenantStatus, StoreInstance, StoreStatus } from './TenantStatus';

export class TenantRepository {
  private readonly tenantTable = 'tenants';
  private readonly storeTable = 'stores';

  async createTenant(tenant: { id: string; ownerEmail: string; packageId: string; status: TenantStatus }): Promise<Tenant> {
    const supabase = getServiceSupabase();
    const now = new Date().toISOString();

    const { data, error } = await supabase
      .from(this.tenantTable)
      .insert({
        id: tenant.id,
        owner_email: tenant.ownerEmail,
        package_id: tenant.packageId,
        status: tenant.status,
        created_at: now,
        updated_at: now,
      })
      .select()
      .single();

    if (error) {
      throw new Error(`TenantRepository.createTenant failed: ${error.message}`);
    }

    return this.mapTenant(data);
  }

  async getTenant(id: string): Promise<Tenant | null> {
    const supabase = getServiceSupabase();
    const { data, error } = await supabase
      .from(this.tenantTable)
      .select('*')
      .eq('id', id)
      .maybeSingle();

    if (error) {
      throw new Error(`TenantRepository.getTenant failed: ${error.message}`);
    }

    if (!data) return null;
    return this.mapTenant(data);
  }

  async getAllTenants(): Promise<Tenant[]> {
    const supabase = getServiceSupabase();
    const { data, error } = await supabase
      .from(this.tenantTable)
      .select('*')
      .order('created_at', { ascending: false });

    if (error) {
      throw new Error(`TenantRepository.getAllTenants failed: ${error.message}`);
    }

    return (data || []).map(row => this.mapTenant(row));
  }

  async updateTenantStatus(id: string, status: TenantStatus): Promise<Tenant> {
    const supabase = getServiceSupabase();
    const now = new Date().toISOString();

    const { data, error } = await supabase
      .from(this.tenantTable)
      .update({
        status,
        updated_at: now,
      })
      .eq('id', id)
      .select()
      .single();

    if (error) {
      throw new Error(`TenantRepository.updateTenantStatus failed: ${error.message}`);
    }

    return this.mapTenant(data);
  }

  async createStore(store: { id: string; tenantId: string; name: string; slug: string; status: StoreStatus }): Promise<StoreInstance> {
    const supabase = getServiceSupabase();
    const now = new Date().toISOString();

    const { data, error } = await supabase
      .from(this.storeTable)
      .insert({
        id: store.id,
        tenant_id: store.tenantId,
        name: store.name,
        slug: store.slug,
        status: store.status,
        created_at: now,
        updated_at: now,
      })
      .select()
      .single();

    if (error) {
      throw new Error(`TenantRepository.createStore failed: ${error.message}`);
    }

    return this.mapStore(data);
  }

  async getStoreByTenant(tenantId: string): Promise<StoreInstance | null> {
    const supabase = getServiceSupabase();
    const { data, error } = await supabase
      .from(this.storeTable)
      .select('*')
      .eq('tenant_id', tenantId)
      .maybeSingle();

    if (error) {
      throw new Error(`TenantRepository.getStoreByTenant failed: ${error.message}`);
    }

    if (!data) return null;
    return this.mapStore(data);
  }

  async updateStoreStatus(id: string, tenantId: string, status: StoreStatus): Promise<StoreInstance> {
    const supabase = getServiceSupabase();
    const now = new Date().toISOString();

    const { data, error } = await supabase
      .from(this.storeTable)
      .update({
        status,
        updated_at: now,
      })
      .eq('id', id)
      .eq('tenant_id', tenantId)
      .select()
      .single();

    if (error) {
      throw new Error(`TenantRepository.updateStoreStatus failed: ${error.message}`);
    }

    return this.mapStore(data);
  }

  private mapTenant(row: any): Tenant {
    return {
      id: row.id,
      ownerEmail: row.owner_email,
      packageId: row.package_id,
      status: row.status as TenantStatus,
      createdAt: row.created_at,
      updatedAt: row.updated_at,
    };
  }

  private mapStore(row: any): StoreInstance {
    return {
      id: row.id,
      tenantId: row.tenant_id,
      name: row.name,
      status: row.status as StoreStatus,
      createdAt: row.created_at,
      updatedAt: row.updated_at,
    };
  }
}

