import type { VerifiedWebhook } from './WebhookTypes';
import type { PaymentProviderEvent } from '@/lib/payments/PaymentProviderEvent';

type IdempotencyStoreLike = {
  get: (
    provider: string,
    providerEventId: string,
    payloadHash: string
  ) => Promise<{ status: string } | null>;
  upsertReceived: (envelope: any, payloadHash: string) => Promise<void>;
  markCompleted: (envelope: any) => Promise<void>;
  markFailed: (envelope: any) => Promise<void>;
};

type PaymentEngineLike = {
  // Bridge decides what to do with provider payload (completePayment / failPayment)
  capture?: (event: PaymentProviderEvent) => Promise<{ paymentIntentId: string }>;
};

type OrderEngineLike = {
  // Bridge confirms order for completed payments only
  confirmPayment?: (params: {
    orderId: string;
    paymentIntentId: string;
    tenantId: string;
    correlationId: string;
  }) => Promise<any>;
};


export class WebhookProcessor {
  constructor(
    private deps: {
      idempotencyStore: IdempotencyStoreLike;
      paymentEngine?: PaymentEngineLike;
      orderEngine?: OrderEngineLike;
      // EventBus/Audit zrobimy docelowo adapterami; na tym etapie trzymamy minimalny kontrakt.
      eventBus?: {
        publish?: (event: any) => Promise<void> | void;
      };

      audit?: {
        record?: (entry: { type: string; correlationId: string; tenantId?: string; details?: any }) => Promise<void> | void;
      };
    }
  ) {}

  async process(verified: VerifiedWebhook) {
    const event = verified.event as PaymentProviderEvent;
    const envelope = verified.envelope;

    const existing = await this.deps.idempotencyStore.get(
      envelope.provider,
      envelope.providerEventId,
      envelope.payloadHash
    );

    if (existing?.status === 'COMPLETED' || existing?.status === 'PROCESSING') {
      await this.deps.audit?.record?.({
        type: 'WebhookDuplicateIgnored',
        correlationId: envelope.correlationId,
        tenantId: envelope.tenantId,
        details: { providerEventId: envelope.providerEventId, inProgress: existing.status === 'PROCESSING' },
      });
      return { ignored: true };
    }


    try {
      await this.deps.idempotencyStore.upsertReceived(envelope, envelope.payloadHash);
    } catch (err) {
      await this.deps.audit?.record?.({
        type: 'WebhookDuplicateIgnored',
        correlationId: envelope.correlationId,
        tenantId: envelope.tenantId,
        details: { providerEventId: envelope.providerEventId, inProgress: true, error: String(err) },
      });
      return { ignored: true };
    }

    try {
      const tenantId = event.tenantId;
      const correlationId = event.correlationId;
      const orderId = event.orderId;

      const captureResult = await this.deps.paymentEngine?.capture?.(event);

      const paymentIntentId = captureResult?.paymentIntentId;
      if (!paymentIntentId) {
        throw new Error('paymentIntentId is required for Payment.Completed and Order confirmation');
      }

      let orderResult: any = null;

      // Adapter/bridge must ensure that only COMPLETED results publish Order confirmation.
      // Here we only orchestrate and publish Payment.Completed payload aligned to engine expectations.
      if (event.type === 'PAYMENT_COMPLETED') {
        await this.deps.eventBus?.publish?.({
          eventId: `evt_pay_completed_${Math.random().toString(36).substr(2, 9)}`,
          eventType: 'Payment.Completed',
          timestamp: new Date().toISOString(),
          correlationId,
          tenantId,
          payload: {
            orderId,
            paymentIntentId,
            tenantId,
            correlationId,
          },
        });

        orderResult = await this.deps.orderEngine?.confirmPayment?.({
          orderId,
          paymentIntentId,
          tenantId,
          correlationId,
        });
      }


      await this.deps.idempotencyStore.markCompleted(envelope);

      await this.deps.audit?.record?.({
        type: 'WebhookCompleted',
        correlationId,
        tenantId,
        details: {
          providerEventId: envelope.providerEventId,
          orderId,
          paymentIntentId: captureResult?.paymentIntentId,
          orderResult,
        },
      });

      return { processed: true };
    } catch (err) {

      await this.deps.idempotencyStore.markFailed(envelope);

      await this.deps.audit?.record?.({
        type: 'WebhookFailed',
        correlationId: envelope.correlationId,
        tenantId: envelope.tenantId,
        details: { providerEventId: envelope.providerEventId, error: String(err) },
      });

      throw err;
    }
  }
}

import crypto from 'node:crypto';
import type { VerifiedWebhook } from './WebhookTypes';
import type { PaymentProviderEvent, PaymentProviderType } from '@/lib/payments/PaymentProviderEvent';

export interface WebhookVerifierDeps {
  providerSecret: string;
  provider: PaymentProviderType;
}

// NOTE: Minimalny verifier dla Step 3.
// Weryfikuje podpis HMAC (jeśli podany) i mapuje payload → PaymentProviderEvent.
export class WebhookVerifier {
  private providerSecret: string;
  private provider: PaymentProviderType;

  constructor(deps: WebhookVerifierDeps) {
    this.providerSecret = deps.providerSecret;
    this.provider = deps.provider;
  }

  verify(params: {
    rawBody: string;
    signatureHeader: string | null;
    payload: any;
    correlationId?: string;
  }): VerifiedWebhook {
    const { rawBody, signatureHeader, payload } = params;

    // Fail-fast jeżeli masz secret, a brakuje podpisu.
    if (this.providerSecret && !signatureHeader) {
      throw new Error('Missing webhook signature');
    }

    if (this.providerSecret && signatureHeader) {
      const expected = crypto
        .createHmac('sha256', this.providerSecret)
        .update(rawBody)
        .digest('hex');

      if (
        signatureHeader.length !== expected.length ||
        !crypto.timingSafeEqual(Buffer.from(signatureHeader), Buffer.from(expected))
      ) {
        throw new Error('Invalid signature');
      }
    }

    const providerEventId = String(payload?.event_id || payload?.eventId || payload?.id || '');
    const providerTransactionId = String(payload?.transaction_id || payload?.transactionId || '');

    const tenantId = String(payload?.tenant_id || payload?.tenantId || payload?.data?.tenant_id || '');

    const correlationId =
      params.correlationId ||
      String(payload?.correlation_id || payload?.correlationId || payload?.order?.correlation_id || '') ||
      `corr_${Math.random().toString(36).substr(2, 9)}`;

    const eventType = String(payload?.type || payload?.event_type || payload?.eventType || 'PAYMENT_COMPLETED');

    const amountRaw = payload?.amount ?? payload?.total ?? payload?.order?.amount ?? 0;
    const amount = Number(amountRaw) || 0;

    const currency = String(payload?.currency || payload?.order?.currency || 'PLN');

    const orderId = String(payload?.order_id || payload?.orderId || payload?.data?.order_id || '');

    const occurredAt = new Date(payload?.occurred_at || payload?.created_at || Date.now()).toISOString();

    const event: PaymentProviderEvent = {
      id: crypto.randomUUID ? crypto.randomUUID() : crypto.randomBytes(16).toString('hex'),
      provider: this.provider,
      type:
        eventType === 'PAYMENT_FAILED'
          ? 'PAYMENT_FAILED'
          : eventType === 'PAYMENT_REFUNDED'
            ? 'PAYMENT_REFUNDED'
            : 'PAYMENT_COMPLETED',
      tenantId,
      orderId,
      transactionId: providerTransactionId,
      amount,
      currency,
      occurredAt,
      correlationId,
      providerPayload: payload,
    };

    const payloadHash = crypto.createHash('sha256').update(rawBody).digest('hex');

    const envelope = {
      provider: this.provider,
      providerEventId,
      providerTransactionId,
      tenantId,
      correlationId,
      payloadHash,
      occurredAt,
    };

    return {
      envelope,
      event,
    };
  }
}

import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';
import crypto from 'node:crypto';
import { POST } from '../../app/api/webhooks/onekoszyk/route';
import { PaymentEngine } from '../../../packages/commerce-engine/src/PaymentEngine';
import { OrderProcessingEngine } from '../../../packages/commerce-engine/src/OrderProcessingEngine';
import { PlatformEventBusImpl } from '../../../packages/platform-core/src/events/PlatformEventBus';
import { ConsolePlatformLogger } from '../../../packages/platform-core/src/logger/Logger';

import { mockDb, clearMockDb } from '@/lib/supabase';

vi.mock('@/lib/supabase');

// -----------------------------------------------------------------------------
// Helper to construct signature headers
// -----------------------------------------------------------------------------
function generateSignature(rawBody: string, secret: string): string {
  return crypto.createHmac('sha256', secret).update(rawBody).digest('hex');
}

describe('Webhook Runtime Integration', () => {
  const secret = 'test-webhook-secret';
  let completePaymentSpy: any;
  let failPaymentSpy: any;
  let confirmPaymentSpy: any;

  beforeEach(() => {
    clearMockDb();
    process.env.ONEKOSZYK_SIGNATURE_KEY = secret;

    // Reset spy tracking cleanly via vi.spyOn (restored in afterEach)
    completePaymentSpy = vi.spyOn(PaymentEngine.prototype, 'completePayment');
    failPaymentSpy = vi.spyOn(PaymentEngine.prototype, 'failPayment');
    confirmPaymentSpy = vi.spyOn(OrderProcessingEngine.prototype, 'confirmPayment');
  });

  afterEach(() => {
    vi.restoreAllMocks();
  });

  it('1. Should return 401 and make zero engine calls for invalid signature', async () => {
    const payload = {
      id: 'evt_sig_fail',
      transaction_id: 'tx_123',
      tenant_id: 'tenant-123',
      order_id: 'ord_123',
      type: 'PAYMENT_COMPLETED',
      correlation_id: 'corr-123',
    };
    const rawBody = JSON.stringify(payload);
    const badSignature = 'invalid-signature-value';

    const req = new Request('http://localhost/api/webhooks/onekoszyk', {
      method: 'POST',
      headers: {
        'x-signature': badSignature,
        'content-type': 'application/json',
      },
      body: rawBody,
    });

    const res = await POST(req);
    expect(res.status).toBe(401);

    const json = await res.json();
    expect(json.error).toContain('signature');

    // Verify zero database insertions in webhook events
    expect(mockDb.webhook_events).toHaveLength(0);

    // Verify zero engine adapter calls
    expect(completePaymentSpy).not.toHaveBeenCalled();
    expect(failPaymentSpy).not.toHaveBeenCalled();
    expect(confirmPaymentSpy).not.toHaveBeenCalled();
  });

  it('2. Should ignore duplicates and return 200 ignored status', async () => {
    const payload = {
      id: 'evt_duplicate_123',
      transaction_id: 'tx_123',
      tenant_id: 'tenant-123',
      order_id: 'ord_123',
      type: 'PAYMENT_COMPLETED',
      correlation_id: 'corr-duplicate-123',
    };
    const rawBody = JSON.stringify(payload);
    const signature = generateSignature(rawBody, secret);

    // Seed existing COMPLETED webhook event in the database matching the payload details
    if (!mockDb.webhook_events) mockDb.webhook_events = [];
    mockDb.webhook_events.push({
      provider: 'onekoszyk',
      provider_event_id: 'evt_duplicate_123',
      payload_hash: crypto.createHash('sha256').update(rawBody).digest('hex'),
      correlation_id: 'corr-duplicate-123',
      tenant_id: 'tenant-123',
      status: 'COMPLETED',
      received_at: new Date().toISOString(),
      processed_at: new Date().toISOString(),
    });

    const req = new Request('http://localhost/api/webhooks/onekoszyk', {
      method: 'POST',
      headers: {
        'x-signature': signature,
        'content-type': 'application/json',
      },
      body: rawBody,
    });

    const res = await POST(req);
    expect(res.status).toBe(200);

    const json = await res.json();
    expect(json).toEqual({ received: true, ignored: true });

    // Verify no engine adapter calls were triggered
    expect(completePaymentSpy).not.toHaveBeenCalled();
    expect(failPaymentSpy).not.toHaveBeenCalled();
    expect(confirmPaymentSpy).not.toHaveBeenCalled();
  });

  it('3. Should confirm payment and order for PAYMENT_COMPLETED event', async () => {
    const tenantId = '7d20df20-80a5-48fa-84db-7b66df2e737d'; // valid UUID for tenant isolation checks
    const orderId = 'ord_completed_test';
    const paymentIntentId = 'intent_completed_test';

    // Seed the payment intent in database (status must be PROCESSING or AUTHORIZED to transition to CAPTURED)
    if (!mockDb.payment_intents) mockDb.payment_intents = [];
    mockDb.payment_intents.push({
      id: paymentIntentId,
      tenant_id: tenantId,
      provider: 'onekoszyk',
      provider_transaction_id: 'tx_completed_123',
      order_id: orderId,
      status: 'PROCESSING',
    });

    // Setup order in memory engine database
    const order = {
      id: orderId,
      tenantId,
      customerId: 'cust-123',
      items: [],
      subtotalGross: 1000,
      taxTotal: 230,
      grandTotalGross: 1000,
      currency: 'PLN',
      status: 'PAYMENT_PENDING' as const,
      shippingAddress: {
        fullName: 'Jan Kowalski',
        street: 'Wiejska 1',
        city: 'Warszawa',
        zipCode: '00-001',
        country: 'Poland',
      },
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
    };

    // We spy on OrderProcessingEngine and inject the order
    vi.spyOn(OrderProcessingEngine.prototype, 'getOrder').mockResolvedValue(order as any);

    const payload = {
      id: 'evt_completed_123',
      transaction_id: 'tx_completed_123',
      tenant_id: tenantId,
      order_id: orderId,
      type: 'PAYMENT_COMPLETED',
      amount: 1000,
      currency: 'PLN',
      correlation_id: 'corr-completed-123',
    };
    const rawBody = JSON.stringify(payload);
    const signature = generateSignature(rawBody, secret);

    const req = new Request('http://localhost/api/webhooks/onekoszyk', {
      method: 'POST',
      headers: {
        'x-signature': signature,
        'content-type': 'application/json',
      },
      body: rawBody,
    });

    const res = await POST(req);
    expect(res.status).toBe(200);

    const json = await res.json();
    expect(json).toEqual({ received: true, success: true });

    // Verify engines were called
    expect(completePaymentSpy).toHaveBeenCalled();
    expect(confirmPaymentSpy).toHaveBeenCalled();

    // Verify event is completed in database
    const record = mockDb.webhook_events.find((x: any) => x.provider_event_id === 'evt_completed_123');
    expect(record).toBeDefined();
    expect(record.status).toBe('COMPLETED');
  });

  it('4. Should call failPayment and NOT confirm order for PAYMENT_FAILED event', async () => {
    const tenantId = '7d20df20-80a5-48fa-84db-7b66df2e737d';
    const orderId = 'ord_failed_test';
    const paymentIntentId = 'intent_failed_test';

    // Seed the payment intent
    if (!mockDb.payment_intents) mockDb.payment_intents = [];
    mockDb.payment_intents.push({
      id: paymentIntentId,
      tenant_id: tenantId,
      provider: 'onekoszyk',
      provider_transaction_id: 'tx_failed_123',
      order_id: orderId,
      status: 'PROCESSING',
    });

    const payload = {
      id: 'evt_failed_123',
      transaction_id: 'tx_failed_123',
      tenant_id: tenantId,
      order_id: orderId,
      type: 'PAYMENT_FAILED',
      amount: 1000,
      currency: 'PLN',
      correlation_id: 'corr-failed-123',
    };
    const rawBody = JSON.stringify(payload);
    const signature = generateSignature(rawBody, secret);

    const req = new Request('http://localhost/api/webhooks/onekoszyk', {
      method: 'POST',
      headers: {
        'x-signature': signature,
        'content-type': 'application/json',
      },
      body: rawBody,
    });

    const res = await POST(req);
    expect(res.status).toBe(200);

    // Verify failPayment was called and confirmPayment was NOT called
    expect(failPaymentSpy).toHaveBeenCalled();
    expect(confirmPaymentSpy).not.toHaveBeenCalled();

    // Verify webhook event state is completed (the webhook delivery succeeded and handled the failure)
    const record = mockDb.webhook_events.find((x: any) => x.provider_event_id === 'evt_failed_123');
    expect(record).toBeDefined();
    expect(record.status).toBe('COMPLETED');
  });

  it('5. Should handle concurrent duplicate delivery atomically using unique constraint', async () => {
    const tenantId = '7d20df20-80a5-48fa-84db-7b66df2e737d';
    const orderId = 'ord_concurrent_test';
    const paymentIntentId = 'intent_concurrent_test';

    if (!mockDb.payment_intents) mockDb.payment_intents = [];
    mockDb.payment_intents.push({
      id: paymentIntentId,
      tenant_id: tenantId,
      provider: 'onekoszyk',
      provider_transaction_id: 'tx_concurrent_123',
      order_id: orderId,
      status: 'PROCESSING',
    });

    const order = {
      id: orderId,
      tenantId,
      customerId: 'cust-123',
      items: [],
      subtotalGross: 1000,
      taxTotal: 230,
      grandTotalGross: 1000,
      currency: 'PLN',
      status: 'PAYMENT_PENDING' as const,
      shippingAddress: {
        fullName: 'Jan Kowalski',
        street: 'Wiejska 1',
        city: 'Warszawa',
        zipCode: '00-001',
        country: 'Poland',
      },
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
    };

    vi.spyOn(OrderProcessingEngine.prototype, 'getOrder').mockResolvedValue(order as any);

    const payload = {
      id: 'evt_concurrent_123',
      transaction_id: 'tx_concurrent_123',
      tenant_id: tenantId,
      order_id: orderId,
      type: 'PAYMENT_COMPLETED',
      amount: 1000,
      currency: 'PLN',
      correlation_id: 'corr-concurrent-123',
    };
    const rawBody = JSON.stringify(payload);
    const signature = generateSignature(rawBody, secret);

    // Make concurrent requests
    const makeRequest = () =>
      new Request('http://localhost/api/webhooks/onekoszyk', {
        method: 'POST',
        headers: {
          'x-signature': signature,
          'content-type': 'application/json',
        },
        body: rawBody,
      });

    // Run both POST requests concurrently
    const [res1, res2] = await Promise.all([POST(makeRequest()), POST(makeRequest())]);

    // One must succeed with true success (received: true, success: true)
    // The other must be ignored (received: true, ignored: true)
    const json1 = await res1.json();
    const json2 = await res2.json();

    expect(res1.status).toBe(200);
    expect(res2.status).toBe(200);

    const results = [json1, json2];
    expect(results).toContainEqual({ received: true, success: true });
    expect(results).toContainEqual({ received: true, ignored: true });

    // Verify engine was called only once for payment completion
    expect(completePaymentSpy).toHaveBeenCalledTimes(1);
    expect(confirmPaymentSpy).toHaveBeenCalled();
  });
});

/**
 * First Runtime Flow Demonstration
 * 
 * This script demonstrates the complete asset lifecycle:
 * 1. Create AssetReference
 * 2. Upload asset to storage
 * 3. Create asset metadata in library
 * 4. Resolve to public URL with transformations
 */

import { LocalAssetStorage } from './src/providers/LocalAssetStorage';
import { AssetLibrary } from './src/AssetLibrary';
import { SimpleAssetResolver } from './src/AssetResolver';
import { AssetReference } from './src/AssetReference';
import { AssetType } from './src/AssetTypes';

// Create storage
const storage = new LocalAssetStorage({ basePath: 'demo' });

// Create library
const library = new AssetLibrary(storage);

// Create resolver
const resolver = new SimpleAssetResolver(storage, library);

// Create asset reference
const assetRef = new AssetReference('demo-image', 'image');
console.log('Created AssetReference:', assetRef.id, assetRef.type);

// Upload asset
const testData = new Uint8Array([1, 2, 3, 4, 5]);
const blob = new Blob([testData]);
const file = new File([blob], 'demo-image.png', { type: 'image/png' });

console.log('Uploading asset...');
const uploadResult = await storage.upload(file, {
  contentType: 'image/png',
  fileName: 'demo-image.png'
});

console.log('Upload successful!');
console.log('Storage key:', uploadResult.storageKey);
console.log('File size:', uploadResult.size);

// Simulate creating asset in library
const asset = {
  id: 'demo-image',
  type: 'image',
  name: 'Demo Image',
  description: 'Demo image for runtime flow',
  tags: ['demo', 'image'],
  metadata: {
    width: 800,
    height: 600,
    mimeType: 'image/png'
  },
  storageKey: uploadResult.storageKey,
  createdAt: new Date().toISOString(),
  updatedAt: new Date().toISOString()
};

library['assets'].set(asset.id, asset);
console.log('Asset added to library');

// Resolve to URL with transformations
console.log('Resolving to URL...');
const url = await resolver.resolve(assetRef, {
  width: 800,
  height: 600,
  quality: 85,
  format: 'webp'
});

console.log('Resolved URL:', url);
console.log('URL contains transformations:', 
  url.includes('width=800') && 
  url.includes('height=600') && 
  url.includes('quality=85') && 
  url.includes('format=webp')
);

console.log('First Runtime Flow demonstration complete!');

